function productionDefaultState(){
 const s=defaultState();
 s.screen='today';s.planTab='meals';s.profileTab='patient';s.logFilter='all';s.careFilter='today';s.mealDay='Monday';
 s.patient={legalName:'',preferredName:'Patient',dob:'',sex:'',blood:'',address:'',primaryDx:'',secondaryDx:'',allergies:'',feeding:'',communication:'',mobility:'',emergencyNotes:''};
 s.caregivers=[];s.hospitals=[];s.emergencyContacts=[];s.routines=[];s.therapies=[];s.meals={Monday:[],Tuesday:[],Wednesday:[],Thursday:[],Friday:[],Saturday:[],Sunday:[]};
 s.mealAssignments=[];s.mealLibrary=[];s.groceries=[];s.groceryLibrary=[];s.medications=[];s.administrations=[];s.appointments=[];s.logs=[];s.completions=[];s.routineLibrary=[];s.therapyLibrary=[];s.externalLinks=[];
 s.safetyAtGlance={critical:'',immediate:'',callCriteria:'',rescue:''};s.lastUpdated=new Date().toISOString();s.calendarRevision=1;
 return s
}
const DEMO_MODE=!CLOUD_ENABLED&&new URLSearchParams(location.search).get('demo')==='1';
let state=load();
function load(){const base=DEMO_MODE?defaultState():productionDefaultState();try{const raw=localStorage.getItem(STORAGE);return raw?merge(base,JSON.parse(raw)):base}catch(e){return base}}
function merge(base,over){if(Array.isArray(base))return Array.isArray(over)?over:base;if(base&&typeof base==='object'){const out={...base};Object.keys(over||{}).forEach(k=>out[k]=k in base?merge(base[k],over[k]):over[k]);return out}return over===undefined?base:over}
function save(){try{localStorage.setItem(STORAGE,JSON.stringify(state));return true}catch(e){return false}}
function toast(msg){const t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');clearTimeout(toast.timer);toast.timer=setTimeout(()=>t.classList.remove('show'),2200)}
function openModal(id){document.getElementById(id).classList.add('show')}
function closeModal(id){document.getElementById(id).classList.remove('show')}
function nav(){const items=[['today','Today'],['care','Daily Care'],['plans','Plans'],['logs','Logs'],['profile','Profile']];document.getElementById('bottomNav').innerHTML=items.map(([key,label])=>`<button class="nav ${state.screen===key?'active':''}" data-nav="${key}">${svg(key)}<span>${label}</span></button>`).join('')}
function setScreen(name){state.screen=name;save();document.querySelectorAll('.screen').forEach(x=>x.classList.remove('active'));document.getElementById(`screen-${name}`).classList.add('active');nav();render()}
function render(){renderHeader();if(state.screen==='today')renderToday();if(state.screen==='care')renderCare();if(state.screen==='plans')renderPlans();if(state.screen==='logs')renderLogs();if(state.screen==='profile')renderProfile()}
function renderHeader(){document.getElementById('quickAdd').innerHTML=svg('plus');document.getElementById('sosBtn').innerHTML=svg('sos');document.querySelectorAll('[data-close]').forEach(b=>b.innerHTML=svg('close',16));document.getElementById('sysIcons').innerHTML=`${svg('logs',15)}<svg width="23" height="12" viewBox="0 0 23 12" fill="none"><rect x=".5" y=".5" width="19" height="11" rx="3" stroke="currentColor" opacity=".45"/><rect x="2" y="2" width="14" height="8" rx="2" fill="currentColor"/><path d="M20.5 4v4c1-.3 1.8-1 1.8-2s-.8-1.7-1.8-2Z" fill="currentColor" opacity=".45"/></svg>`}
function ageFromDob(d){if(!d)return'';const dob=new Date(d+'T00:00:00'),now=new Date();let y=now.getFullYear()-dob.getFullYear(),m=now.getMonth()-dob.getMonth();if(m<0||m===0&&now.getDate()<dob.getDate())y--;return `${y} years`}
function todayName(){return new Date().toLocaleDateString('en-US',{weekday:'long'})}
function currentDay(){const d=todayName();return DAYS.includes(d)?d:'Monday'}
function todayItems(){const day=currentDay();const routines=state.routines.filter(r=>r.active&&r.days.includes(day)).map(r=>({id:r.id,time:r.time,title:r.title,detail:r.category,kind:r.category.includes('Position')?'position':r.category.includes('Clinical')?'therapy':'therapy',done:r.status==='done',source:'routine'}));const meals=(state.meals[day]||[]).map(m=>({id:m.id,time:m.time,title:m.name,detail:`${m.portion} · ${m.route}`,kind:'feed',done:false,source:'meal'}));const meds=state.medications.filter(m=>m.status==='Current').flatMap(m=>m.times.filter(t=>t!=='PRN').map(t=>({id:`${m.id}_${t}`,time:t,title:m.name,detail:`${m.dose} · ${m.route}`,kind:'med',done:m.taken.includes(t),source:'med',medId:m.id,medTime:t})));return [...routines,...meals,...meds].sort((a,b)=>a.time.localeCompare(b.time))}
function renderToday(){const items=todayItems(),done=items.filter(x=>x.done).length,pct=items.length?Math.round(done/items.length*100):0;document.getElementById('todayScroll').innerHTML=`
<div class="hero"><div class="eyebrow">Care companion · ${new Date().toLocaleDateString('en-MY',{day:'numeric',month:'long'})}</div><h1>Good ${new Date().getHours()<12?'morning':new Date().getHours()<18?'afternoon':'evening'}, ${esc(state.caregivers[0].displayName)}.</h1><p>A calm overview of ${esc(state.patient.preferredName)}’s care, without hiding the details you may need.</p></div>
<div class="care-banner"><div class="banner-row"><div><div class="banner-code">Today · ${done} of ${items.length} complete</div><h2>${esc(state.patient.preferredName)}’s care rhythm</h2><p>${esc(state.patient.primaryDx)} · ${esc(state.patient.feeding)}</p></div><button class="banner-action" id="openProfileFromBanner">Profile</button></div><div class="progress-line"><span style="width:${pct}%"></span></div></div>
<div class="stats"><div class="stat"><div class="stat-top"><span class="stat-icon">${svg('care',16)}</span><strong>${state.routines.filter(r=>r.active).length}</strong></div><label>Daily care routines</label><small>Personal care, positioning and comfort</small></div><div class="stat"><div class="stat-top"><span class="stat-icon">${svg('med',16)}</span><strong>${state.medications.filter(m=>m.status==='Current').length}</strong></div><label>Current medicines</label><small>With dose and administration times</small></div><div class="stat"><div class="stat-top"><span class="stat-icon">${svg('logs',16)}</span><strong>${state.logs.length}</strong></div><label>Care observations</label><small>Structured logs kept in this preview</small></div><div class="stat"><div class="stat-top"><span class="stat-icon">${svg('hospital',16)}</span><strong>${state.hospitals.length}</strong></div><label>Hospitals linked</label><small>Every centre and card number</small></div></div>
<div class="section-title"><div><h3>Today’s care flow</h3><p>Tap the check to update routine or medication status.</p></div><button class="text-btn" data-navgo="care">Open Daily Care</button></div>
<div class="timeline">${items.map(x=>`<div class="timeline-item card ${x.done?'done':''}"><div class="timeline-time">${esc(x.time)}</div><div style="display:grid;grid-template-columns:34px 1fr;gap:9px;align-items:center"><span class="care-dot ${x.kind}">${svg(x.kind==='feed'?'meal':x.kind==='med'?'med':'care',16)}</span><div><h4>${esc(x.title)}</h4><p>${esc(x.detail)}</p></div></div><button class="check" data-today-toggle="${esc(x.source)}|${esc(x.id)}|${esc(x.medId||'')}|${esc(x.medTime||'')}">${svg('check',15)}</button></div>`).join('')}</div>
<div class="section-title"><div><h3>Quick actions</h3><p>Reach the most important care records in one tap.</p></div></div>
<div class="quick-grid"><button class="quick card" data-quick="seizure"><span class="qicon" style="background:var(--redp);color:var(--red)">${svg('activity',19)}</span><h4>Log seizure</h4><p>Structured onset, duration, response and recovery fields.</p></button><button class="quick card" data-quick="dystonia"><span class="qicon" style="background:var(--amberp);color:var(--amber)">${svg('care',19)}</span><h4>Log dystonia</h4><p>Record trigger, severity, intervention and response.</p></button><button class="quick card" data-quick="meal"><span class="qicon">${svg('meal',19)}</span><h4>Add meal</h4><p>Place a saved feed or meal into the weekly plan.</p></button><button class="quick card" data-quick="print"><span class="qicon">${svg('print',19)}</span><h4>Print handover</h4><p>Open the complete emergency handover print dialog.</p></button></div>`}
function renderCare(){const day=currentDay();let list=state.routines.filter(r=>state.careFilter==='paused'?!r.active:state.careFilter==='all'?true:r.active&&r.days.includes(day));const active=state.routines.filter(r=>r.active).length,done=state.routines.filter(r=>r.status==='done').length,pct=active?Math.round(done/active*100):0;document.getElementById('careScroll').innerHTML=`
<div class="summary-card card"><h3>Daily care completion</h3><p>Completion supports handover; it does not replace clinical judgement.</p><div class="summary-row"><div class="ring" style="--pct:${pct}%"><strong>${pct}%</strong></div><div class="summary-info"><div><span>Active routines</span><strong>${active}</strong></div><div><span>Completed today</span><strong>${done}</strong></div><div><span>Paused</span><strong>${state.routines.filter(r=>!r.active).length}</strong></div></div></div></div>
<div class="chips"><button class="chip ${state.careFilter==='today'?'active':''}" data-care-filter="today">Today</button><button class="chip ${state.careFilter==='all'?'active':''}" data-care-filter="all">All routines</button><button class="chip ${state.careFilter==='paused'?'active':''}" data-care-filter="paused">Paused</button></div>
<div class="section-title" style="margin-top:4px"><div><h3>${state.careFilter==='today'?day:state.careFilter==='paused'?'Paused routines':'All care routines'}</h3><p>Personal care, feeding, positioning, comfort and family-specific tasks.</p></div><button class="text-btn" id="addRoutine">+ Add</button></div>
<div class="routine-list">${list.length?list.sort((a,b)=>a.time.localeCompare(b.time)).map(r=>`<article class="routine-card card"><span class="routine-icon">${esc(r.icon)}</span><div><h4>${esc(r.title)}</h4><p>${esc(r.notes)}</p><div class="routine-meta"><span class="mini">${esc(r.time)}</span><span class="mini">${esc(r.category)}</span><span class="mini">${r.days.length===7?'Daily':r.days.length+' days'}</span>${!r.active?'<span class="mini">Paused</span>':''}</div></div><div class="state-btns"><button class="icon-action ${r.status==='done'?'done':''}" data-routine-done="${r.id}" title="Mark done">${svg('check',15)}</button><button class="icon-action skip" data-routine-edit="${r.id}" title="Edit">${svg('edit',14)}</button></div></article>`).join(''):'<div class="card empty">No routines match this view.</div>'}</div>
<button class="add-slot" id="addRoutineBottom">${svg('plus',14)} Add a Daily Care routine</button>`}
function renderPlans(){document.getElementById('plansScroll').innerHTML=`<div class="chips plan-tabs">${[['meals','Meals'],['grocery','Grocery'],['meds','Medicines'],['appointments','Appointments']].map(([k,l])=>`<button class="chip ${state.planTab===k?'active':''}" data-plan-tab="${k}">${l}</button>`).join('')}</div><div id="planTabContent"></div>`;if(state.planTab==='meals')renderMeals();if(state.planTab==='grocery')renderGrocery();if(state.planTab==='meds')renderMeds();if(state.planTab==='appointments')renderAppointments()}
function renderMeals(){const day=state.mealDay,list=state.meals[day]||[];document.getElementById('planTabContent').innerHTML=`<div class="day-tabs">${DAYS.map(d=>`<button class="day-tab ${d===day?'active':''}" data-meal-day="${d}"><strong>${d.slice(0,3)}</strong><span>${(state.meals[d]||[]).length} meals</span></button>`).join('')}</div><div class="section-title" style="margin-top:4px"><div><h3>${day} meal plan</h3><p>Different meals can be scheduled on every day.</p></div><button class="text-btn" id="copyMealDay">Copy day</button></div><div class="plan-list">${list.length?list.sort((a,b)=>a.time.localeCompare(b.time)).map(m=>`<article class="meal-card card"><span class="accent"></span><div><h4>${esc(m.name)}</h4><p>${esc(m.time)} · ${esc(m.slot)} · ${esc(m.portion)}</p><div class="tags"><span class="mini">${esc(m.route)}</span>${m.notes?`<span class="mini">${esc(m.notes)}</span>`:''}</div></div><button class="more" data-meal-edit="${m.id}">${svg('arrow',17)}</button></article>`).join(''):'<div class="card empty">No meals scheduled for this day.</div>'}</div><button class="add-slot" id="addMeal">${svg('plus',14)} Add meal to ${day}</button><div class="section-title"><div><h3>Saved meal library</h3><p>Reusable recipes, feeds and prepared meals.</p></div><button class="text-btn" id="saveMeal">+ Save meal</button></div><div class="library-list">${state.mealLibrary.map(m=>`<article class="meal-card card"><span class="accent" style="background:var(--gold)"></span><div><h4>${esc(m.name)}</h4><p>${esc(m.portion)} · ${esc(m.calories)} · ${esc(m.texture)}</p><div class="tags"><span class="mini">${esc(m.route)}</span><span class="mini">Reusable</span></div></div><button class="small-btn fill" data-libmeal-add="${m.id}">Add</button></article>`).join('')}</div>`}
function renderGrocery(){const total=state.groceries.reduce((s,g)=>s+Number(g.cost||0),0),bought=state.groceries.filter(g=>g.checked).reduce((s,g)=>s+Number(g.cost||0),0);document.getElementById('planTabContent').innerHTML=`<div class="cost-banner card"><span class="cost-icon">${svg('grocery',22)}</span><div><h4>Active shopping list</h4><p>RM ${bought.toFixed(2)} purchased · ${state.groceries.filter(g=>!g.checked).length} items remaining</p></div><div class="cost-value">RM ${total.toFixed(2)}</div></div><div class="section-title"><div><h3>Current list</h3><p>Tap the box as each item is purchased.</p></div><button class="text-btn" id="addGrocery">+ Add</button></div><div class="plan-list">${state.groceries.map(g=>`<article class="grocery-card card ${g.checked?'checked':''}"><button class="grocery-check" data-grocery-check="${g.id}">${g.checked?svg('check',14):''}</button><div><h4>${esc(g.name)}</h4><p>${esc(g.category)} · ${esc(g.qty)}</p></div><span class="price">RM ${Number(g.cost).toFixed(2)}</span></article>`).join('')}</div><div class="section-title"><div><h3>Saved grocery library</h3><p>Add regular supplies without typing them again.</p></div><button class="text-btn" id="saveGrocery">+ Save item</button></div><div class="library-list">${state.groceryLibrary.map(g=>`<article class="grocery-card card"><span class="grocery-check" style="background:var(--goldp);color:var(--gold);border:0">${svg('grocery',14)}</span><div><h4>${esc(g.name)}</h4><p>${esc(g.category)} · ${esc(g.qty)}${g.notes?' · '+esc(g.notes):''}</p></div><button class="small-btn fill" data-libgrocery-add="${g.id}">Add</button></article>`).join('')}</div>`}
function renderMeds(){document.getElementById('planTabContent').innerHTML=`<div class="section-title" style="margin-top:4px"><div><h3>Current medication plan</h3><p>Dose, route, schedule and emergency medicines.</p></div><button class="text-btn" id="addMed">+ Add</button></div><div class="plan-list">${state.medications.map(m=>`<article class="med-card card"><div class="med-head"><div><h4>${esc(m.name)}</h4><p>${esc(m.dose)} · ${esc(m.route)}</p></div><span class="status-pill ${m.status==='Emergency'?'red':''}">${esc(m.status)}</span></div><div class="dose-row">${m.times.map(t=>`<button class="dose ${m.taken.includes(t)?'taken':''}" data-med-toggle="${m.id}|${t}">${esc(t)}${m.taken.includes(t)?' ✓':''}</button>`).join('')}</div><p>${esc(m.notes)}</p></article>`).join('')}</div><div class="notice warning" style="margin-top:12px"><strong>Medication safety:</strong> This preview is not a prescribing system. Always follow the current clinician-approved medication chart.</div>`}
function renderAppointments(){const sorted=[...state.appointments].sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time));document.getElementById('planTabContent').innerHTML=`<div class="section-title" style="margin-top:4px"><div><h3>Appointments</h3><p>Each visit can be linked to a hospital and department.</p></div><button class="text-btn" id="addAppt">+ Add</button></div><div class="plan-list">${sorted.map(a=>{const d=new Date(a.date+'T00:00:00');return`<article class="appt-card card"><span class="date-box"><span>${d.toLocaleDateString('en-US',{month:'short'})}</span><strong>${d.getDate()}</strong></span><div><h4>${esc(a.title)}</h4><p>${esc(a.time)} · ${esc(a.hospital)}</p><div class="tags"><span class="mini">${esc(a.department)}</span></div></div><button class="more" data-appt-edit="${a.id}">${svg('arrow',17)}</button></article>`}).join('')}</div>`}
const LOG_TYPES=['all','Seizure','Dystonia','Vitals','Medication','Fluid In/Out','Positioning','Behaviour','Development','General'];
function renderLogs(){let logs=state.logFilter==='all'?state.logs:state.logs.filter(l=>l.type===state.logFilter);logs=[...logs].sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time));document.getElementById('logsScroll').innerHTML=`<div class="search"><span>${svg('search',17)}</span><input class="control" id="logSearch" placeholder="Search saved logs"></div><div class="chips">${LOG_TYPES.map(t=>`<button class="chip ${state.logFilter===t?'active':''} ${t==='Seizure'?'alert':''}" data-log-filter="${t}">${t==='all'?'All logs':t}</button>`).join('')}</div><div class="section-title" style="margin-top:4px"><div><h3>${state.logFilter==='all'?'Recent care logs':state.logFilter+' logs'}</h3><p>Structured entries with caregiver attribution.</p></div><button class="text-btn" id="addLog">+ Add log</button></div><div class="log-list" id="logList">${logs.length?logs.map(l=>logHTML(l)).join(''):'<div class="card empty">No logs match this filter.</div>'}</div><button class="add-slot" id="printLogs">${svg('print',14)} Print saved logs</button>`}
function logHTML(l){const cls=l.type==='Seizure'?'seizure':l.type==='Dystonia'?'dystonia':l.type==='Vitals'?'vitals':'';return`<article class="log-card card ${cls}" data-log-open="${l.id}"><span class="log-icon">${svg(l.type==='Seizure'?'activity':l.type==='Vitals'?'logs':'care',18)}</span><div><h4>${esc(l.title)}</h4><p>${esc(l.summary)}</p><div class="tags"><span class="mini">${esc(l.type)}</span><span class="mini">By ${esc(l.caregiver)}</span></div></div><span class="log-date">${esc(l.date)}<br>${esc(l.time)}</span></article>`}
function renderProfile(){document.getElementById('profileScroll').innerHTML=`<div class="chips">${[['patient','Patient'],['caregivers','Caregivers'],['hospitals','Hospitals'],['data','Data & safety']].map(([k,l])=>`<button class="chip ${state.profileTab===k?'active':''}" data-profile-tab="${k}">${l}</button>`).join('')}</div><div id="profileTabContent"></div>`;if(state.profileTab==='patient')renderPatientProfile();if(state.profileTab==='caregivers')renderCaregivers();if(state.profileTab==='hospitals')renderHospitals();if(state.profileTab==='data')renderDataSafety()}
function renderPatientProfile(){const p=state.patient;document.getElementById('profileTabContent').innerHTML=`<div class="patient-hero"><div class="patient-top"><span class="avatar">${esc((p.preferredName||p.legalName).slice(0,1))}</span><div><h2>${esc(p.preferredName)}</h2><p>${esc(p.legalName)} · ${esc(ageFromDob(p.dob))}</p></div></div><div class="patient-chips"><span>${esc(p.primaryDx)}</span><span>Blood ${esc(p.blood)}</span><span>${esc(p.feeding)}</span></div></div><div class="profile-card card"><h3>Complete patient profile</h3><div class="profile-grid"><div class="field"><label>Legal name</label><input class="control" id="pfLegal" value="${esc(p.legalName)}"></div><div class="field"><label>Preferred name</label><input class="control" id="pfPreferred" value="${esc(p.preferredName)}"></div><div class="field"><label>Date of birth</label><input class="control" id="pfDob" type="date" value="${esc(p.dob)}"></div><div class="field"><label>Sex / gender</label><input class="control" id="pfSex" value="${esc(p.sex)}"></div><div class="field"><label>Blood group</label><input class="control" id="pfBlood" value="${esc(p.blood)}"></div><div class="field"><label>Primary diagnosis</label><input class="control" id="pfDx" value="${esc(p.primaryDx)}"></div><div class="field full"><label>Home address</label><textarea class="control" id="pfAddress">${esc(p.address)}</textarea></div><div class="field full"><label>Secondary diagnoses</label><textarea class="control" id="pfSecondary">${esc(p.secondaryDx)}</textarea></div><div class="field full"><label>Allergies</label><textarea class="control" id="pfAllergies">${esc(p.allergies)}</textarea></div><div class="field full"><label>Feeding method</label><textarea class="control" id="pfFeeding">${esc(p.feeding)}</textarea></div><div class="field full"><label>Communication</label><textarea class="control" id="pfCommunication">${esc(p.communication)}</textarea></div><div class="field full"><label>Mobility / positioning</label><textarea class="control" id="pfMobility">${esc(p.mobility)}</textarea></div><div class="field full"><label>Emergency / handover notes</label><textarea class="control" id="pfEmergency">${esc(p.emergencyNotes)}</textarea></div></div><button class="primary wide" id="savePatient">Save patient profile</button></div>`}
function renderCaregivers(){document.getElementById('profileTabContent').innerHTML=`<div class="section-title" style="margin-top:4px"><div><h3>Caregiver profiles</h3><p>Complete details for emergency handover and communication.</p></div><button class="text-btn" id="addCaregiver">+ Add</button></div><div class="library-list">${state.caregivers.map(c=>`<article class="person-card card"><div class="person-head"><div><h4>${esc(c.fullName)}</h4><p>${esc(c.type)} caregiver · ${esc(c.relationship)}</p></div><span class="status-pill">${c.decision?'Medical decisions':'Contact only'}</span></div><div class="info-grid"><div class="info"><label>Preferred name</label><strong>${esc(c.displayName)}</strong></div><div class="info"><label>Occupation</label><strong>${esc(c.occupation)}</strong></div><div class="info"><label>Phone</label><strong>${esc(c.phone)}</strong></div><div class="info"><label>Email</label><strong>${esc(c.email)}</strong></div><div class="info full"><label>Address</label><strong>${esc(c.address)}</strong></div></div><button class="small-btn" style="margin-top:9px" data-caregiver-edit="${c.id}">${svg('edit',13)} Edit profile</button></article>`).join('')}</div>`}
function renderHospitals(){document.getElementById('profileTabContent').innerHTML=`<div class="section-title" style="margin-top:4px"><div><h3>Hospitals &amp; care centres</h3><p>Multiple hospitals and card numbers are fully supported.</p></div><button class="text-btn" id="addHospital">+ Add</button></div><div class="library-list">${state.hospitals.map(h=>`<article class="hospital-card card ${h.primary?'primary-hospital':''}"><div class="hospital-head"><div><h4>${esc(h.name)}</h4><p>${esc(h.department)}</p></div><span class="status-pill ${h.primary?'warn':''}">${h.primary?'Primary hospital':'Linked centre'}</span></div><div class="hospital-meta"><div><label>Card / MRN</label><strong>${esc(h.mrn)}</strong></div><div><label>Telephone</label><strong>${esc(h.phone)}</strong></div><div class="full"><label>Consultant / team</label><strong>${esc(h.consultant)}</strong></div><div class="full"><label>Notes</label><strong>${esc(h.notes)}</strong></div></div><button class="small-btn" style="margin-top:9px" data-hospital-edit="${h.id}">${svg('edit',13)} Edit hospital</button></article>`).join('')}</div>`}
function renderDataSafety(){document.getElementById('profileTabContent').innerHTML=`<div class="profile-card card"><h3>Standalone preview storage</h3><div class="notice warning"><strong>This preview saves only inside this browser on this device.</strong><br>Data may be lost if browser data is cleared, private/incognito mode ends, the browser is reinstalled, the device is reset or replaced, storage is blocked, or this file is opened under a different browser profile.</div><div class="notice" style="margin-top:9px"><strong>For secure production storage:</strong><br>Use the GitHub-managed Cloudflare version with authenticated access, encrypted D1 persistence, role controls, version conflicts and encrypted backups. Do not use this preview for real patient records.</div><div class="actions-row" style="margin-top:10px"><button class="secondary" id="exportData">${svg('download',14)} Export demo</button><button class="secondary" id="importData">${svg('upload',14)} Import demo</button></div><input type="file" id="importFile" accept="application/json" class="hidden"><button class="ghost wide" id="resetData" style="margin-top:8px;color:var(--maroon)">${svg('trash',14)} Reset fictional demo data</button></div><div class="profile-card card"><h3>About this preview</h3><p style="font-size:10px;line-height:1.55;color:var(--muted)">This installed PWA uses the same care workspace on mobile, tablet and desktop.</p></div>`}
function showEditor(title,html){document.getElementById('editorTitle').textContent=title;document.getElementById('editorBody').innerHTML=html;openModal('editorModal')}
function openRoutineEditor(rid){const r=state.routines.find(x=>x.id===rid)||{id:'',icon:'🌿',title:'',category:'Personal care',time:'09:00',days:DAYS,notes:'',active:true,status:'pending'};showEditor(rid?'Edit Daily Care routine':'Add Daily Care routine',`<div class="field"><label>Routine name</label><input class="control" id="erTitle" value="${esc(r.title)}" placeholder="e.g. Morning positioning"></div><div class="toolbar"><div class="field"><label>Icon</label><input class="control" id="erIcon" value="${esc(r.icon)}" maxlength="4"></div><div class="field"><label>Time</label><input class="control" id="erTime" type="time" value="${esc(r.time)}"></div></div><div class="field"><label>Category</label><select class="control" id="erCategory">${['Morning care','Personal care','Feeding & nutrition','Positioning','Clinical care','Sleep & rest','Therapy & play','Communication','School & learning','Other'].map(x=>`<option ${x===r.category?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Care instructions</label><textarea class="control" id="erNotes">${esc(r.notes)}</textarea></div><div class="field"><label>Schedule</label><div class="chips" style="flex-wrap:wrap;overflow:visible">${DAYS.map(d=>`<button type="button" class="chip ${r.days.includes(d)?'active':''}" data-editor-day="${d}">${d.slice(0,3)}</button>`).join('')}</div></div><label style="display:flex;gap:8px;align-items:center;font-size:10px;color:var(--muted);margin:8px 0"><input id="erActive" type="checkbox" ${r.active?'checked':''}> Routine is active</label><button class="primary wide" id="saveRoutineEditor" data-id="${rid||''}">Save routine</button>`)}
function openMealEditor(mid,libraryId){let meal=mid?(state.meals[state.mealDay]||[]).find(x=>x.id===mid):null;const lib=libraryId?state.mealLibrary.find(x=>x.id===libraryId):null;meal=meal||{id:'',time:'09:00',slot:'Meal / feed',name:lib?.name||'',portion:lib?.portion||'',route:lib?.route||'',notes:''};showEditor(mid?'Edit scheduled meal':'Add meal to '+state.mealDay,`<div class="field"><label>Meal / feed name</label><input class="control" id="emName" value="${esc(meal.name)}"></div><div class="toolbar"><div class="field"><label>Time</label><input class="control" id="emTime" type="time" value="${esc(meal.time)}"></div><div class="field"><label>Slot</label><input class="control" id="emSlot" value="${esc(meal.slot)}"></div></div><div class="toolbar"><div class="field"><label>Portion</label><input class="control" id="emPortion" value="${esc(meal.portion)}"></div><div class="field"><label>Route</label><input class="control" id="emRoute" value="${esc(meal.route)}"></div></div><div class="field"><label>Day-specific instructions</label><textarea class="control" id="emNotes">${esc(meal.notes)}</textarea></div><button class="primary wide" id="saveMealEditor" data-id="${mid||''}">Save to ${state.mealDay}</button>`)}
function openGroceryEditor(){showEditor('Add grocery item',`<div class="field"><label>Item name</label><input class="control" id="egName" placeholder="e.g. Formula tins"></div><div class="toolbar"><div class="field"><label>Category</label><input class="control" id="egCategory" value="Pantry"></div><div class="field"><label>Quantity</label><input class="control" id="egQty" value="1"></div></div><div class="field"><label>Estimated cost (RM)</label><input class="control" id="egCost" type="number" min="0" step="0.01" value="0"></div><button class="primary wide" id="saveGroceryEditor">Add to active list</button>`)}
const LOG_FIELDS={Seizure:['Duration','Observed features','Possible trigger','Rescue medication','Action taken','Recovery'],Dystonia:['Severity','Body areas affected','Trigger','Intervention','Response'],Vitals:['Temperature','Heart rate','SpO2','Respiratory rate','Blood pressure'],Medication:['Medicine','Dose','Route','Given by','Response'], 'Fluid In/Out':['Type','Amount','Route','Urine','Bowel'],Positioning:['Position','Duration','Support used','Skin check','Tolerance'],Behaviour:['Antecedent','Behaviour','Consequence','Regulation support'],Development:['Skill area','Observed ability','Support needed','Next step'],General:['Context','Observation','Action','Next step']};
function openLogEditor(type='General'){const fields=LOG_FIELDS[type]||LOG_FIELDS.General;showEditor('Add '+type+' log',`<div class="toolbar"><div class="field"><label>Log type</label><select class="control" id="elType">${Object.keys(LOG_FIELDS).map(t=>`<option ${t===type?'selected':''}>${t}</option>`).join('')}</select></div><div class="field"><label>Caregiver</label><select class="control" id="elCaregiver">${state.caregivers.map(c=>`<option>${esc(c.displayName)}</option>`).join('')}</select></div></div><div class="toolbar"><div class="field"><label>Date</label><input class="control" id="elDate" type="date" value="${new Date().toISOString().slice(0,10)}"></div><div class="field"><label>Time</label><input class="control" id="elTime" type="time" value="${new Date().toTimeString().slice(0,5)}"></div></div><div class="field"><label>Title</label><input class="control" id="elTitle" placeholder="Short event title"></div><div class="field"><label>Summary</label><textarea class="control" id="elSummary" placeholder="What happened?"></textarea></div><div id="dynamicLogFields">${fields.map((f,i)=>`<div class="field"><label>${esc(f)}</label><input class="control log-extra" data-label="${esc(f)}"></div>`).join('')}</div><button class="primary wide" id="saveLogEditor">Save structured log</button>`)}
function openCaregiverEditor(cid){const c=state.caregivers.find(x=>x.id===cid)||{id:'',type:'Additional',fullName:'',displayName:'',relationship:'',occupation:'',phone:'',email:'',address:'',decision:false};showEditor(cid?'Edit caregiver':'Add caregiver',`<div class="toolbar"><div class="field"><label>Caregiver type</label><select class="control" id="ecType">${['Primary','Secondary','Additional'].map(x=>`<option ${x===c.type?'selected':''}>${x}</option>`).join('')}</select></div><div class="field"><label>Relationship</label><input class="control" id="ecRelationship" value="${esc(c.relationship)}"></div></div><div class="field"><label>Full legal name</label><input class="control" id="ecFull" value="${esc(c.fullName)}"></div><div class="field"><label>Preferred / display name</label><input class="control" id="ecDisplay" value="${esc(c.displayName)}"></div><div class="field"><label>Occupation</label><input class="control" id="ecOccupation" value="${esc(c.occupation)}"></div><div class="toolbar"><div class="field"><label>Phone</label><input class="control" id="ecPhone" value="${esc(c.phone)}"></div><div class="field"><label>Email</label><input class="control" id="ecEmail" value="${esc(c.email)}"></div></div><div class="field"><label>Address</label><textarea class="control" id="ecAddress">${esc(c.address)}</textarea></div><label style="display:flex;gap:8px;align-items:center;font-size:10px;color:var(--muted);margin:8px 0"><input id="ecDecision" type="checkbox" ${c.decision?'checked':''}> Authorised for medical decisions</label><button class="primary wide" id="saveCaregiverEditor" data-id="${cid||''}">Save caregiver</button>`)}
function openHospitalEditor(hid){const h=state.hospitals.find(x=>x.id===hid)||{id:'',name:'',mrn:'',department:'',consultant:'',phone:'',notes:'',primary:false};showEditor(hid?'Edit hospital':'Add hospital / centre',`<div class="field"><label>Hospital or centre name</label><input class="control" id="ehName" value="${esc(h.name)}"></div><div class="toolbar"><div class="field"><label>Card / MRN</label><input class="control" id="ehMrn" value="${esc(h.mrn)}"></div><div class="field"><label>Telephone</label><input class="control" id="ehPhone" value="${esc(h.phone)}"></div></div><div class="field"><label>Department</label><input class="control" id="ehDepartment" value="${esc(h.department)}"></div><div class="field"><label>Consultant / team</label><input class="control" id="ehConsultant" value="${esc(h.consultant)}"></div><div class="field"><label>Notes</label><textarea class="control" id="ehNotes">${esc(h.notes)}</textarea></div><label style="display:flex;gap:8px;align-items:center;font-size:10px;color:var(--muted);margin:8px 0"><input id="ehPrimary" type="checkbox" ${h.primary?'checked':''}> Set as primary hospital</label><button class="primary wide" id="saveHospitalEditor" data-id="${hid||''}">Save hospital</button>`)}
function openLogDetail(lid){const l=state.logs.find(x=>x.id===lid);if(!l)return;document.getElementById('detailTitle').textContent=l.type+' log';document.getElementById('detailBody').innerHTML=`<div class="detail-hero ${l.type==='Seizure'?'red':''}"><div class="type">${esc(l.type)} · ${esc(l.date)} ${esc(l.time)}</div><h3>${esc(l.title)}</h3><p>${esc(l.summary)}</p><div class="detail-tags"><span>Recorded by ${esc(l.caregiver)}</span></div></div><div class="profile-card card"><h3>Structured details</h3>${Object.entries(l.fields||{}).map(([k,v])=>`<div class="step"><span class="step-num">${esc(k.slice(0,1))}</span><p><strong>${esc(k)}:</strong> ${esc(v||'—')}</p></div>`).join('')}</div>`;openModal('detailModal')}
function renderSOS(){const p=state.patient,primary=state.hospitals.find(h=>h.primary)||state.hospitals[0];document.getElementById('sosBody').innerHTML=`<div class="detail-hero red"><div class="type">Emergency identity card</div><h3>${esc(p.legalName)}</h3><p>${esc(p.primaryDx)} · ${esc(p.feeding)}</p><div class="detail-tags"><span>DOB ${esc(p.dob)}</span><span>Blood ${esc(p.blood)}</span><span>${esc(p.allergies)}</span></div></div><button class="danger wide" id="printHandoverNow">${svg('print',15)} Print Complete Handover</button><p style="font-size:8px;color:var(--muted);text-align:center;margin:6px 0 12px">Generates the latest handover and immediately opens the browser print dialog.</p><div class="profile-card card"><h3>Critical information</h3><div class="step"><span class="step-num red">A</span><p><strong>Allergies:</strong> ${esc(p.allergies)}</p></div><div class="step"><span class="step-num red">F</span><p><strong>Feeding:</strong> ${esc(p.feeding)}</p></div><div class="step"><span class="step-num red">P</span><p><strong>Positioning:</strong> ${esc(p.mobility)}</p></div><div class="step"><span class="step-num red">!</span><p><strong>Emergency notes:</strong> ${esc(p.emergencyNotes)}</p></div></div><div class="section-title"><div><h3>Emergency contacts</h3><p>Tap a number to call from a supported device.</p></div></div><div class="library-list">${state.emergencyContacts.map(c=>`<article class="contact-card card"><span class="contact-icon">${svg('phone',17)}</span><div><h4>${esc(c.name)}</h4><p>${esc(c.role)}</p></div><a class="phone-link" href="tel:${esc(c.phone.replace(/\s/g,''))}">${esc(c.phone)}</a></article>`).join('')}</div><div class="section-title"><div><h3>Primary hospital</h3><p>Full hospital list appears in the printed handover.</p></div></div><article class="hospital-card card primary-hospital"><div class="hospital-head"><div><h4>${esc(primary?.name||'—')}</h4><p>${esc(primary?.department||'—')}</p></div><span class="status-pill warn">Primary</span></div><div class="hospital-meta"><div><label>Card / MRN</label><strong>${esc(primary?.mrn||'—')}</strong></div><div><label>Telephone</label><strong>${esc(primary?.phone||'—')}</strong></div><div class="full"><label>Consultant / team</label><strong>${esc(primary?.consultant||'—')}</strong></div></div></article><div class="section-title"><div><h3>Immediate seizure response</h3><p>Use the child’s clinician-approved emergency plan.</p></div></div><div class="profile-card card">${['Keep the child safe and note the exact start time.','Position to protect the airway; do not restrain movements.','Observe breathing, colour, body parts affected and responsiveness.','Give rescue medication only according to the approved plan.','Call emergency services when the care plan threshold is met or breathing is compromised.'].map((s,i)=>`<div class="step"><span class="step-num red">${i+1}</span><p>${esc(s)}</p></div>`).join('')}</div>`;openModal('sosModal')}
function printHandover(){const p=state.patient,now=new Date();const caregivers=state.caregivers.map(c=>`<tr><td>${esc(c.type)}</td><td><strong>${esc(c.fullName)}</strong><br>Preferred: ${esc(c.displayName)}<br>${esc(c.relationship)} · ${esc(c.occupation)}</td><td>${esc(c.phone)}<br>${esc(c.email)}</td><td>${esc(c.address)}<br>Medical decisions: ${c.decision?'Yes':'No'}</td></tr>`).join('');const hospitals=state.hospitals.map(h=>`<tr><td><strong>${esc(h.name)}</strong>${h.primary?' (Primary)':''}<br>${esc(h.department)}</td><td>${esc(h.mrn)}</td><td>${esc(h.consultant)}<br>${esc(h.phone)}</td><td>${esc(h.notes)}</td></tr>`).join('');const meds=state.medications.map(m=>`<tr><td>${esc(m.name)}</td><td>${esc(m.dose)}</td><td>${esc(m.route)}</td><td>${esc(m.times.join(', '))}</td><td>${esc(m.notes)}</td></tr>`).join('');const routines=state.routines.filter(r=>r.active).sort((a,b)=>a.time.localeCompare(b.time)).map(r=>`<tr><td>${esc(r.time)}</td><td>${esc(r.title)}</td><td>${esc(r.category)}</td><td>${esc(r.notes)}</td></tr>`).join('');const appts=state.appointments.map(a=>`<tr><td>${esc(a.date)} ${esc(a.time)}</td><td>${esc(a.title)}</td><td>${esc(a.hospital)}</td><td>${esc(a.department)}</td></tr>`).join('');document.getElementById('printSheet').innerHTML=`<h1>CarePlan · Emergency Handover</h1><p>Generated ${esc(now.toLocaleString('en-MY'))} · CONFIDENTIAL CARE INFORMATION</p><div class="critical"><strong>Patient:</strong> ${esc(p.legalName)} (${esc(p.preferredName)}) · DOB ${esc(p.dob)} · ${esc(ageFromDob(p.dob))}<br><strong>Primary diagnosis:</strong> ${esc(p.primaryDx)}<br><strong>Allergies:</strong> ${esc(p.allergies)}<br><strong>Emergency notes:</strong> ${esc(p.emergencyNotes)}</div><h2>Complete patient profile</h2><div class="grid"><div class="box"><strong>Legal name</strong><br>${esc(p.legalName)}</div><div class="box"><strong>Preferred name</strong><br>${esc(p.preferredName)}</div><div class="box"><strong>Date of birth / age</strong><br>${esc(p.dob)} · ${esc(ageFromDob(p.dob))}</div><div class="box"><strong>Sex / blood group</strong><br>${esc(p.sex)} · ${esc(p.blood)}</div><div class="box"><strong>Primary diagnosis</strong><br>${esc(p.primaryDx)}</div><div class="box"><strong>Secondary diagnoses</strong><br>${esc(p.secondaryDx)}</div><div class="box"><strong>Feeding</strong><br>${esc(p.feeding)}</div><div class="box"><strong>Communication</strong><br>${esc(p.communication)}</div><div class="box"><strong>Mobility / positioning</strong><br>${esc(p.mobility)}</div><div class="box"><strong>Home address</strong><br>${esc(p.address)}</div></div><h2>Complete caregiver profiles</h2><table><thead><tr><th>Role</th><th>Identity</th><th>Contact</th><th>Address & authority</th></tr></thead><tbody>${caregivers}</tbody></table><h2>Hospitals & card details</h2><table><thead><tr><th>Hospital / department</th><th>Card / MRN</th><th>Consultant / contact</th><th>Notes</th></tr></thead><tbody>${hospitals}</tbody></table><h2>Emergency contacts</h2><table><thead><tr><th>Name</th><th>Role</th><th>Phone</th></tr></thead><tbody>${state.emergencyContacts.map(c=>`<tr><td>${esc(c.name)}</td><td>${esc(c.role)}</td><td>${esc(c.phone)}</td></tr>`).join('')}</tbody></table><h2>Current medicines</h2><table><thead><tr><th>Medicine</th><th>Dose</th><th>Route</th><th>Schedule</th><th>Notes</th></tr></thead><tbody>${meds}</tbody></table><h2>Daily Care routines</h2><table><thead><tr><th>Time</th><th>Routine</th><th>Category</th><th>Instructions</th></tr></thead><tbody>${routines}</tbody></table><h2>Upcoming appointments</h2><table><thead><tr><th>Date / time</th><th>Appointment</th><th>Hospital</th><th>Department</th></tr></thead><tbody>${appts}</tbody></table><h2>Emergency action plan</h2><ol><li>Keep the patient safe and protect the airway.</li><li>Observe and time the event. Note breathing, colour and responsiveness.</li><li>Use prescribed rescue medication only according to the approved plan.</li><li>Call emergency services when the approved threshold is met or breathing is compromised.</li><li>Bring this handover and all current medication information.</li></ol><div class="footer"><span>CarePlan · Complete Emergency Handover</span><span>${esc(p.legalName)} · CONFIDENTIAL</span></div>`;setTimeout(()=>window.print(),50)}
function exportData(){const blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='careplan-pro-preview-demo.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function printLogs(){const rows=[...state.logs].sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time)).map(l=>`<tr><td>${esc(l.date)} ${esc(l.time)}</td><td>${esc(l.type)}</td><td><strong>${esc(l.title)}</strong><br>${esc(l.summary)}</td><td>${esc(l.caregiver)}</td></tr>`).join('');document.getElementById('printSheet').innerHTML=`<h1>CarePlan · Saved Care Logs</h1><p>Patient: ${esc(state.patient.legalName)} · Generated ${esc(new Date().toLocaleString('en-MY'))}</p><table><thead><tr><th>Date / time</th><th>Type</th><th>Entry</th><th>Caregiver</th></tr></thead><tbody>${rows}</tbody></table>`;setTimeout(()=>window.print(),50)}
function savePatient(){Object.assign(state.patient,{legalName:document.getElementById('pfLegal').value.trim(),preferredName:document.getElementById('pfPreferred').value.trim(),dob:document.getElementById('pfDob').value,sex:document.getElementById('pfSex').value.trim(),blood:document.getElementById('pfBlood').value.trim(),primaryDx:document.getElementById('pfDx').value.trim(),address:document.getElementById('pfAddress').value.trim(),secondaryDx:document.getElementById('pfSecondary').value.trim(),allergies:document.getElementById('pfAllergies').value.trim(),feeding:document.getElementById('pfFeeding').value.trim(),communication:document.getElementById('pfCommunication').value.trim(),mobility:document.getElementById('pfMobility').value.trim(),emergencyNotes:document.getElementById('pfEmergency').value.trim()});save();toast('Patient profile saved');render()}
function bind(){document.addEventListener('click',e=>{const navBtn=e.target.closest('[data-nav]');if(navBtn)return setScreen(navBtn.dataset.nav);const navGo=e.target.closest('[data-navgo]');if(navGo)return setScreen(navGo.dataset.navgo);const close=e.target.closest('[data-close]');if(close)return closeModal(close.dataset.close);if(e.target.classList.contains('modal-back'))return closeModal(e.target.id);
 const planTab=e.target.closest('[data-plan-tab]');if(planTab){state.planTab=planTab.dataset.planTab;save();return render()}
 const profileTab=e.target.closest('[data-profile-tab]');if(profileTab){state.profileTab=profileTab.dataset.profileTab;save();return render()}
 const careFilter=e.target.closest('[data-care-filter]');if(careFilter){state.careFilter=careFilter.dataset.careFilter;save();return render()}
 const logFilter=e.target.closest('[data-log-filter]');if(logFilter){state.logFilter=logFilter.dataset.logFilter;save();return render()}
 const mealDay=e.target.closest('[data-meal-day]');if(mealDay){state.mealDay=mealDay.dataset.mealDay;save();return render()}
 const todayToggle=e.target.closest('[data-today-toggle]');if(todayToggle){const [source,itemId,medId,medTime]=todayToggle.dataset.todayToggle.split('|');if(source==='routine'){const r=state.routines.find(x=>x.id===itemId);if(r)r.status=r.status==='done'?'pending':'done'}if(source==='med'){const m=state.medications.find(x=>x.id===medId);if(m)m.taken=m.taken.includes(medTime)?m.taken.filter(t=>t!==medTime):[...m.taken,medTime]}save();return render()}
 const routineDone=e.target.closest('[data-routine-done]');if(routineDone){const r=state.routines.find(x=>x.id===routineDone.dataset.routineDone);if(r)r.status=r.status==='done'?'pending':'done';save();return render()}
 const routineEdit=e.target.closest('[data-routine-edit]');if(routineEdit)return openRoutineEditor(routineEdit.dataset.routineEdit);
 const mealEdit=e.target.closest('[data-meal-edit]');if(mealEdit)return openMealEditor(mealEdit.dataset.mealEdit);
 const libMeal=e.target.closest('[data-libmeal-add]');if(libMeal)return openMealEditor('',libMeal.dataset.libmealAdd);
 const groceryCheck=e.target.closest('[data-grocery-check]');if(groceryCheck){const g=state.groceries.find(x=>x.id===groceryCheck.dataset.groceryCheck);if(g)g.checked=!g.checked;save();return render()}
 const libG=e.target.closest('[data-libgrocery-add]');if(libG){const g=state.groceryLibrary.find(x=>x.id===libG.dataset.libgroceryAdd);if(g)state.groceries.push({...g,id:id(),checked:false});save();toast('Added to active list');return render()}
 const medToggle=e.target.closest('[data-med-toggle]');if(medToggle){const [mid,t]=medToggle.dataset.medToggle.split('|'),m=state.medications.find(x=>x.id===mid);if(m)m.taken=m.taken.includes(t)?m.taken.filter(x=>x!==t):[...m.taken,t];save();return render()}
 const logOpen=e.target.closest('[data-log-open]');if(logOpen)return openLogDetail(logOpen.dataset.logOpen);
 const cgEdit=e.target.closest('[data-caregiver-edit]');if(cgEdit)return openCaregiverEditor(cgEdit.dataset.caregiverEdit);
 const hEdit=e.target.closest('[data-hospital-edit]');if(hEdit)return openHospitalEditor(hEdit.dataset.hospitalEdit);
 if(e.target.closest('#sosBtn'))return renderSOS();if(e.target.closest('#quickAdd'))return openLogEditor('General');if(e.target.closest('#openProfileFromBanner'))return setScreen('profile');if(e.target.closest('#addRoutine')||e.target.closest('#addRoutineBottom'))return openRoutineEditor();if(e.target.closest('#addMeal'))return openMealEditor();if(e.target.closest('#addGrocery'))return openGroceryEditor();if(e.target.closest('#addLog'))return openLogEditor('General');if(e.target.closest('#addCaregiver'))return openCaregiverEditor();if(e.target.closest('#addHospital'))return openHospitalEditor();if(e.target.closest('#printHandoverNow'))return printHandover();if(e.target.closest('#printLogs'))return printLogs();if(e.target.closest('#savePatient'))return savePatient();
 const q=e.target.closest('[data-quick]');if(q){if(q.dataset.quick==='seizure')return openLogEditor('Seizure');if(q.dataset.quick==='dystonia')return openLogEditor('Dystonia');if(q.dataset.quick==='meal'){state.screen='plans';state.planTab='meals';save();setScreen('plans');return setTimeout(()=>openMealEditor(),50)}if(q.dataset.quick==='print')return printHandover()}
 if(e.target.closest('#saveRoutineEditor')){const btn=e.target.closest('#saveRoutineEditor'),rid=btn.dataset.id,days=[...document.querySelectorAll('[data-editor-day].active')].map(x=>x.dataset.editorDay);const data={id:rid||id(),icon:document.getElementById('erIcon').value||'🌿',title:document.getElementById('erTitle').value.trim()||'Care routine',category:document.getElementById('erCategory').value,time:document.getElementById('erTime').value||'09:00',days:days.length?days:DAYS,notes:document.getElementById('erNotes').value.trim(),active:document.getElementById('erActive').checked,status:'pending'};if(rid){const i=state.routines.findIndex(x=>x.id===rid);data.status=state.routines[i]?.status||'pending';state.routines[i]=data}else state.routines.push(data);save();closeModal('editorModal');toast('Daily Care routine saved');return render()}
 const eday=e.target.closest('[data-editor-day]');if(eday){eday.classList.toggle('active');return}
 if(e.target.closest('#saveMealEditor')){const btn=e.target.closest('#saveMealEditor'),mid=btn.dataset.id,list=state.meals[state.mealDay]||(state.meals[state.mealDay]=[]),data={id:mid||id(),time:document.getElementById('emTime').value||'09:00',slot:document.getElementById('emSlot').value.trim(),name:document.getElementById('emName').value.trim()||'Meal / feed',portion:document.getElementById('emPortion').value.trim(),route:document.getElementById('emRoute').value.trim(),notes:document.getElementById('emNotes').value.trim()};if(mid){const i=list.findIndex(x=>x.id===mid);list[i]=data}else list.push(data);save();closeModal('editorModal');toast('Meal added to weekly plan');return render()}
 if(e.target.closest('#saveGroceryEditor')){state.groceries.push({id:id(),name:document.getElementById('egName').value.trim()||'Grocery item',category:document.getElementById('egCategory').value.trim(),qty:document.getElementById('egQty').value.trim(),cost:Number(document.getElementById('egCost').value)||0,checked:false});save();closeModal('editorModal');toast('Grocery item added');return render()}
 if(e.target.closest('#saveLogEditor')){const type=document.getElementById('elType').value,fields={};document.querySelectorAll('.log-extra').forEach(x=>fields[x.dataset.label]=x.value.trim());state.logs.push({id:id(),type,date:document.getElementById('elDate').value,time:document.getElementById('elTime').value,title:document.getElementById('elTitle').value.trim()||type+' entry',summary:document.getElementById('elSummary').value.trim(),fields,caregiver:document.getElementById('elCaregiver').value});save();closeModal('editorModal');toast('Structured log saved');return render()}
 if(e.target.closest('#saveCaregiverEditor')){const btn=e.target.closest('#saveCaregiverEditor'),cid=btn.dataset.id,data={id:cid||id(),type:document.getElementById('ecType').value,relationship:document.getElementById('ecRelationship').value.trim(),fullName:document.getElementById('ecFull').value.trim(),displayName:document.getElementById('ecDisplay').value.trim(),occupation:document.getElementById('ecOccupation').value.trim(),phone:document.getElementById('ecPhone').value.trim(),email:document.getElementById('ecEmail').value.trim(),address:document.getElementById('ecAddress').value.trim(),decision:document.getElementById('ecDecision').checked};if(cid){const i=state.caregivers.findIndex(x=>x.id===cid);state.caregivers[i]=data}else state.caregivers.push(data);save();closeModal('editorModal');toast('Caregiver saved');return render()}
 if(e.target.closest('#saveHospitalEditor')){const btn=e.target.closest('#saveHospitalEditor'),hid=btn.dataset.id,primary=document.getElementById('ehPrimary').checked,data={id:hid||id(),name:document.getElementById('ehName').value.trim(),mrn:document.getElementById('ehMrn').value.trim(),department:document.getElementById('ehDepartment').value.trim(),consultant:document.getElementById('ehConsultant').value.trim(),phone:document.getElementById('ehPhone').value.trim(),notes:document.getElementById('ehNotes').value.trim(),primary};if(primary)state.hospitals.forEach(h=>h.primary=false);if(hid){const i=state.hospitals.findIndex(x=>x.id===hid);state.hospitals[i]=data}else state.hospitals.push(data);save();closeModal('editorModal');toast('Hospital saved');return render()}
 if(e.target.closest('#exportData'))return exportData();if(e.target.closest('#importData'))return document.getElementById('importFile').click();if(e.target.closest('#resetData')){if(confirm('Reset all fictional preview data?')){state=defaultState();save();toast('Preview reset');render()}return}
 if(e.target.closest('#copyMealDay')){const target=DAYS[(DAYS.indexOf(state.mealDay)+1)%7];state.meals[target]=(state.meals[state.mealDay]||[]).map(m=>({...m,id:id()}));save();toast(`Copied ${state.mealDay} to ${target}`);return render()}
 });
 document.addEventListener('change',e=>{if(e.target.id==='importFile'&&e.target.files?.[0]){const reader=new FileReader();reader.onload=()=>{try{state=merge(defaultState(),JSON.parse(reader.result));save();toast('Demo data imported');render()}catch(err){alert('This is not a valid CarePlan preview backup.')}};reader.readAsText(e.target.files[0])}if(e.target.id==='elType')openLogEditor(e.target.value)});
 document.addEventListener('input',e=>{if(e.target.id==='logSearch'){const q=e.target.value.toLowerCase();document.querySelectorAll('#logList .log-card').forEach(card=>card.style.display=card.textContent.toLowerCase().includes(q)?'grid':'none')}})
}
function init(){bind();nav();render();document.getElementById('clock').textContent=new Date().toLocaleTimeString([],{hour:'2-digit',minute:'2-digit',hour12:false});setInterval(()=>document.getElementById('clock').textContent=new Date().toLocaleTimeString([],{hour:'2-digit',minute:'2-digit',hour12:false}),30000)}
init();


