const V94_DAY_NAMES=['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const V94_DAY_SHORT=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
const V94_NAV=[['today','Today'],['calendar','Calendar'],['care','Daily Care'],['therapy','Therapies'],['appointments','Appointments'],['meals','Meals'],['medicines','Medicines'],['grocery','Grocery'],['logs','Logs'],['sos','SOS'],['profile','Profile']];
const V94_THERAPY_CATS=['Physiotherapy','Occupational Therapy','Speech & Language','Cognitive','Vision','Sensory','Custom'];
const V94_THERAPY_CATEGORIES=V94_THERAPY_CATS;
const V94_LOG_TYPES=['Seizure','Dystonia','Fluid In/Out','Medication','Vital Signs','Positioning','Behaviour','Development','Skin / Pressure Area','General'];
const V94_MEDIA_DB='careplan_v94_preview_media';
const v94DateISO=d=>{const x=new Date(d);x.setMinutes(x.getMinutes()-x.getTimezoneOffset());return x.toISOString().slice(0,10)};
const v94ParseDate=s=>{const [y,m,d]=String(s).split('-').map(Number);return new Date(y,m-1,d)};
const v94AddDays=(s,n)=>{const d=typeof s==='string'?v94ParseDate(s):new Date(s);d.setDate(d.getDate()+Number(n));return v94DateISO(d)};
const v94StartMonday=s=>{const d=typeof s==='string'?v94ParseDate(s):new Date(s),day=d.getDay();d.setDate(d.getDate()-(day===0?6:day-1));return v94DateISO(d)};
const v94FormatDate=(s,opt={weekday:'long',day:'numeric',month:'long'})=>v94ParseDate(s).toLocaleDateString('en-MY',opt);
const v94Uid=()=>Date.now().toString(36)+Math.random().toString(36).slice(2,8);
let v94PendingAttachments=[],v94Edit=null,v94ObjectUrls=[];
function v94Migrate(){
 const today=v94DateISO(new Date());state.selectedDate=state.selectedDate||today;state.monthCursor=state.monthCursor||state.selectedDate;state.careFilter=state.careFilter||'today';state.therapyFilter=(state.therapyFilter&&state.therapyFilter!=='All')?state.therapyFilter:'all';state.mealTab=state.mealTab||'week';state.groceryTab=state.groceryTab||'active';state.medFilter=state.medFilter||'All';state.profileTab=state.profileTab||'patient';state.completions=state.completions||[];state.administrations=state.administrations||[];
 const dayMap={Sunday:0,Monday:1,Tuesday:2,Wednesday:3,Thursday:4,Friday:5,Saturday:6};
 state.routines=(state.routines||[]).map(r=>({...r,duration:r.duration||15,instructions:r.instructions||r.notes||'',attachments:r.attachments||[],days:(r.days||V94_DAY_NAMES).map(x=>typeof x==='number'?x:dayMap[x]).filter(x=>Number.isInteger(x))}));
 state.therapies=state.therapies||[
  {id:'v94t1',icon:'🧘',title:'Supported sitting and head control',category:'Physiotherapy',time:'09:00',days:[1,3,5],duration:20,instructions:'Use full trunk support. Stop if breathing, colour or distress changes.',active:true,attachments:[]},
  {id:'v94t2',icon:'👐',title:'Bilateral reach and grasp',category:'Occupational Therapy',time:'11:30',days:[2,4,6],duration:15,instructions:'Present one lightweight object at midline, then alternate sides.',active:true,attachments:[]},
  {id:'v94t3',icon:'🗣️',title:'Choice-making through gaze',category:'Speech & Language',time:'15:30',days:[1,2,4,5],duration:12,instructions:'Offer two meaningful choices and wait at least 8 seconds.',active:true,attachments:[]},
  {id:'v94t4',icon:'🧠',title:'Cause-and-effect switch play',category:'Cognitive',time:'16:00',days:[3,6],duration:15,instructions:'Use one clear action and one predictable sensory response.',active:true,attachments:[]}
 ];
 state.therapies=state.therapies.map(t=>({...t,attachments:t.attachments||[],duration:t.duration||15,instructions:t.instructions||t.notes||'',days:(t.days||[]).map(x=>typeof x==='number'?x:dayMap[x]).filter(x=>Number.isInteger(x))}));
 if(!state.mealAssignments){state.mealAssignments=[];const mon=v94StartMonday(state.selectedDate);Object.entries(state.meals||{}).forEach(([day,list])=>{const idx=dayMap[day],date=v94AddDays(mon,idx===0?6:idx-1);(list||[]).forEach(m=>state.mealAssignments.push({...m,id:m.id||v94Uid(),date,status:m.status||'pending'}))});}
 if(DEMO_MODE&&state.mealAssignments.length<10){const mon=v94StartMonday(state.selectedDate),patterns=[['06:30','Breakfast feed','Formula feed','180 ml'],['10:30','Snack / flush','Pear & oat blend','80 ml'],['14:00','Lunch feed','Chicken rice blend','120 ml'],['18:30','Evening feed','Formula feed','180 ml']];for(let i=0;i<7;i++){const date=v94AddDays(mon,i);if(!state.mealAssignments.some(m=>m.date===date))patterns.slice(0,i%2?3:4).forEach((p,pi)=>state.mealAssignments.push({id:v94Uid(),date,time:p[0],slot:p[1],mealId:'',name:p[2],portion:p[3],route:'NG tube',notes:pi?'Flush 15 ml water':'Run over 90 minutes',status:'pending'}));}}
 state.medications=(state.medications||[]).map(m=>({...m,generic:m.generic||m.name,strength:m.strength||'',frequency:m.frequency||(m.times?.length?m.times.length+' times daily':'PRN'),indication:m.indication||'',prescriber:m.prescriber||'',startDate:m.startDate||'',endDate:m.endDate||'',reviewDate:m.reviewDate||'',status:m.status==='Emergency'?'Current':(m.status||'Current'),prn:m.prn||m.times?.includes('PRN')||false,rescue:m.rescue||m.status==='Emergency',maxPrn:m.maxPrn||'',instructions:m.instructions||m.notes||'',warnings:m.warnings||'',expiry:m.expiry||'',attachments:m.attachments||[]}));
 state.medications.forEach(m=>(m.taken||[]).forEach(t=>{if(t!=='PRN'&&!state.administrations.some(a=>a.medId===m.id&&a.date===state.selectedDate&&a.scheduledTime===t))state.administrations.push({id:v94Uid(),medId:m.id,date:state.selectedDate,scheduledTime:t,actualTime:t,status:'Given',caregiver:state.caregivers?.[0]?.displayName||'',dose:m.dose,note:''})}));
 state.appointments=(state.appointments||[]).map(a=>({...a,hospitalId:a.hospitalId||state.hospitals?.find(h=>h.name===a.hospital)?.id||state.hospitals?.[0]?.id||'',consultant:a.consultant||'',location:a.location||'',phone:a.phone||'',prep:a.prep||'',status:a.status||'Scheduled',notes:a.notes||''}));
 state.logs=(state.logs||[]).map(l=>({...l,type:l.type==='Vitals'?'Vital Signs':l.type,attachments:l.attachments||[],severity:l.severity||'Routine'}));
 state.caregivers=(state.caregivers||[]).map((c,i)=>({...c,emergency:c.emergency??i<2}));state.hospitals=(state.hospitals||[]).map(h=>({...h,address:h.address||''}));
 if(!['today','calendar','care','therapy','appointments','meals','medicines','grocery','logs','sos','profile'].includes(state.screen))state.screen='today';save();
}
function v94BuildShell(){
 const app=document.getElementById('app');if(app.querySelector('.v94-sidebar'))return;
 const old=[...app.children],sidebar=document.createElement('aside'),workspace=document.createElement('section');sidebar.className='v94-sidebar';sidebar.innerHTML='<div class="v94-brand"><div class="v94-mark">CP</div><div class="v94-logo">CarePlan<em>· Specialcare</em></div></div><div class="v94-patient" id="v94Patient"></div><nav class="v94-side-nav" id="v94SideNav"></nav><div class="v94-side-foot">Private authenticated CarePlan workspace<br>Cloud records and private media are protected by workspace access controls.</div>';workspace.className='v94-workspace';old.forEach(n=>workspace.appendChild(n));app.append(sidebar,workspace);
 const bottom=workspace.querySelector('#bottomNav');[['calendar','Calendar','One calendar for every care module.'],['therapy','Therapies','Physiotherapy, OT, speech and cognitive activities.'],['appointments','Appointments','Hospitals, preparation and outcomes.'],['meals','Meal Plan','Seven-day plan and reusable meals.'],['medicines','Medicines','Master medicine list and administrations.'],['grocery','Grocery Plan','Active list and reusable library.'],['sos','SOS & Handover','Emergency identity and instant print.']].forEach(([id,title,sub])=>{if(!document.getElementById('screen-'+id)){const s=document.createElement('section');s.className='screen';s.id='screen-'+id;s.innerHTML=`<div class="screen-head"><h1>${title}</h1><p>${sub}</p></div><div class="scroll" id="${id}Scroll"></div>`;workspace.insertBefore(s,bottom)}});
 const more=document.createElement('div');more.id='v94More';more.setAttribute('aria-hidden','true');more.innerHTML='<aside class="v94-drawer" role="dialog" aria-modal="true" aria-label="CarePlan navigation"><header class="v94-drawer-head"><div class="v94-drawer-brand"><div class="v94-mark">CP</div><div class="v94-drawer-title">CarePlan<em>· Specialcare</em></div></div><button class="v94-drawer-close" data-v94-close="v94More" aria-label="Close navigation"></button></header><div class="v94-drawer-patient" id="v94DrawerPatient"></div><nav class="v94-drawer-nav" id="v94MoreGrid" aria-label="All CarePlan modules"></nav><div class="v94-drawer-foot">All care modules are available here and in the desktop sidebar.<br>Private authenticated CarePlan workspace.</div></aside>';document.body.appendChild(more);
 const viewer=document.createElement('div');viewer.className='v94-media-viewer';viewer.id='v94MediaViewer';viewer.innerHTML='<button data-v94-close-media>×</button><div id="v94MediaBody"></div>';document.body.appendChild(viewer);
 document.getElementById('editorModal').querySelector('.sheet')?.classList.add('v94-sheet');document.getElementById('detailModal').querySelector('.sheet')?.classList.add('v94-sheet');
}
function v94Title(s){return ({today:'Today',calendar:'Calendar',care:'Daily Care',therapy:'Therapies',appointments:'Appointments',meals:'Meal Plan',medicines:'Medicines',grocery:'Grocery Plan',logs:'Care Logs',sos:'SOS & Handover',profile:'Care Profile'})[s]||'CarePlan'}
function v94Sub(s){return ({today:'Everything due on the selected day',calendar:'One calendar for the complete care plan',care:'Recurring personal and clinical care routines',therapy:'Physiotherapy, OT, speech, cognitive and more',appointments:'Hospital appointments and preparation',meals:'Weekly feeding plan and reusable meal library',medicines:'Current medicines, PRN, rescue and administration history',grocery:'Active shopping list and reusable item library',logs:'Structured observations with media evidence',sos:'Emergency identity and complete printable handover',profile:'Patient, caregivers, hospitals and data safety'})[s]||''}
function v94SideButton([k,l]){return `<button class="v94-side-btn ${state.screen===k?'active':''} ${k==='sos'?'sos':''}" data-v94-nav="${k}">${svg(k,18)}<span>${l}</span></button>`}
function v94RenderNav(){
 const p=state.patient,patientHTML=`<span class="ava">${esc((p.preferredName||p.legalName).slice(0,1))}</span><div><strong>${esc(p.preferredName)}</strong><span>${esc(p.primaryDx)}</span></div>`;
 document.getElementById('v94Patient').innerHTML=patientHTML;
 const drawerPatient=document.getElementById('v94DrawerPatient');if(drawerPatient)drawerPatient.innerHTML=patientHTML;
 const grouped=`<div class="v94-nav-sec">Care workspace</div>${V94_NAV.slice(0,4).map(v94SideButton).join('')}<div class="v94-nav-sec">Plans & records</div>${V94_NAV.slice(4,9).map(v94SideButton).join('')}<div class="v94-nav-sec">Safety & profile</div>${V94_NAV.slice(9).map(v94SideButton).join('')}`;
 document.getElementById('v94SideNav').innerHTML=grouped;
 const secondaryActive=!['today','care','therapy','calendar'].includes(state.screen);
 document.getElementById('bottomNav').innerHTML=[['today','Home'],['care','Daily Care'],['therapy','Therapy'],['calendar','Calendar']].map(([k,l])=>`<button class="nav ${state.screen===k?'active':''}" data-v94-mobile="${k}">${svg(k,20)}<span>${l}</span></button>`).join('')+`<button class="nav nav-menu ${secondaryActive?'active':''}" data-v94-mobile="menu" aria-label="Open all CarePlan navigation" aria-controls="v94More" aria-expanded="false">${svg('more',22)}<span>Menu</span></button>`;
 document.getElementById('v94MoreGrid').innerHTML=grouped;
 document.querySelectorAll('[data-v94-close]').forEach(b=>b.innerHTML=svg('close',16));
}
function v94OpenDrawer(){const d=document.getElementById('v94More');if(!d)return;d.classList.add('show');d.setAttribute('aria-hidden','false');const b=document.querySelector('[data-v94-mobile="menu"]');if(b)b.setAttribute('aria-expanded','true');requestAnimationFrame(()=>d.querySelector('.v94-drawer-close')?.focus())}
function v94CloseDrawer(){const d=document.getElementById('v94More');if(!d)return;d.classList.remove('show');d.setAttribute('aria-hidden','true');const b=document.querySelector('[data-v94-mobile="menu"]');if(b)b.setAttribute('aria-expanded','false')}

function v94SetScreen(s){state.screen=s;save();v94CloseDrawer();document.querySelectorAll('.screen').forEach(x=>x.classList.remove('active'));document.getElementById('screen-'+s)?.classList.add('active');v94Render()}
function v94WeekDates(){const mon=v94StartMonday(state.selectedDate);return Array.from({length:7},(_,i)=>v94AddDays(mon,i))}
function v94Completion(source,sourceId,date,time=''){return state.completions.find(c=>c.source===source&&c.sourceId===sourceId&&c.date===date&&c.time===time)}
function v94SetCompletion(source,sourceId,date,time){const old=v94Completion(source,sourceId,date,time);if(old)state.completions=state.completions.filter(c=>c!==old);else state.completions.push({id:v94Uid(),source,sourceId,date,time,status:'Done',completedAt:new Date().toISOString(),caregiver:state.caregivers?.[0]?.displayName||''});save()}
function v94PageHead(title,desc,actions=''){return `<div class="v94-page-head"><div><div class="eyebrow">CarePlan · PWA Preview</div><h1>${title}</h1><p>${desc}</p></div><div class="v94-page-actions">${actions}</div></div>`}
function v94DateStrip(){const today=v94DateISO(new Date());return `<div class="v94-date-toolbar"><button class="v94-icon-btn" data-v94-week="-7">${svg('back',16)}</button><div class="v94-date-label">Week of ${v94FormatDate(v94WeekDates()[0],{day:'numeric',month:'long',year:'numeric'})}</div><button class="secondary" data-v94-today>Today</button><button class="v94-icon-btn" data-v94-week="7">${svg('arrow',16)}</button></div><div class="v94-date-strip">${v94WeekDates().map(d=>{const x=v94ParseDate(d);return `<button class="v94-date-btn ${d===state.selectedDate?'active':''} ${d===today?'today':''}" data-v94-date="${d}"><strong>${V94_DAY_SHORT[x.getDay()]}</strong><span>${x.getDate()}</span><small>${x.toLocaleDateString('en-MY',{month:'short'})}</small></button>`}).join('')}</div>`}
function v94HospitalName(hid){return state.hospitals.find(h=>h.id===hid)?.name||'Unlinked hospital'}
function v94MediaStrip(ids=[]){return ids.length?`<div class="v94-media-strip">${ids.map(a=>`<button class="v94-media-thumb v94-media-loading" data-v94-media="${typeof a==='string'?a:a.id}" aria-label="Open media"></button>`).join('')}</div>`:''}
function v94TodayItems(date=state.selectedDate){const dow=v94ParseDate(date).getDay(),items=[];state.routines.filter(r=>r.active&&r.days.includes(dow)).forEach(r=>items.push({source:'routine',id:r.id,time:r.time,title:r.title,sub:`Daily Care · ${r.category}`,notes:r.instructions,type:'care',attachments:r.attachments||[]}));state.therapies.filter(t=>t.active&&t.days.includes(dow)).forEach(t=>items.push({source:'therapy',id:t.id,time:t.time,title:t.title,sub:`${t.category} · ${t.duration} min`,notes:t.instructions,type:'therapy',attachments:t.attachments||[]}));state.mealAssignments.filter(m=>m.date===date).forEach(m=>items.push({source:'meal',id:m.id,time:m.time,title:m.name,sub:`${m.slot} · ${m.portion} · ${m.route}`,notes:m.notes,type:'feed',attachments:[]}));state.medications.filter(m=>m.status==='Current'&&!m.prn).forEach(m=>m.times.filter(t=>t!=='PRN').forEach(time=>items.push({source:'med',id:m.id,time,title:m.name,sub:`${m.dose} · ${m.route}`,notes:m.instructions,type:'med',attachments:[]})));state.appointments.filter(a=>a.date===date&&a.status!=='Cancelled').forEach(a=>items.push({source:'appointment',id:a.id,time:a.time,title:a.title,sub:`${v94HospitalName(a.hospitalId)} · ${a.department}`,notes:a.prep,type:'appt',attachments:[]}));return items.sort((a,b)=>a.time.localeCompare(b.time))}
function v94ItemDone(item,date){if(item.source==='med')return state.administrations.some(a=>a.medId===item.id&&a.date===date&&a.scheduledTime===item.time&&a.status==='Given');return !!v94Completion(item.source,item.id,date,item.time)}
function v94Timeline(items,date){if(!items.length)return `<div class="card empty"><div class="empty-icon">${svg('calendar',24)}</div><h3>No scheduled items</h3><p>This date has no care, therapy, meals, medicines or appointments.</p></div>`;return `<div class="v94-timeline">${items.map(it=>{const done=v94ItemDone(it,date);return `<article class="v94-timeline-item card ${done?'done':''}"><time class="v94-time">${esc(it.time)}</time><span class="v94-dot ${it.type}">${svg(it.type==='feed'?'meal':it.type==='med'?'med':it.type==='appt'?'appt':it.type==='therapy'?'therapy':'care',17)}</span><div class="v94-main"><h4>${esc(it.title)}</h4><p>${esc(it.sub)}</p>${it.notes?`<p>${esc(it.notes)}</p>`:''}<div class="plan-meta"><span class="mini">${done?'Completed':'Pending'}</span><span class="mini">${it.source==='routine'?'Daily Care':it.source==='appointment'?'Appointment':it.source}</span></div>${v94MediaStrip(it.attachments)}</div><div class="v94-timeline-actions"><button class="v94-icon-btn" data-v94-open="${it.source}|${it.id}">${svg('arrow',15)}</button><button class="v94-icon-btn ${done?'done':''}" data-v94-complete="${it.source}|${it.id}|${date}|${it.time}">${svg('check',15)}</button></div></article>`}).join('')}</div>`}
function v94Section(title,sub,action=''){return `<div class="section-title"><div><h3>${title}</h3><p>${sub}</p></div>${action}</div>`}
function v94Stat(icon,value,label,sub){return `<div class="v94-stat card"><div class="v94-stat-top"><span class="v94-stat-icon">${svg(icon,16)}</span><strong>${value}</strong></div><label>${label}</label><small>${sub}</small></div>`}
function v94RenderToday(){
 const items=v94TodayItems(),done=items.filter(x=>v94ItemDone(x,state.selectedDate)).length,pct=items.length?Math.round(done/items.length*100):0;
 const currentMeds=state.medications.filter(m=>m.status==='Current').length,urgent=state.medications.filter(m=>m.status==='Current'&&(m.rescue||m.prn)).length;
 document.getElementById('todayScroll').innerHTML=`${v94PageHead(`Good ${new Date().getHours()<12?'morning':new Date().getHours()<18?'afternoon':'evening'}, ${esc(state.caregivers[0]?.displayName||'Caregiver')}.`,`A complete view of ${esc(state.patient.preferredName)}’s care for ${v94FormatDate(state.selectedDate,{weekday:'long',day:'numeric',month:'long'})}.`,`<button class="secondary" data-v94-log>${svg('plus',14)} Add log</button><button class="primary" data-v94-nav="sos">${svg('sos',14)} SOS</button>`)}
 ${v94DateStrip()}
 <div class="v94-hero-grid"><div class="care-banner"><div class="banner-row"><div><div class="banner-code">Selected day · ${done} of ${items.length} complete</div><h2>${esc(state.patient.preferredName)}’s care rhythm</h2><p>${esc(state.patient.primaryDx)} · ${esc(state.patient.feeding)}</p></div><span class="banner-action">${pct}%</span></div><div class="progress-line"><span style="width:${pct}%"></span></div></div><div class="v94-safety card"><h3>Safety at a glance</h3><p>${esc(state.patient.emergencyNotes)}</p><div class="v94-safety-actions"><button class="secondary" data-v94-quick="seizure">Log seizure</button><button class="secondary" data-v94-quick="dystonia">Log dystonia</button><button class="primary" data-v94-print-handover>${svg('print',14)} Print handover</button><button class="secondary" data-v94-nav="medicines">${urgent} PRN / rescue</button></div></div></div>
 <div class="v94-stats">${v94Stat('care',state.routines.filter(r=>r.active).length,'Daily Care routines','Personal, clinical and comfort care')}${v94Stat('therapy',state.therapies.filter(t=>t.active).length,'Therapy activities','Physio, OT, speech and cognitive')}${v94Stat('med',currentMeds,'Current medicines','Synced live to SOS handover')}${v94Stat('logs',state.logs.length,'Care logs','Structured records with media')}</div>
 ${v94Section('Today’s complete timeline','Daily Care, therapy, meals, medicines and appointments in time order.',`<button class="text-btn" data-v94-nav="calendar">Open calendar</button>`)}${v94Timeline(items,state.selectedDate)}
 <div class="notice" style="margin-top:14px"><strong>Media follows the task.</strong> Images and short videos added to Daily Care, therapy or cognitive activities appear here as thumbnails. They open only when tapped and never autoplay.</div>`;
 setTimeout(v94HydrateMedia,0)
}
function v94RoutineCard(r){const done=!!v94Completion('routine',r.id,state.selectedDate,r.time);return `<article class="v94-module card ${done?'done':''}"><div class="v94-module-head"><span class="v94-module-icon">${esc(r.icon||'🌿')}</span><div style="flex:1"><h4>${esc(r.title)}</h4><p>${esc(r.time)} · ${esc(r.category)} · ${r.duration||15} min</p></div><button class="v94-icon-btn" data-v94-open="routine|${r.id}">${svg('edit',14)}</button></div><p>${esc(r.instructions||r.notes||'')}</p>${v94MediaStrip(r.attachments)}<div class="v94-module-foot"><span class="v94-pill ${r.active?'':'paused'}">${r.active?(done?'Done on selected date':'Active'):'Paused'}</span><button class="small-btn fill" data-v94-complete="routine|${r.id}|${state.selectedDate}|${r.time}">${done?'Mark pending':'Mark done'}</button></div></article>`}
function v94RenderCare(){const dow=v94ParseDate(state.selectedDate).getDay();let list=state.routines.filter(r=>state.careFilter==='paused'?!r.active:state.careFilter==='all'?true:r.active&&r.days.includes(dow));document.getElementById('careScroll').innerHTML=`${v94PageHead('Daily Care','Personal care, positioning, feeding support, airway care, sleep and family-specific routines.',`<button class="primary" data-v94-new="routine">${svg('plus',14)} Add routine</button>`)}${v94DateStrip()}<div class="chips"><button class="chip ${state.careFilter==='today'?'active':''}" data-v94-care-filter="today">Selected day</button><button class="chip ${state.careFilter==='all'?'active':''}" data-v94-care-filter="all">All routines</button><button class="chip ${state.careFilter==='paused'?'active':''}" data-v94-care-filter="paused">Paused</button></div>${v94Section(state.careFilter==='today'?v94FormatDate(state.selectedDate,{weekday:'long'})+' routines':state.careFilter==='paused'?'Paused routines':'All Daily Care','Completion is recorded separately for each calendar date.')}<div class="v94-grid2">${list.map(v94RoutineCard).join('')||'<div class="card empty">No routines match this view.</div>'}</div>`;setTimeout(v94HydrateMedia,0)}
function v94TherapyCard(t){const done=!!v94Completion('therapy',t.id,state.selectedDate,t.time);return `<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:var(--purplep);color:var(--purple)">${esc(t.icon||'🧠')}</span><div style="flex:1"><h4>${esc(t.title)}</h4><p>${esc(t.time)} · ${esc(t.category)} · ${t.duration} min</p></div><button class="v94-icon-btn" data-v94-open="therapy|${t.id}">${svg('edit',14)}</button></div><p>${esc(t.instructions)}</p>${v94MediaStrip(t.attachments)}<div class="v94-module-foot"><span class="v94-pill ${t.active?'':'paused'}">${t.active?(done?'Done on selected date':'Active'):'Paused'}</span><button class="small-btn fill" data-v94-complete="therapy|${t.id}|${state.selectedDate}|${t.time}">${done?'Mark pending':'Mark done'}</button></div></article>`}
function v94RenderTherapy(){const dow=v94ParseDate(state.selectedDate).getDay();const filter=state.therapyFilter||'all',list=state.therapies.filter(t=>(filter==='all'||t.category===filter)&&(state.therapyDayOnly===false||t.days.includes(dow)));document.getElementById('therapyScroll').innerHTML=`${v94PageHead('Therapies & Cognitive Care','Physiotherapy, occupational therapy, speech and language, cognitive activities and custom therapy programmes.',`<button class="primary" data-v94-new="therapy">${svg('plus',14)} Add activity</button>`)}${v94DateStrip()}<div class="toolbar"><div class="field"><label>Therapy category</label><select class="control" id="v94TherapyFilter"><option value="all">All categories</option>${V94_THERAPY_CATEGORIES.map(c=>`<option ${filter===c?'selected':''}>${c}</option>`).join('')}</select></div><div class="field" style="max-width:220px"><label>Schedule view</label><select class="control" id="v94TherapyScope"><option value="day" ${state.therapyDayOnly!==false?'selected':''}>Selected day</option><option value="all" ${state.therapyDayOnly===false?'selected':''}>All activities</option></select></div></div>${v94Section(state.therapyDayOnly===false?'All therapy activities':v94FormatDate(state.selectedDate,{weekday:'long'})+' activities','Images and short videos added here also render on Today and Calendar.')}<div class="v94-grid2">${list.map(v94TherapyCard).join('')||'<div class="card empty">No therapy activities match this view.</div>'}</div>`;setTimeout(v94HydrateMedia,0)}
function v94EventsForDate(date){const items=v94TodayItems(date);return {items,types:[...new Set(items.map(x=>x.type))]}}
function v94RenderCalendar(){const cur=v94ParseDate(state.monthCursor||state.selectedDate),y=cur.getFullYear(),m=cur.getMonth(),first=new Date(y,m,1),start=new Date(y,m,1-first.getDay()),cells=Array.from({length:42},(_,i)=>{const d=new Date(start);d.setDate(start.getDate()+i);return d});const today=v94DateISO(new Date());document.getElementById('calendarScroll').innerHTML=`${v94PageHead('Unified Calendar','Every care routine, therapy activity, meal, medicine and appointment appears in one calendar.',`<button class="primary" data-v94-new="appointment">${svg('plus',14)} Add appointment</button>`)}<div class="v94-calendar-layout"><div class="v94-calendar-card card"><div class="v94-month-head"><button class="v94-icon-btn" data-v94-month="-1">${svg('back',15)}</button><h3>${cur.toLocaleDateString('en-MY',{month:'long',year:'numeric'})}</h3><button class="v94-icon-btn" data-v94-month="1">${svg('arrow',15)}</button></div><div class="v94-cal-grid">${V94_DAY_SHORT.map(x=>`<div class="v94-dow">${x}</div>`).join('')}${cells.map(d=>{const iso=v94DateISO(d),ev=v94EventsForDate(iso);return `<button class="v94-cal-day ${d.getMonth()!==m?'other':''} ${iso===state.selectedDate?'selected':''} ${iso===today?'today':''}" data-v94-cal-date="${iso}"><span class="v94-cal-num">${d.getDate()}</span><span class="v94-cal-dots">${ev.types.slice(0,5).map(t=>`<i class="v94-cal-dot ${t==='feed'?'meal':t}"></i>`).join('')}</span></button>`}).join('')}</div></div><div class="v94-calendar-card card">${v94Section(v94FormatDate(state.selectedDate,{weekday:'long',day:'numeric',month:'long'}),'Selected-date detail')} ${v94Timeline(v94TodayItems(),state.selectedDate)}</div></div>`;setTimeout(v94HydrateMedia,0)}
function v94RenderAppointments(){const list=[...state.appointments].sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time));document.getElementById('appointmentsScroll').innerHTML=`${v94PageHead('Appointments','Hospital-linked appointments, preparation instructions and follow-up outcomes.',`<button class="primary" data-v94-new="appointment">${svg('plus',14)} Add appointment</button>`)}<div class="v94-grid2">${list.map(a=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:var(--goldp);color:var(--gold)">${svg('appt',18)}</span><div style="flex:1"><h4>${esc(a.title)}</h4><p>${v94FormatDate(a.date,{weekday:'short',day:'numeric',month:'short'})} · ${esc(a.time)}</p></div><button class="v94-icon-btn" data-v94-open="appointment|${a.id}">${svg('edit',14)}</button></div><p><strong>${esc(v94HospitalName(a.hospitalId))}</strong><br>${esc(a.department)}${a.consultant?' · '+esc(a.consultant):''}</p>${a.prep?`<p>Prepare: ${esc(a.prep)}</p>`:''}<div class="v94-module-foot"><span class="v94-pill ${a.status==='Cancelled'?'paused':''}">${esc(a.status)}</span><button class="small-btn" data-v94-cal-date="${a.date}">View date</button></div></article>`).join('')||'<div class="card empty">No appointments yet.</div>'}</div>`}
function v94MealCard(m){return `<div class="v94-meal-slot"><time>${esc(m.time)} · ${esc(m.slot)}</time><h5>${esc(m.name)}</h5><p>${esc(m.portion)} · ${esc(m.route)}</p>${m.notes?`<p>${esc(m.notes)}</p>`:''}<div class="material-actions"><button class="small-btn" data-v94-open="meal|${m.id}">${svg('edit',12)}</button><button class="small-btn" data-v94-complete="meal|${m.id}|${m.date}|${m.time}">${v94Completion('meal',m.id,m.date,m.time)?'Done ✓':'Done'}</button></div></div>`}
function v94RenderMeals(){const dates=v94WeekDates();document.getElementById('mealsScroll').innerHTML=`${v94PageHead('Weekly Meal & Feeding Plan','Different schedules for every day, reusable meals and deliberate copy controls.',`<button class="secondary" data-v94-copy-meals>${svg('copy',14)} Copy day</button><button class="primary" data-v94-new="meal">${svg('plus',14)} Add meal</button>`)}${v94DateStrip()}<div class="v94-week-meals"><div class="v94-meal-grid">${dates.map(d=>{const list=state.mealAssignments.filter(m=>m.date===d).sort((a,b)=>a.time.localeCompare(b.time));return `<section class="v94-meal-day"><header class="v94-meal-head"><div><strong>${v94FormatDate(d,{weekday:'short'})}</strong><span>${v94FormatDate(d,{day:'numeric',month:'short'})}</span></div><button class="v94-icon-btn" style="width:27px;height:27px" data-v94-new-meal-date="${d}">${svg('plus',12)}</button></header><div class="v94-meal-body">${list.map(v94MealCard).join('')||'<p style="font-size:8px;color:var(--muted);padding:6px">No meals scheduled.</p>'}<button class="v94-add-day" data-v94-new-meal-date="${d}">+ Add meal</button></div></section>`}).join('')}</div></div>${v94Section('Saved meal library','Reusable feeds, prepared meals and recipes.',`<button class="text-btn" data-v94-new="mealLibrary">+ Save meal</button>`)}<div class="v94-grid3">${state.mealLibrary.map(m=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:var(--amberp);color:var(--amber)">${svg('meal',18)}</span><div style="flex:1"><h4>${esc(m.name)}</h4><p>${esc(m.portion)} · ${esc(m.calories)} · ${esc(m.texture)}</p></div><button class="v94-icon-btn" data-v94-open="mealLibrary|${m.id}">${svg('edit',14)}</button></div><p>${esc(m.ingredients||'')}</p><div class="v94-module-foot"><span class="v94-pill">${esc(m.route)}</span><button class="small-btn fill" data-v94-assign-meal="${m.id}">Add to schedule</button></div></article>`).join('')}</div>`}
function v94MedSchedule(m){return m.prn?'PRN':(m.times||[]).join(', ')}
function v94RenderMedicines(){const current=state.medications.filter(m=>m.status==='Current'),history=state.medications.filter(m=>m.status!=='Current');document.getElementById('medicinesScroll').innerHTML=`${v94PageHead('Medicines','One medicine master list powers Today, administration records, SOS and the printed handover.',`<button class="primary" data-v94-new="medicine">${svg('plus',14)} Add medicine</button>`)}<div class="notice"><strong>Live handover synchronisation:</strong> current, PRN and rescue medicines below are the exact records used in the SOS handover. Paused and discontinued medicines are excluded from “Current Medicines” and retained in medication history.</div>${v94Section('Current, PRN & rescue medicines','Edit once; every connected view updates immediately.')}<div class="v94-grid2">${current.map(m=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:${m.rescue?'var(--redp)':'var(--bluep)'};color:${m.rescue?'var(--red)':'var(--blue)'}">${svg('med',18)}</span><div style="flex:1"><h4>${esc(m.name)}</h4><p>${esc(m.strength)} · ${esc(m.dose)} · ${esc(m.route)}</p></div><button class="v94-icon-btn" data-v94-open="medicine|${m.id}">${svg('edit',14)}</button></div><p>${esc(m.indication||m.instructions||'')}</p><div class="plan-meta"><span class="mini">${esc(v94MedSchedule(m))}</span>${m.prn?'<span class="mini">PRN</span>':''}${m.rescue?'<span class="mini">Rescue</span>':''}<span class="mini">Handover synced</span></div><div class="v94-module-foot"><span class="v94-pill ${m.rescue?'critical':''}">${m.rescue?'Emergency':m.prn?'As needed':'Current'}</span><button class="small-btn fill" data-v94-admin-med="${m.id}">Record administration</button></div></article>`).join('')}</div>${v94Section('Administration history','Every dose is date-specific and separate from the medicine definition.')}<div class="plan-list">${[...state.administrations].sort((a,b)=>(b.date+b.actualTime).localeCompare(a.date+a.actualTime)).slice(0,20).map(a=>{const m=state.medications.find(x=>x.id===a.medId);return `<article class="grocery-card card"><span class="grocery-check" style="background:var(--greenp);color:var(--green);border:0">${svg('check',14)}</span><div><h4>${esc(m?.name||'Medicine')}</h4><p>${v94FormatDate(a.date,{day:'numeric',month:'short'})} · ${esc(a.actualTime||a.scheduledTime)} · ${esc(a.status)} · ${esc(a.dose||m?.dose||'')}</p></div><span class="price">${esc(a.caregiver||'')}</span></article>`}).join('')||'<div class="card empty">No administrations recorded.</div>'}</div>${history.length?v94Section('Medication history','Paused and discontinued medicines remain available for review.')+`<div class="v94-grid2">${history.map(m=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon">${svg('med',18)}</span><div style="flex:1"><h4>${esc(m.name)}</h4><p>${esc(m.dose)} · ${esc(m.route)}</p></div><button class="v94-icon-btn" data-v94-open="medicine|${m.id}">${svg('edit',14)}</button></div><div class="v94-module-foot"><span class="v94-pill paused">${esc(m.status)}</span><span style="font-size:8px;color:var(--muted)">Not in current handover</span></div></article>`).join('')}</div>`:''}`}
function v94RenderGrocery(){const total=state.groceries.reduce((s,g)=>s+Number(g.cost||0),0),bought=state.groceries.filter(g=>g.checked).reduce((s,g)=>s+Number(g.cost||0),0);document.getElementById('groceryScroll').innerHTML=`${v94PageHead('Grocery Plan','An active shopping list plus a reusable library of regular food, feeding and medical supplies.',`<button class="primary" data-v94-new="grocery">${svg('plus',14)} Add item</button>`)}<div class="v94-summary card"><div><strong>RM ${bought.toFixed(2)} purchased</strong><span>${state.groceries.filter(g=>!g.checked).length} items remaining</span></div><strong>RM ${total.toFixed(2)}</strong></div>${v94Section('Active list','Check purchased items, edit quantities or remove them.')}<div class="plan-list">${state.groceries.map(g=>`<article class="grocery-card card ${g.checked?'checked':''}"><button class="grocery-check" data-v94-grocery-check="${g.id}">${g.checked?svg('check',14):''}</button><div style="flex:1"><h4>${esc(g.name)}</h4><p>${esc(g.category)} · ${esc(g.qty)}</p></div><span class="price">RM ${Number(g.cost||0).toFixed(2)}</span><button class="v94-icon-btn" data-v94-open="grocery|${g.id}">${svg('edit',13)}</button></article>`).join('')}</div>${v94Section('Saved grocery library','Reusable items can be added without retyping.',`<button class="text-btn" data-v94-new="groceryLibrary">+ Save item</button>`)}<div class="v94-grid3">${state.groceryLibrary.map(g=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon">${svg('grocery',18)}</span><div style="flex:1"><h4>${esc(g.name)}</h4><p>${esc(g.category)} · ${esc(g.qty)} · RM ${Number(g.cost||0).toFixed(2)}</p></div><button class="v94-icon-btn" data-v94-open="groceryLibrary|${g.id}">${svg('edit',13)}</button></div><p>${esc(g.notes||'')}</p><div class="v94-module-foot"><span class="v94-pill">Reusable</span><button class="small-btn fill" data-v94-add-library-grocery="${g.id}">Add to list</button></div></article>`).join('')}</div>`}
function v94LogCard(l){return `<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:${['Seizure','Dystonia'].includes(l.type)?'var(--redp)':'var(--maroonp)'};color:${['Seizure','Dystonia'].includes(l.type)?'var(--red)':'var(--maroon)'}">${svg('logs',18)}</span><div style="flex:1"><h4>${esc(l.title)}</h4><p>${v94FormatDate(l.date,{day:'numeric',month:'short',year:'numeric'})} · ${esc(l.time)} · ${esc(l.type)}</p></div><button class="v94-icon-btn" data-v94-open="log|${l.id}">${svg('edit',14)}</button></div><p>${esc(l.summary)}</p><div class="plan-meta">${Object.entries(l.fields||{}).slice(0,4).map(([k,v])=>`<span class="mini">${esc(k)}: ${esc(v)}</span>`).join('')}<span class="mini">${esc(l.caregiver)}</span></div>${v94MediaStrip(l.attachments)}</article>`}
function v94RenderLogs(){const filter=state.logFilter||'all',list=[...state.logs].filter(l=>filter==='all'||l.type===filter).sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time));document.getElementById('logsScroll').innerHTML=`${v94PageHead('Structured Care Logs','Seizure, dystonia, fluids, medicines, vitals, positioning, behaviour, development and general observations.',`<button class="secondary" data-v94-print-logs>${svg('print',14)} Print logs</button><button class="primary" data-v94-log>${svg('plus',14)} Add log</button>`)}<div class="chips"><button class="chip ${filter==='all'?'active':''}" data-v94-log-filter="all">All</button>${V94_LOG_TYPES.map(t=>`<button class="chip ${filter===t?'active':''}" data-v94-log-filter="${t}">${t}</button>`).join('')}</div><div class="v94-grid2">${list.map(v94LogCard).join('')||'<div class="card empty">No logs match this filter.</div>'}</div>`;setTimeout(v94HydrateMedia,0)}
function v94EmergencyContacts(){const fromCaregivers=state.caregivers.filter(c=>c.emergency).map(c=>({name:c.fullName,role:`${c.relationship} · ${c.type}`,phone:c.phone}));return fromCaregivers.length?fromCaregivers:state.emergencyContacts}
function v94RenderSOS(){const current=state.medications.filter(m=>m.status==='Current'),contacts=v94EmergencyContacts();document.getElementById('sosScroll').innerHTML=`${v94PageHead('SOS & Complete Handover','Critical identity, contacts, medicines and one-tap printing for emergency transfer.',`<button class="primary" data-v94-print-handover>${svg('print',14)} Print Complete Handover</button>`)}<div class="detail-hero"><div class="type">Emergency identity · ${esc(state.patient.blood)} · ${esc(state.patient.allergies)}</div><h3>${esc(state.patient.legalName)}</h3><p>${esc(state.patient.primaryDx)}<br>${esc(state.patient.emergencyNotes)}</p><div class="detail-tags"><span>DOB ${esc(state.patient.dob)}</span><span>${esc(state.patient.feeding)}</span><span>${state.hospitals.length} hospitals</span><span>${current.length} current medicines</span></div></div><div class="v94-grid2"><section class="v94-module card">${v94Section('Emergency contacts','Derived from caregiver profiles.')} ${contacts.map(c=>`<div class="contact-row"><span class="contact-icon">${svg('phone',15)}</span><div><strong>${esc(c.name)}</strong><small>${esc(c.role)}</small></div><a href="tel:${esc(c.phone)}">${esc(c.phone)}</a></div>`).join('')}</section><section class="v94-module card">${v94Section('Current medicine summary','This exact master list prints in the handover.')} ${current.map(m=>`<div class="grocery-card"><span class="grocery-check" style="background:${m.rescue?'var(--redp)':'var(--bluep)'};color:${m.rescue?'var(--red)':'var(--blue)'};border:0">${svg('med',13)}</span><div><h4>${esc(m.name)}</h4><p>${esc(m.dose)} · ${esc(m.route)} · ${esc(v94MedSchedule(m))}</p></div></div>`).join('')}</section></div><div class="notice warning" style="margin-top:12px"><strong>Print behaviour:</strong> “Print Complete Handover” generates the document from the latest patient, caregiver, hospital, medicine, Daily Care, therapy and appointment records, then immediately opens the browser print dialog.</div>`}
function v94ProfileTabs(){const t=state.profileTab||'patient';return `<div class="chips">${[['patient','Patient'],['caregivers','Caregivers'],['hospitals','Hospitals'],['data','Data & PWA']].map(([k,l])=>`<button class="chip ${t===k?'active':''}" data-v94-profile-tab="${k}">${l}</button>`).join('')}</div>`}
function v94RenderProfile(){const tab=state.profileTab||'patient';let body='';if(tab==='patient'){const p=state.patient;body=`<div class="profile-card card"><h3>Complete patient profile</h3><div class="form-grid"><div class="field"><label>Legal name</label><input class="control" id="v94PfLegal" value="${esc(p.legalName)}"></div><div class="field"><label>Preferred name</label><input class="control" id="v94PfPreferred" value="${esc(p.preferredName)}"></div><div class="field"><label>Date of birth</label><input class="control" type="date" id="v94PfDob" value="${esc(p.dob)}"></div><div class="field"><label>Sex / gender</label><input class="control" id="v94PfSex" value="${esc(p.sex)}"></div><div class="field"><label>Blood type</label><input class="control" id="v94PfBlood" value="${esc(p.blood)}"></div><div class="field"><label>Primary diagnosis</label><input class="control" id="v94PfDx" value="${esc(p.primaryDx)}"></div><div class="field full"><label>Home address</label><textarea class="control" id="v94PfAddress">${esc(p.address)}</textarea></div><div class="field full"><label>Secondary diagnoses</label><textarea class="control" id="v94PfSecondary">${esc(p.secondaryDx)}</textarea></div><div class="field"><label>Allergies</label><textarea class="control" id="v94PfAllergies">${esc(p.allergies)}</textarea></div><div class="field"><label>Feeding method</label><textarea class="control" id="v94PfFeeding">${esc(p.feeding)}</textarea></div><div class="field"><label>Communication</label><textarea class="control" id="v94PfCommunication">${esc(p.communication)}</textarea></div><div class="field"><label>Mobility & positioning</label><textarea class="control" id="v94PfMobility">${esc(p.mobility)}</textarea></div><div class="field full"><label>Critical emergency / handover notes</label><textarea class="control" id="v94PfEmergency">${esc(p.emergencyNotes)}</textarea></div></div><button class="primary wide" data-v94-save-patient>Save complete patient profile</button></div>`}else if(tab==='caregivers'){body=`${v94Section('Caregiver profiles','Primary, secondary and additional caregivers appear in the complete handover.',`<button class="text-btn" data-v94-new="caregiver">+ Add caregiver</button>`)}<div class="v94-grid2">${state.caregivers.map(c=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon">${svg('profile',18)}</span><div style="flex:1"><h4>${esc(c.fullName)}</h4><p>${esc(c.type)} · ${esc(c.relationship)} · ${esc(c.occupation)}</p></div><button class="v94-icon-btn" data-v94-open="caregiver|${c.id}">${svg('edit',14)}</button></div><p>${esc(c.phone)} · ${esc(c.email)}<br>${esc(c.address)}</p><div class="v94-module-foot"><span class="v94-pill">${c.decision?'Medical decision authority':'No decision authority'}</span><span class="v94-pill ${c.emergency?'':'paused'}">${c.emergency?'Emergency contact':'Not emergency contact'}</span></div></article>`).join('')}</div>`}else if(tab==='hospitals'){body=`${v94Section('Hospitals & care centres','Unlimited hospitals, MRN/card numbers, departments and consultants.',`<button class="text-btn" data-v94-new="hospital">+ Add hospital</button>`)}<div class="v94-grid2">${state.hospitals.map(h=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon">${svg('hospital',18)}</span><div style="flex:1"><h4>${esc(h.name)}</h4><p>${esc(h.department)} · ${esc(h.mrn)}</p></div><button class="v94-icon-btn" data-v94-open="hospital|${h.id}">${svg('edit',14)}</button></div><p>${esc(h.consultant)} · ${esc(h.phone)}<br>${esc(h.address||'')}${h.notes?'<br>'+esc(h.notes):''}</p><div class="v94-module-foot"><span class="v94-pill ${h.primary?'':'paused'}">${h.primary?'Primary hospital':'Linked centre'}</span></div></article>`).join('')}</div>`}else{body=`<div class="profile-card card"><h3>Data, sync & backup</h3><div class="notice warning"><strong>This browser keeps an offline working cache.</strong> Clearing browser/site data, using private browsing, uninstalling the PWA, resetting the device or browser storage failure may remove it. Cloud sync must show as confirmed before this browser cache is treated as backed up.</div><div class="actions-row" style="margin-top:10px"><button class="secondary" data-v94-export>${svg('download',14)} Export JSON</button><button class="secondary" data-v94-import>${svg('upload',14)} Import JSON</button></div><input type="file" id="v94ImportFile" accept="application/json" class="hidden"><button class="ghost wide" data-v94-reset style="margin-top:8px;color:var(--maroon)">${svg('trash',14)} Reset fictional preview data</button></div><div class="profile-card card"><h3>PWA security model</h3><p style="font-size:10px;line-height:1.6;color:var(--muted)">Mobile-first installation, responsive desktop sidebar, the same modules on every device, offline-safe shell, Cloudflare Access authentication, D1 records, R2 private media, conflict protection and encrypted backups. No feature is desktop-only or mobile-only.</p></div>`}document.getElementById('profileScroll').innerHTML=`${v94PageHead('Care Profile','Complete patient, caregiver and hospital data feeds the SOS handover automatically.')} ${v94ProfileTabs()}${body}`}
function v94Render(){renderHeader();document.querySelectorAll('.screen').forEach(x=>x.classList.toggle('active',x.id==='screen-'+state.screen));v94RenderNav();if(state.screen==='today')v94RenderToday();if(state.screen==='calendar')v94RenderCalendar();if(state.screen==='care')v94RenderCare();if(state.screen==='therapy')v94RenderTherapy();if(state.screen==='appointments')v94RenderAppointments();if(state.screen==='meals')v94RenderMeals();if(state.screen==='medicines')v94RenderMedicines();if(state.screen==='grocery')v94RenderGrocery();if(state.screen==='logs')v94RenderLogs();if(state.screen==='sos')v94RenderSOS();if(state.screen==='profile')v94RenderProfile()}
let v94PendingMedia=[];let v94MediaDbPromise=null;const v94MemoryMedia=new Map();
function v94OpenMediaDb(){try{if(!('indexedDB'in window))return Promise.resolve(null);if(v94MediaDbPromise)return v94MediaDbPromise;v94MediaDbPromise=new Promise(resolve=>{try{const r=indexedDB.open(V94_MEDIA_DB,1);r.onupgradeneeded=()=>{if(!r.result.objectStoreNames.contains('media'))r.result.createObjectStore('media',{keyPath:'id'})};r.onsuccess=()=>resolve(r.result);r.onerror=()=>resolve(null)}catch(e){resolve(null)}});return v94MediaDbPromise}catch(e){return Promise.resolve(null)}}
async function v94PutMedia(item){const db=await v94OpenMediaDb();if(!db){v94MemoryMedia.set(item.id,item);return true;}return new Promise(res=>{const tx=db.transaction('media','readwrite');tx.objectStore('media').put(item);tx.oncomplete=()=>res(true);tx.onerror=()=>res(false)})}
async function v94GetMedia(id){const db=await v94OpenMediaDb();if(!db)return v94MemoryMedia.get(id)||null;return new Promise(res=>{const r=db.transaction('media').objectStore('media').get(id);r.onsuccess=()=>res(r.result||null);r.onerror=()=>res(null)})}
async function v94DeleteMedia(id){const db=await v94OpenMediaDb();if(!db){v94MemoryMedia.delete(id);return;}return new Promise(res=>{const tx=db.transaction('media','readwrite');tx.objectStore('media').delete(id);tx.oncomplete=()=>res()})}
async function v94ClearMedia(){const db=await v94OpenMediaDb();if(!db){v94MemoryMedia.clear();return;}return new Promise(res=>{const tx=db.transaction('media','readwrite');tx.objectStore('media').clear();tx.oncomplete=()=>res()})}
function v94VideoDuration(file){return new Promise(res=>{const u=URL.createObjectURL(file),v=document.createElement('video');v.preload='metadata';v.onloadedmetadata=()=>{const d=v.duration;URL.revokeObjectURL(u);res(d)};v.onerror=()=>{URL.revokeObjectURL(u);res(Infinity)};v.src=u})}
async function v94QueueFiles(files){for(const file of [...files]){const isImage=file.type.startsWith('image/'),isVideo=file.type.startsWith('video/');if(!isImage&&!isVideo){toast('Only images and short videos are supported');continue}if(isImage&&file.size>8*1024*1024){toast('Image exceeds 8 MB');continue}if(isVideo&&file.size>25*1024*1024){toast('Video exceeds 25 MB');continue}if(isVideo&&(await v94VideoDuration(file))>30){toast('Video must be 30 seconds or shorter');continue}v94PendingMedia.push({id:v94Uid(),name:file.name,type:file.type,kind:isVideo?'video':'image',file,new:true})}v94RenderPendingMedia()}
function v94MediaField(){return `<div class="v94-form-section">Images & short video</div><div class="v94-file-drop"><strong>Add visual evidence or guidance</strong><p>Images up to 8 MB. Videos up to 25 MB and 30 seconds. Media appears on Today when attached to scheduled care or therapy.</p><button class="secondary" type="button" data-v94-pick-media>${svg('image',14)} Choose image / video</button><input type="file" id="v94MediaInput" accept="image/*,video/*" multiple hidden><div class="v94-attachments" id="v94PendingMedia"></div></div>`}
async function v94RenderPendingMedia(){const el=document.getElementById('v94PendingMedia');if(!el)return;el.innerHTML=v94PendingMedia.map(x=>`<div class="v94-attach"><div class="preview" data-v94-pending-preview="${x.id}"></div><span>${esc(x.name||x.id)}</span><button class="v94-attach-remove" data-v94-remove-pending="${x.id}">×</button></div>`).join('');for(const x of v94PendingMedia){let blob=x.file;if(!blob){const rec=await v94GetMedia(x.id);blob=rec?.blob}const box=el.querySelector(`[data-v94-pending-preview="${CSS.escape(x.id)}"]`);if(box&&blob){const u=URL.createObjectURL(blob);box.innerHTML=x.kind==='video'||x.type?.startsWith('video')?`<video muted playsinline src="${u}"></video>`:`<img alt="" src="${u}">`}}
}
async function v94CommitMedia(){const refs=[];for(const x of v94PendingMedia){if(x.new&&x.file)await v94PutMedia({id:x.id,name:x.name,type:x.type,kind:x.kind,createdAt:new Date().toISOString(),blob:x.file});refs.push({id:x.id,name:x.name,type:x.type,kind:x.kind})}return refs}
async function v94HydrateMedia(){for(const btn of document.querySelectorAll('.v94-media-thumb[data-v94-media]')){if(btn.dataset.ready)return;btn.dataset.ready='1';const rec=await v94GetMedia(btn.dataset.v94Media);btn.classList.remove('v94-media-loading');if(!rec){btn.innerHTML=svg('image',18);continue}const u=URL.createObjectURL(rec.blob);btn.innerHTML=(rec.kind==='video'||rec.type?.startsWith('video'))?`<video muted playsinline preload="metadata" src="${u}"></video><span class="play">▶</span>`:`<img alt="Attached care media" src="${u}">`}}
async function v94ShowMedia(id){const rec=await v94GetMedia(id);if(!rec){toast('Media is unavailable in this browser');return}const u=URL.createObjectURL(rec.blob),body=document.getElementById('v94MediaBody');body.innerHTML=(rec.kind==='video'||rec.type?.startsWith('video'))?`<video controls muted playsinline src="${u}"></video>`:`<img alt="Care attachment" src="${u}">`;document.getElementById('v94MediaViewer').classList.add('show')}
function v94PrepareEditor(title,html){document.getElementById('editorTitle').textContent=title;document.getElementById('editorBody').innerHTML=html;openModal('editorModal');setTimeout(v94RenderPendingMedia,0)}
function v94Field(label,id,value='',type='text',full=false){return `<div class="field ${full?'full':''}"><label>${label}</label><input class="control" id="${id}" type="${type}" value="${esc(value)}"></div>`}
function v94Text(label,id,value='',full=true){return `<div class="field ${full?'full':''}"><label>${label}</label><textarea class="control" id="${id}" rows="3">${esc(value)}</textarea></div>`}
function v94DayChecks(days=[]){return `<div class="v94-check-row">${V94_DAY_NAMES.map((d,i)=>`<button type="button" class="v94-check-chip ${days.includes(i)?'active':''}" data-v94-editor-day="${i}">${d.slice(0,3)}</button>`).join('')}</div>`}
function v94OpenRoutineEditor(r={}){v94PendingMedia=[...(r.attachments||[])];v94PrepareEditor(r.id?'Edit Daily Care':'Add Daily Care',`<div class="form-grid">${v94Field('Icon','v94ErIcon',r.icon||'🌿')}${v94Field('Routine name','v94ErTitle',r.title||'')}${v94Field('Category','v94ErCategory',r.category||'Personal care')}${v94Field('Time','v94ErTime',r.time||'09:00','time')}${v94Field('Duration (minutes)','v94ErDuration',r.duration||15,'number')}<div class="field"><label>Status</label><select class="control" id="v94ErActive"><option value="true" ${r.active!==false?'selected':''}>Active</option><option value="false" ${r.active===false?'selected':''}>Paused</option></select></div><div class="field full"><label>Days</label>${v94DayChecks(r.days||[0,1,2,3,4,5,6])}</div>${v94Text('Instructions / how to support','v94ErInstructions',r.instructions||r.notes||'')}</div>${v94MediaField()}<div class="actions-row"><button class="primary" data-v94-save-routine="${r.id||''}">Save routine</button>${r.id?'<button class="ghost" data-v94-delete="routine|'+r.id+'">Delete</button>':''}</div>`)}
function v94OpenTherapyEditor(t={}){v94PendingMedia=[...(t.attachments||[])];v94PrepareEditor(t.id?'Edit Therapy / Cognitive Activity':'Add Therapy / Cognitive Activity',`<div class="form-grid">${v94Field('Icon','v94EtIcon',t.icon||'🧠')}${v94Field('Activity name','v94EtTitle',t.title||'')}<div class="field"><label>Category</label><select class="control" id="v94EtCategory">${V94_THERAPY_CATEGORIES.map(c=>`<option ${t.category===c?'selected':''}>${c}</option>`).join('')}</select></div>${v94Field('Time','v94EtTime',t.time||'10:00','time')}${v94Field('Duration (minutes)','v94EtDuration',t.duration||15,'number')}<div class="field"><label>Status</label><select class="control" id="v94EtActive"><option value="true" ${t.active!==false?'selected':''}>Active</option><option value="false" ${t.active===false?'selected':''}>Paused</option></select></div><div class="field full"><label>Days</label>${v94DayChecks(t.days||[1,3,5])}</div>${v94Text('Instructions / handling / stop criteria','v94EtInstructions',t.instructions||'')}</div>${v94MediaField()}<div class="actions-row"><button class="primary" data-v94-save-therapy="${t.id||''}">Save activity</button>${t.id?'<button class="ghost" data-v94-delete="therapy|'+t.id+'">Delete</button>':''}</div>`)}
function v94OpenMealEditor(m={},date=state.selectedDate){v94PrepareEditor(m.id?'Edit scheduled meal':'Add scheduled meal',`<div class="form-grid">${v94Field('Date','v94EmDate',m.date||date,'date')}${v94Field('Time','v94EmTime',m.time||'09:00','time')}${v94Field('Meal / feed name','v94EmName',m.name||'')}${v94Field('Slot','v94EmSlot',m.slot||'Feed')}${v94Field('Portion / volume','v94EmPortion',m.portion||'')}${v94Field('Route','v94EmRoute',m.route||'NG tube')}${v94Text('Instructions / flush / tolerance notes','v94EmNotes',m.notes||'')}</div><div class="actions-row"><button class="primary" data-v94-save-meal="${m.id||''}">Save scheduled meal</button>${m.id?'<button class="ghost" data-v94-delete="meal|'+m.id+'">Delete</button>':''}</div>`)}
function v94OpenMealLibraryEditor(m={}){v94PrepareEditor(m.id?'Edit saved meal':'Save reusable meal',`<div class="form-grid">${v94Field('Meal / feed name','v94EmlName',m.name||'')}${v94Field('Default portion','v94EmlPortion',m.portion||'')}${v94Field('Calories','v94EmlCalories',m.calories||'')}${v94Field('Texture','v94EmlTexture',m.texture||'')}${v94Field('Route','v94EmlRoute',m.route||'NG tube')}${v94Text('Ingredients','v94EmlIngredients',m.ingredients||'')}${v94Text('Preparation / caregiver instructions','v94EmlInstructions',m.instructions||'')}</div><div class="actions-row"><button class="primary" data-v94-save-meal-library="${m.id||''}">Save reusable meal</button>${m.id?'<button class="ghost" data-v94-delete="mealLibrary|'+m.id+'">Delete</button>':''}</div>`)}
function v94OpenMealAssign(id){const m=state.mealLibrary.find(x=>x.id===id);if(!m)return;v94PrepareEditor('Add saved meal to schedule',`<div class="card preview-card"><h4>${esc(m.name)}</h4><p>${esc(m.portion)} · ${esc(m.route)} · ${esc(m.texture)}</p></div><div class="form-grid">${v94Field('Date','v94EmaDate',state.selectedDate,'date')}${v94Field('Time','v94EmaTime','09:00','time')}${v94Field('Slot','v94EmaSlot','Feed')}${v94Text('Day-specific notes','v94EmaNotes','')}</div><button class="primary wide" data-v94-confirm-assign-meal="${id}">Add to schedule</button>`)}
function v94OpenCopyMeals(){const source=state.selectedDate,meals=state.mealAssignments.filter(m=>m.date===source).sort((a,b)=>a.time.localeCompare(b.time));v94PrepareEditor('Copy meal plan',`<div class="notice"><strong>Copy from:</strong> ${v94FormatDate(source,{weekday:'long',day:'numeric',month:'long'})}. Nothing will be copied until you review and confirm.</div><div class="v94-form-section">Meals / slots to copy</div><div class="v94-check-row">${meals.map(m=>`<button type="button" class="v94-check-chip active" data-v94-copy-meal="${m.id}">${esc(m.time)} · ${esc(m.slot)} · ${esc(m.name)}</button>`).join('')||'<span>No meals on this day.</span>'}</div><div class="v94-form-section">Copy to which day(s)?</div><div class="v94-check-row">${v94WeekDates().filter(d=>d!==source).map(d=>`<button type="button" class="v94-check-chip" data-v94-copy-target="${d}">${v94FormatDate(d,{weekday:'short',day:'numeric'})}</button>`).join('')}</div><div class="form-grid"><div class="field"><label>Target slot handling</label><select class="control" id="v94CopySlotMode"><option value="keep">Keep each original time and slot</option><option value="single">Put all copied meals into one chosen slot</option></select></div>${v94Field('Chosen target slot','v94CopyTargetSlot','Copied feed')}<div class="field"><label>If target already has meals</label><select class="control" id="v94CopyConflict"><option value="merge">Merge without deleting existing meals</option><option value="matching">Replace matching time/slot only</option><option value="day">Replace entire target day</option></select></div></div><button class="primary wide" data-v94-confirm-copy-meals ${meals.length?'':'disabled'}>Review complete · Copy selected meals</button>`)}
function v94OpenMedicineEditor(m={}){v94PrepareEditor(m.id?'Edit medicine':'Add medicine',`<div class="form-grid">${v94Field('Medicine name','v94MdName',m.name||'')}${v94Field('Generic / brand','v94MdGeneric',m.generic||'')}${v94Field('Strength','v94MdStrength',m.strength||'')}${v94Field('Prescribed dose','v94MdDose',m.dose||'')}${v94Field('Route','v94MdRoute',m.route||'NG tube')}${v94Field('Frequency','v94MdFrequency',m.frequency||'')}${v94Field('Scheduled times (comma separated)','v94MdTimes',(m.times||[]).join(', '))}${v94Field('Indication','v94MdIndication',m.indication||'')}<div class="field"><label>Status</label><select class="control" id="v94MdStatus"><option ${m.status==='Current'?'selected':''}>Current</option><option ${m.status==='Paused'?'selected':''}>Paused</option><option ${m.status==='Discontinued'?'selected':''}>Discontinued</option></select></div>${v94Field('Prescriber','v94MdPrescriber',m.prescriber||'')}${v94Field('Start date','v94MdStart',m.startDate||'','date')}${v94Field('End date','v94MdEnd',m.endDate||'','date')}${v94Field('Last reviewed','v94MdReview',m.reviewDate||'','date')}<div class="field"><label>Medicine type</label><select class="control" id="v94MdType"><option value="scheduled" ${!m.prn&&!m.rescue?'selected':''}>Scheduled</option><option value="prn" ${m.prn&&!m.rescue?'selected':''}>PRN / as needed</option><option value="rescue" ${m.rescue?'selected':''}>Emergency / rescue</option></select></div>${v94Field('Maximum PRN dose/frequency','v94MdMaxPrn',m.maxPrn||'')}${v94Text('Administration instructions','v94MdInstructions',m.instructions||m.notes||'')}${v94Text('Important warnings','v94MdWarnings',m.warnings||'')}${v94Field('Expiry date','v94MdExpiry',m.expiry||'','date')}</div><div class="notice"><strong>Handover sync:</strong> saving this medicine immediately updates Today, SOS and the printed handover according to its status.</div><div class="actions-row"><button class="primary" data-v94-save-medicine="${m.id||''}">Save & sync medicine</button>${m.id?'<button class="ghost" data-v94-delete="medicine|'+m.id+'">Delete</button>':''}</div>`)}
function v94OpenAdministration(m){v94PrepareEditor('Record medicine administration',`<div class="card preview-card"><h4>${esc(m.name)}</h4><p>${esc(m.dose)} · ${esc(m.route)} · ${esc(v94MedSchedule(m))}</p></div><div class="form-grid">${v94Field('Date','v94MaDate',state.selectedDate,'date')}${v94Field('Scheduled time','v94MaScheduled',m.prn?'PRN':m.times?.[0]||'08:00')}${v94Field('Actual time','v94MaActual',new Date().toTimeString().slice(0,5),'time')}<div class="field"><label>Status</label><select class="control" id="v94MaStatus"><option>Given</option><option>Skipped</option><option>Refused</option><option>Held</option><option>Vomited</option></select></div>${v94Field('Actual dose','v94MaDose',m.dose||'')}<div class="field"><label>Caregiver</label><select class="control" id="v94MaCaregiver">${state.caregivers.map(c=>`<option>${esc(c.displayName)}</option>`).join('')}</select></div>${v94Text('Reason / response / note','v94MaNote','')}</div><button class="primary wide" data-v94-save-administration="${m.id}">Save administration record</button>`)}
function v94OpenAppointmentEditor(a={}){v94PrepareEditor(a.id?'Edit appointment':'Add appointment',`<div class="form-grid">${v94Field('Appointment title','v94EaTitle',a.title||'')}${v94Field('Date','v94EaDate',a.date||state.selectedDate,'date')}${v94Field('Time','v94EaTime',a.time||'09:00','time')}<div class="field"><label>Hospital / centre</label><select class="control" id="v94EaHospital">${state.hospitals.map(h=>`<option value="${h.id}" ${a.hospitalId===h.id?'selected':''}>${esc(h.name)}</option>`).join('')}</select></div>${v94Field('Department','v94EaDepartment',a.department||'')}${v94Field('Consultant / team','v94EaConsultant',a.consultant||'')}${v94Field('Location','v94EaLocation',a.location||'')}${v94Field('Phone','v94EaPhone',a.phone||'')}<div class="field"><label>Status</label><select class="control" id="v94EaStatus"><option ${a.status==='Scheduled'?'selected':''}>Scheduled</option><option ${a.status==='Completed'?'selected':''}>Completed</option><option ${a.status==='Cancelled'?'selected':''}>Cancelled</option></select></div>${v94Text('Preparation / items to bring','v94EaPrep',a.prep||'')}${v94Text('Outcome / follow-up notes','v94EaNotes',a.notes||'')}</div><div class="actions-row"><button class="primary" data-v94-save-appointment="${a.id||''}">Save appointment</button>${a.id?'<button class="ghost" data-v94-delete="appointment|'+a.id+'">Delete</button>':''}</div>`)}
const V94_LOG_FIELDS={
 Seizure:['Duration','Seizure type','Body parts affected','Possible trigger','Breathing / colour','Post-event state','Rescue medicine','Action taken'],
 Dystonia:['Duration','Severity','Body pattern','Possible trigger','Intervention','Response','Pain / distress'],
 'Fluid In/Out':['Type','Amount (ml)','Route','Tolerance','Urine / stool output'],
 Medication:['Medicine','Dose','Route','Administration status','Response / adverse effect'],
 'Vital Signs':['Temperature','Heart rate','SpO2','Respiratory rate','Blood pressure'],
 Positioning:['Position','Duration','Support used','Skin / pressure check','Tolerance'],
 Behaviour:['Antecedent / trigger','Observed behaviour','Duration','Support used','Outcome'],
 Development:['Skill / domain','What was observed','Level of support','Next step'],
 'Skin / Pressure Area':['Location','Appearance','Size','Pain / tenderness','Action taken'],
 General:['Context','Observation','Action / next step']
};
function v94OpenLogEditor(l={},preset=''){const type=l.type||preset||'General';v94PendingMedia=[...(l.attachments||[])];v94PrepareEditor(l.id?'Edit structured log':'Add structured log',`<div class="form-grid"><div class="field"><label>Log type</label><select class="control" id="v94ElType">${V94_LOG_TYPES.map(t=>`<option ${type===t?'selected':''}>${t}</option>`).join('')}</select></div>${v94Field('Date','v94ElDate',l.date||state.selectedDate,'date')}${v94Field('Time','v94ElTime',l.time||new Date().toTimeString().slice(0,5),'time')}${v94Field('Title','v94ElTitle',l.title||'')}<div class="field"><label>Severity</label><select class="control" id="v94ElSeverity"><option ${l.severity==='Routine'?'selected':''}>Routine</option><option ${l.severity==='Mild'?'selected':''}>Mild</option><option ${l.severity==='Moderate'?'selected':''}>Moderate</option><option ${l.severity==='Severe'?'selected':''}>Severe</option><option ${l.severity==='Emergency'?'selected':''}>Emergency</option></select></div><div class="field"><label>Caregiver</label><select class="control" id="v94ElCaregiver">${state.caregivers.map(c=>`<option ${l.caregiver===c.displayName?'selected':''}>${esc(c.displayName)}</option>`).join('')}</select></div>${v94Text('Summary','v94ElSummary',l.summary||'')}</div><div class="v94-form-section">Structured fields</div><div class="form-grid" id="v94LogFields"></div>${v94MediaField()}<div class="actions-row"><button class="primary" data-v94-save-log="${l.id||''}">Save structured log</button>${l.id?'<button class="ghost" data-v94-delete="log|'+l.id+'">Delete</button>':''}</div>`);setTimeout(()=>v94RenderLogFields(type,l.fields||{}),0)}
function v94RenderLogFields(type,values={}){const box=document.getElementById('v94LogFields');if(!box)return;box.innerHTML=(V94_LOG_FIELDS[type]||V94_LOG_FIELDS.General).map((k,i)=>`<div class="field ${i>2?'full':''}"><label>${esc(k)}</label>${i>2?`<textarea class="control v94-log-extra" data-label="${esc(k)}">${esc(values[k]||'')}</textarea>`:`<input class="control v94-log-extra" data-label="${esc(k)}" value="${esc(values[k]||'')}">`}</div>`).join('')}
function v94OpenGroceryEditor(g={},library=false){v94PrepareEditor(g.id?`Edit ${library?'saved':'active'} grocery item`:`Add ${library?'saved':'active'} grocery item`,`<div class="form-grid">${v94Field('Item name','v94EgName',g.name||'')}${v94Field('Category','v94EgCategory',g.category||'Feeding')}${v94Field('Quantity','v94EgQty',g.qty||'')}${v94Field('Estimated cost (RM)','v94EgCost',g.cost||0,'number')}${v94Text('Notes','v94EgNotes',g.notes||'')}</div><div class="actions-row"><button class="primary" data-v94-save-grocery="${library?'library':'active'}|${g.id||''}">Save item</button>${g.id?'<button class="ghost" data-v94-delete="'+(library?'groceryLibrary':'grocery')+'|'+g.id+'">Delete</button>':''}</div>`)}
function v94OpenCaregiverEditor(c={}){v94PrepareEditor(c.id?'Edit caregiver':'Add caregiver',`<div class="form-grid"><div class="field"><label>Caregiver type</label><select class="control" id="v94EcType"><option ${c.type==='Primary'?'selected':''}>Primary</option><option ${c.type==='Secondary'?'selected':''}>Secondary</option><option ${c.type==='Additional'?'selected':''}>Additional</option></select></div>${v94Field('Relationship / role','v94EcRelationship',c.relationship||'')}${v94Field('Full legal name','v94EcFull',c.fullName||'')}${v94Field('Display name','v94EcDisplay',c.displayName||'')}${v94Field('Occupation','v94EcOccupation',c.occupation||'')}${v94Field('Phone','v94EcPhone',c.phone||'')}${v94Field('Email','v94EcEmail',c.email||'','email')}${v94Text('Address','v94EcAddress',c.address||'')}<div class="field"><label>Medical decision authority</label><select class="control" id="v94EcDecision"><option value="true" ${c.decision?'selected':''}>Authorised</option><option value="false" ${!c.decision?'selected':''}>Not authorised</option></select></div><div class="field"><label>Emergency contact</label><select class="control" id="v94EcEmergency"><option value="true" ${c.emergency!==false?'selected':''}>Yes</option><option value="false" ${c.emergency===false?'selected':''}>No</option></select></div></div><div class="actions-row"><button class="primary" data-v94-save-caregiver="${c.id||''}">Save caregiver</button>${c.id?'<button class="ghost" data-v94-delete="caregiver|'+c.id+'">Delete</button>':''}</div>`)}
function v94OpenHospitalEditor(h={}){v94PrepareEditor(h.id?'Edit hospital / centre':'Add hospital / centre',`<div class="form-grid">${v94Field('Hospital / centre name','v94EhName',h.name||'')}${v94Field('Card / MRN number','v94EhMrn',h.mrn||'')}${v94Field('Department','v94EhDepartment',h.department||'')}${v94Field('Consultant / team','v94EhConsultant',h.consultant||'')}${v94Field('Main phone','v94EhPhone',h.phone||'')}${v94Text('Address','v94EhAddress',h.address||'')}${v94Text('Notes','v94EhNotes',h.notes||'')}<div class="field"><label>Hospital priority</label><select class="control" id="v94EhPrimary"><option value="true" ${h.primary?'selected':''}>Primary hospital</option><option value="false" ${!h.primary?'selected':''}>Linked centre</option></select></div></div><div class="actions-row"><button class="primary" data-v94-save-hospital="${h.id||''}">Save hospital</button>${h.id?'<button class="ghost" data-v94-delete="hospital|'+h.id+'">Delete</button>':''}</div>`)}
function v94OpenRecord(source,id){if(source==='routine')return v94OpenRoutineEditor(state.routines.find(x=>x.id===id));if(source==='therapy')return v94OpenTherapyEditor(state.therapies.find(x=>x.id===id));if(source==='meal')return v94OpenMealEditor(state.mealAssignments.find(x=>x.id===id));if(source==='mealLibrary')return v94OpenMealLibraryEditor(state.mealLibrary.find(x=>x.id===id));if(source==='med'||source==='medicine')return v94OpenMedicineEditor(state.medications.find(x=>x.id===id));if(source==='appointment')return v94OpenAppointmentEditor(state.appointments.find(x=>x.id===id));if(source==='log')return v94OpenLogEditor(state.logs.find(x=>x.id===id));if(source==='grocery')return v94OpenGroceryEditor(state.groceries.find(x=>x.id===id));if(source==='groceryLibrary')return v94OpenGroceryEditor(state.groceryLibrary.find(x=>x.id===id),true);if(source==='caregiver')return v94OpenCaregiverEditor(state.caregivers.find(x=>x.id===id));if(source==='hospital')return v94OpenHospitalEditor(state.hospitals.find(x=>x.id===id))}
function v94OpenNew(kind,extra=''){if(kind==='routine')v94OpenRoutineEditor();if(kind==='therapy')v94OpenTherapyEditor();if(kind==='meal')v94OpenMealEditor({},extra||state.selectedDate);if(kind==='mealLibrary')v94OpenMealLibraryEditor();if(kind==='medicine')v94OpenMedicineEditor();if(kind==='appointment')v94OpenAppointmentEditor();if(kind==='grocery')v94OpenGroceryEditor();if(kind==='groceryLibrary')v94OpenGroceryEditor({},true);if(kind==='caregiver')v94OpenCaregiverEditor();if(kind==='hospital')v94OpenHospitalEditor()}
function v94CurrentEditorDays(){return [...document.querySelectorAll('[data-v94-editor-day].active')].map(x=>Number(x.dataset.v94EditorDay))}
async function v94SaveRoutine(rid){const data={id:rid||v94Uid(),icon:document.getElementById('v94ErIcon').value||'🌿',title:document.getElementById('v94ErTitle').value.trim()||'Care routine',category:document.getElementById('v94ErCategory').value.trim()||'Personal care',time:document.getElementById('v94ErTime').value||'09:00',duration:Number(document.getElementById('v94ErDuration').value)||15,days:v94CurrentEditorDays(),instructions:document.getElementById('v94ErInstructions').value.trim(),active:document.getElementById('v94ErActive').value==='true',attachments:await v94CommitMedia()};const i=state.routines.findIndex(x=>x.id===rid);if(i>=0)state.routines[i]=data;else state.routines.push(data);save();closeModal('editorModal');toast('Daily Care routine saved');v94Render()}
async function v94SaveTherapy(tid){const data={id:tid||v94Uid(),icon:document.getElementById('v94EtIcon').value||'🧠',title:document.getElementById('v94EtTitle').value.trim()||'Therapy activity',category:document.getElementById('v94EtCategory').value,time:document.getElementById('v94EtTime').value||'10:00',duration:Number(document.getElementById('v94EtDuration').value)||15,days:v94CurrentEditorDays(),instructions:document.getElementById('v94EtInstructions').value.trim(),active:document.getElementById('v94EtActive').value==='true',attachments:await v94CommitMedia()};const i=state.therapies.findIndex(x=>x.id===tid);if(i>=0)state.therapies[i]=data;else state.therapies.push(data);save();closeModal('editorModal');toast('Therapy activity saved');v94Render()}
