function v94SaveMealLibrary(mid){const data={id:mid||v94Uid(),name:document.getElementById('v94EmlName').value.trim()||'Saved meal',portion:document.getElementById('v94EmlPortion').value.trim(),calories:document.getElementById('v94EmlCalories').value.trim(),texture:document.getElementById('v94EmlTexture').value.trim(),route:document.getElementById('v94EmlRoute').value.trim(),ingredients:document.getElementById('v94EmlIngredients').value.trim(),instructions:document.getElementById('v94EmlInstructions').value.trim()};const i=state.mealLibrary.findIndex(x=>x.id===mid);if(i>=0)state.mealLibrary[i]=data;else state.mealLibrary.push(data);save();closeModal('editorModal');toast('Reusable meal saved');v94Render()}
