function v94CopyMeals(){const selected=[...document.querySelectorAll('[data-v94-copy-meal].active')].map(x=>x.dataset.v94CopyMeal),targets=[...document.querySelectorAll('[data-v94-copy-target].active')].map(x=>x.dataset.v94CopyTarget);if(!selected.length||!targets.length){toast('Choose at least one meal and one target day');return}const sourceMeals=state.mealAssignments.filter(m=>selected.includes(m.id)),slotMode=document.getElementById('v94CopySlotMode').value,targetSlot=document.getElementById('v94CopyTargetSlot').value.trim()||'Copied feed',conflict=document.getElementById('v94CopyConflict').value;targets.forEach(date=>{if(conflict==='day')state.mealAssignments=state.mealAssignments.filter(m=>m.date!==date);sourceMeals.forEach(src=>{if(conflict==='matching')state.mealAssignments=state.mealAssignments.filter(m=>!(m.date===date&&m.time===src.time&&m.slot===src.slot));state.mealAssignments.push({...src,id:v94Uid(),date,slot:slotMode==='single'?targetSlot:src.slot,status:'pending'})})});save();closeModal('editorModal');toast(`Copied ${selected.length} meal${selected.length>1?'s':''} to ${targets.length} day${targets.length>1?'s':''}`);v94Render()}
function v94SaveMedicine(mid){const type=document.getElementById('v94MdType').value,times=document.getElementById('v94MdTimes').value.split(',').map(x=>x.trim()).filter(Boolean);const data={id:mid||v94Uid(),name:document.getElementById('v94MdName').value.trim()||'Medicine',generic:document.getElementById('v94MdGeneric').value.trim(),strength:document.getElementById('v94MdStrength').value.trim(),dose:document.getElementById('v94MdDose').value.trim(),route:document.getElementById('v94MdRoute').value.trim(),frequency:document.getElementById('v94MdFrequency').value.trim(),times:type==='scheduled'?times:['PRN'],indication:document.getElementById('v94MdIndication').value.trim(),status:document.getElementById('v94MdStatus').value,prescriber:document.getElementById('v94MdPrescriber').value.trim(),startDate:document.getElementById('v94MdStart').value,endDate:document.getElementById('v94MdEnd').value,reviewDate:document.getElementById('v94MdReview').value,prn:type!=='scheduled',rescue:type==='rescue',maxPrn:document.getElementById('v94MdMaxPrn').value.trim(),instructions:document.getElementById('v94MdInstructions').value.trim(),warnings:document.getElementById('v94MdWarnings').value.trim(),expiry:document.getElementById('v94MdExpiry').value,attachments:[]};const i=state.medications.findIndex(x=>x.id===mid);if(i>=0)state.medications[i]={...state.medications[i],...data};else state.medications.push(data);save();closeModal('editorModal');toast('Medicine saved and handover synchronised');v94Render()}
