 const gcheck=e.target.closest('[data-v94-grocery-check]');if(gcheck){const g=state.groceries.find(x=>x.id===gcheck.dataset.v94GroceryCheck);if(g)g.checked=!g.checked;save();return v94Render()}
 const glib=e.target.closest('[data-v94-add-library-grocery]');if(glib){const g=state.groceryLibrary.find(x=>x.id===glib.dataset.v94AddLibraryGrocery);if(g)state.groceries.push({...g,id:v94Uid(),checked:false});save();toast('Saved item added to active list');return v94Render()}
 const quick=e.target.closest('[data-v94-quick]');if(quick)return v94OpenLogEditor({},quick.dataset.v94Quick==='seizure'?'Seizure':'Dystonia')
 if(e.target.closest('[data-v94-log]'))return v94OpenLogEditor()
