 const media=e.target.closest('[data-v94-media]');if(media)return v94ShowMedia(media.dataset.v94Media)
 if(e.target.closest('[data-v94-pick-media]'))return document.getElementById('v94MediaInput')?.click()
 const removeMedia=e.target.closest('[data-v94-remove-pending]');if(removeMedia){const id=removeMedia.dataset.v94RemovePending,rec=v94PendingMedia.find(x=>x.id===id);v94PendingMedia=v94PendingMedia.filter(x=>x.id!==id);if(rec&&!rec.new)await v94DeleteMedia(id);return v94RenderPendingMedia()}
 const day=e.target.closest('[data-v94-editor-day]');if(day){day.classList.toggle('active');return}
 const del=e.target.closest('[data-v94-delete]');if(del){const [k,id]=del.dataset.v94Delete.split('|');return v94DeleteRecord(k,id)}
 const sr=e.target.closest('[data-v94-save-routine]');if(sr)return v94SaveRoutine(sr.dataset.v94SaveRoutine)
 const st=e.target.closest('[data-v94-save-therapy]');if(st)return v94SaveTherapy(st.dataset.v94SaveTherapy)
 const sm=e.target.closest('[data-v94-save-meal]');if(sm)return v94SaveMeal(sm.dataset.v94SaveMeal)
 const sml=e.target.closest('[data-v94-save-meal-library]');if(sml)return v94SaveMealLibrary(sml.dataset.v94SaveMealLibrary)
 const smd=e.target.closest('[data-v94-save-medicine]');if(smd)return v94SaveMedicine(smd.dataset.v94SaveMedicine)
 const sad=e.target.closest('[data-v94-save-administration]');if(sad)return v94SaveAdministration(sad.dataset.v94SaveAdministration)
 const sap=e.target.closest('[data-v94-save-appointment]');if(sap)return v94SaveAppointment(sap.dataset.v94SaveAppointment)
 const sl=e.target.closest('[data-v94-save-log]');if(sl)return v94SaveLog(sl.dataset.v94SaveLog)
 const sg=e.target.closest('[data-v94-save-grocery]');if(sg){const [mode,id]=sg.dataset.v94SaveGrocery.split('|');return v94SaveGrocery(mode,id)}
 const sc=e.target.closest('[data-v94-save-caregiver]');if(sc)return v94SaveCaregiver(sc.dataset.v94SaveCaregiver)
 const sh=e.target.closest('[data-v94-save-hospital]');if(sh)return v94SaveHospital(sh.dataset.v94SaveHospital)
 if(e.target.closest('[data-v94-save-patient]'))return v94SavePatient()
 if(e.target.closest('[data-v94-export]'))return v94Export()
