/* ===== CarePlan v9.5 requested functional modifications ===== */
const V95_CARE_CATEGORIES=['Personal care','Positioning','Feeding support','Airway / Respiratory','Continence','Skin / Pressure care','Sleep & rest','Comfort / Sensory','Clinical care','Custom'];
const V95_MED_CATEGORIES=['Routine','PRN (as needed)','Emergency / rescue'];
const v95OriginalSave=save;
save=function(){state.calendarRevision=(state.calendarRevision||0)+1;state.lastUpdated=new Date().toISOString();return v95OriginalSave()};
function v95Migrate(){
 state.calendarRevision=state.calendarRevision||1;state.lastUpdated=state.lastUpdated||new Date().toISOString();
 state.safetyAtGlance=state.safetyAtGlance||{critical:state.patient.emergencyNotes||'',immediate:'Protect airway, use prescribed positioning and observe breathing, colour and responsiveness.',callCriteria:'Call emergency services for breathing compromise, prolonged event, repeated events without recovery, or according to the approved clinical plan.',rescue:'Use rescue medication only as prescribed and record the exact time and response.'};
 state.routineLibrary=state.routineLibrary||[
  {id:'rllib1',icon:'🛏️',title:'Supported positioning & pressure check',category:'Positioning',duration:15,instructions:'Use prescribed supports. Check skin, breathing and comfort before and after.',attachments:[]},
  {id:'rllib2',icon:'🪥',title:'Oral care',category:'Personal care',duration:10,instructions:'Use soft oral-care materials. Pause if gagging, distress or breathing changes.',attachments:[]},
  {id:'rllib3',icon:'🫁',title:'Airway and secretion observation',category:'Airway / Respiratory',duration:8,instructions:'Observe effort, colour, secretion burden and need for the approved airway plan.',attachments:[]},
  {id:'rllib4',icon:'🥣',title:'Feeding readiness and tube check',category:'Feeding support',duration:10,instructions:'Confirm position and prescribed feeding plan before starting. Document tolerance.',attachments:[]},
  {id:'rllib5',icon:'🧴',title:'Skin and pressure-area care',category:'Skin / Pressure care',duration:12,instructions:'Inspect vulnerable areas and record redness, swelling or skin breakdown.',attachments:[]},
  {id:'rllib6',icon:'🌙',title:'Evening comfort routine',category:'Sleep & rest',duration:20,instructions:'Reduce stimulation and use the person’s preferred settling supports.',attachments:[]},
  {id:'rllib7',icon:'🧷',title:'Continence and hygiene care',category:'Continence',duration:15,instructions:'Provide privacy, document output when required, and inspect skin condition.',attachments:[]},
  {id:'rllib8',icon:'🎵',title:'Calming sensory support',category:'Comfort / Sensory',duration:10,instructions:'Use known preferred sensory input and stop if distress increases.',attachments:[]}
 ];
 state.therapyLibrary=state.therapyLibrary||[
  {id:'tllib1',icon:'🧘',title:'Supported sitting and head control',category:'Physiotherapy',duration:20,instructions:'Use full trunk support. Stop with breathing, colour, pain or distress change.',attachments:[]},
  {id:'tllib2',icon:'👐',title:'Bilateral reach and grasp',category:'Occupational Therapy',duration:15,instructions:'Present lightweight objects at midline and alternate sides slowly.',attachments:[]},
  {id:'tllib3',icon:'🗣️',title:'Choice-making through gaze',category:'Speech & Language',duration:12,instructions:'Offer two meaningful choices and allow at least eight seconds for response.',attachments:[]},
  {id:'tllib4',icon:'🧠',title:'Cause-and-effect activity',category:'Cognitive',duration:15,instructions:'Use one clear action and one predictable response. Repeat only while engaged.',attachments:[]},
  {id:'tllib5',icon:'👁️',title:'Visual tracking in supported position',category:'Vision',duration:10,instructions:'Use a high-contrast target and move slowly within the comfortable visual field.',attachments:[]},
  {id:'tllib6',icon:'✨',title:'Tactile sensory exploration',category:'Sensory',duration:10,instructions:'Introduce one texture at a time and observe approach, avoidance and regulation.',attachments:[]},
  {id:'tllib7',icon:'⭐',title:'Custom therapy activity',category:'Custom',duration:15,instructions:'Record the therapist-approved steps, positioning, assistance and stop criteria.',attachments:[]}
 ];
 state.routineLibrary=state.routineLibrary.map(x=>({...x,attachments:x.attachments||[]}));state.therapyLibrary=state.therapyLibrary.map(x=>({...x,attachments:x.attachments||[]}));
 state.careLibraryFilter=state.careLibraryFilter||'All';state.therapyLibraryFilter=state.therapyLibraryFilter||'All';
 state.medications=(state.medications||[]).map(m=>{const category=m.category||(m.rescue?'Emergency / rescue':m.prn?'PRN (as needed)':'Routine');return {...m,category,prn:category!=='Routine',rescue:category==='Emergency / rescue',updatedAt:m.updatedAt||state.lastUpdated}});
 save();
}
function v95PrintIcon(attr,label,kind=''){return `<button class="v95-icon-only ${kind}" ${attr} aria-label="${esc(label)}" title="${esc(label)}">${svg('print',16)}</button>`}
function v95DownloadIcon(attr,label){return `<button class="v95-icon-only gold" ${attr} aria-label="${esc(label)}" title="${esc(label)}">${svg('download',16)}</button>`}
function v95WeekTools(){const dates=v94WeekDates();return `<div class="v95-week-tools"><button class="v95-icon-only" data-v94-week="-7" aria-label="Previous week">${svg('back',15)}</button><button class="secondary" data-v94-today>Today</button><strong>${v94FormatDate(dates[0],{day:'numeric',month:'short'})} – ${v94FormatDate(dates[6],{day:'numeric',month:'short',year:'numeric'})}<span>Seven-day care plan</span></strong><button class="v95-icon-only" data-v94-week="7" aria-label="Next week">${svg('arrow',15)}</button></div>`}
function v95SafetyCard(){const s=state.safetyAtGlance;return `<div class="v94-safety card"><div class="v95-safety-head"><h3>Safety at a glance</h3><button class="v94-icon-btn" data-v95-edit-safety aria-label="Edit safety at a glance">${svg('edit',14)}</button></div><div class="v95-safety-list"><div class="v95-safety-row"><strong>Critical notes</strong><span>${esc(s.critical)}</span></div><div class="v95-safety-row"><strong>Immediate action</strong><span>${esc(s.immediate)}</span></div><div class="v95-safety-row"><strong>Call emergency services</strong><span>${esc(s.callCriteria)}</span></div><div class="v95-safety-row"><strong>Rescue plan</strong><span>${esc(s.rescue)}</span></div></div><div class="v94-safety-actions"><button class="secondary" data-v94-quick="seizure">Log seizure</button><button class="secondary" data-v94-quick="dystonia">Log dystonia</button>${v95PrintIcon('data-v94-print-handover','Print complete handover')}<button class="secondary" data-v94-nav="medicines">Medicines</button></div></div>`}
function v95Timeline(items,date){if(!items.length)return `<div class="card empty"><div class="empty-icon">${svg('calendar',24)}</div><h3>No scheduled items</h3><p>This date has no Daily Care, therapy, meals, routine medicines or appointments.</p></div>`;return `<div class="v94-timeline">${items.map(it=>{const done=v94ItemDone(it,date),doneAttr=it.source==='med'?`data-v95-med-done="${it.id}|${date}|${it.time}"`:`data-v94-complete="${it.source}|${it.id}|${date}|${it.time}"`;return `<article class="v94-timeline-item card ${done?'done':''}"><time class="v94-time">${esc(it.time)}</time><span class="v94-dot ${it.type}">${svg(it.type==='feed'?'meal':it.type==='med'?'med':it.type==='appt'?'appt':it.type==='therapy'?'therapy':'care',17)}</span><div class="v94-main"><h4>${esc(it.title)}</h4><p>${esc(it.sub)}</p>${it.notes?`<p>${esc(it.notes)}</p>`:''}<div class="plan-meta"><span class="mini">${done?'Completed':'Pending'}</span><span class="mini">${it.source==='routine'?'Daily Care':it.source==='appointment'?'Appointment':it.source==='med'?'Routine medicine':it.source}</span></div>${v94MediaStrip(it.attachments)}</div><div class="v94-timeline-actions"><button class="v94-icon-btn" data-v94-open="${it.source}|${it.id}" aria-label="Open details">${svg('arrow',15)}</button><button class="v94-icon-btn ${done?'done':''}" ${doneAttr} aria-label="${done?'Mark pending':'Mark done'}">${svg('check',15)}</button></div></article>`}).join('')}</div>`}
function v95RenderToday(){const date=v94DateISO(new Date()),items=v94TodayItems(date),done=items.filter(x=>v94ItemDone(x,date)).length,pct=items.length?Math.round(done/items.length*100):0,currentMeds=state.medications.filter(m=>m.status==='Current').length;document.getElementById('todayScroll').innerHTML=`${v94PageHead(`Good ${new Date().getHours()<12?'morning':new Date().getHours()<18?'afternoon':'evening'}, ${esc(state.caregivers[0]?.displayName||'Caregiver')}.`,`A complete view of ${esc(state.patient.preferredName)}’s care for today.`,'')}<div class="v94-hero-grid"><div class="care-banner"><div class="banner-row"><div><div class="banner-code">Today · ${done} of ${items.length} complete</div><h2>${esc(state.patient.preferredName)}’s care rhythm</h2><p>${esc(state.patient.primaryDx)} · ${esc(state.patient.feeding)}</p></div><span class="banner-action">${pct}%</span></div><div class="progress-line"><span style="width:${pct}%"></span></div></div>${v95SafetyCard()}</div><div class="v94-stats">${v94Stat('care',state.routines.filter(r=>r.active).length,'Daily Care routines','Personal, clinical and comfort care')}${v94Stat('therapy',state.therapies.filter(t=>t.active).length,'Therapy activities','Physio, OT, speech and cognitive')}${v94Stat('med',currentMeds,'Current medicines','Synced live to SOS handover')}${v94Stat('logs',state.logs.length,'Care logs','Structured records with media')}</div>${v94Section('Today’s complete timeline','Daily Care, therapy, meals, routine medicines and appointments in time order.',`<button class="text-btn" data-v94-nav="calendar">Open calendar</button>`)}${v95Timeline(items,date)}<div class="notice" style="margin-top:14px"><strong>Media follows the task.</strong> Images and short videos attached to Daily Care, therapy or cognitive activities render here as thumbnails and never autoplay.</div>`;setTimeout(v94HydrateMedia,0)}
function v95PlanCard(kind,rec,date){const done=!!v94Completion(kind,rec.id,date,rec.time);return `<article class="v95-plan-card ${done?'done':''}"><div class="v95-plan-top"><span class="v95-plan-icon">${esc(rec.icon||'🌿')}</span><div><h4>${esc(rec.title)}</h4><p>${esc(rec.time)} · ${esc(rec.category)} · ${rec.duration||15} min</p></div></div>${rec.instructions?`<p>${esc(rec.instructions)}</p>`:''}${v94MediaStrip(rec.attachments)}<div class="v95-plan-actions"><button class="v94-icon-btn" data-v94-open="${kind}|${rec.id}" aria-label="Edit">${svg('edit',13)}</button><button class="v94-icon-btn ${done?'done':''}" data-v94-complete="${kind}|${rec.id}|${date}|${rec.time}" aria-label="${done?'Mark pending':'Mark done'}">${svg('check',13)}</button></div></article>`}
function v95WeekBoard(kind){const dates=v94WeekDates(),arr=kind==='routine'?state.routines:state.therapies;return `<div class="v95-board-scroll"><div class="v95-board">${dates.map(date=>{const dow=v94ParseDate(date).getDay(),list=arr.filter(x=>x.active&&x.days.includes(dow)).sort((a,b)=>a.time.localeCompare(b.time));return `<section class="v95-day ${date===state.selectedDate?'selected':''}"><header class="v95-day-head"><button data-v95-select-date="${date}" style="border:0;background:none;text-align:left"><strong>${v94FormatDate(date,{weekday:'short'})}</strong><span>${v94FormatDate(date,{day:'numeric',month:'short'})}</span></button><button class="v94-icon-btn" data-v95-schedule-new="${kind}|${date}" aria-label="Add to this day">${svg('plus',12)}</button></header><div class="v95-day-body">${list.map(x=>v95PlanCard(kind,x,date)).join('')||'<p style="font-size:8px;color:var(--muted);padding:6px">No scheduled items.</p>'}<button class="v94-add-day" data-v95-schedule-new="${kind}|${date}">+ Add</button></div></section>`}).join('')}</div></div>`}
function v95LibraryCard(kind,item){return `<article class="v94-module card v95-library-card"><div class="v94-module-head"><span class="v94-module-icon">${esc(item.icon||'🌿')}</span><div style="flex:1"><h4>${esc(item.title)}</h4><p>${esc(item.category)} · ${item.duration||15} min</p></div><button class="v94-icon-btn" data-v95-edit-library="${kind}|${item.id}" aria-label="Edit template">${svg('edit',14)}</button></div><p>${esc(item.instructions||'')}</p>${v94MediaStrip(item.attachments)}<div class="v94-module-foot"><span class="v94-pill">Reusable template</span><button class="small-btn fill" data-v95-assign-library="${kind}|${item.id}">Add to schedule</button></div></article>`}
function v95LibrarySection(kind){const isCare=kind==='routine',arr=isCare?state.routineLibrary:state.therapyLibrary,cats=isCare?V95_CARE_CATEGORIES:V94_THERAPY_CATEGORIES,filter=isCare?state.careLibraryFilter:state.therapyLibraryFilter,list=arr.filter(x=>filter==='All'||x.category===filter);return `<div class="v95-library-toolbar"><div><div class="section-title" style="margin:0"><div><h3>${isCare?'Daily Care':'Therapy'} library</h3><p>Reusable templates for every category. Add a template to one or several days, then personalise it.</p></div></div></div><button class="text-btn" data-v95-new-library="${kind}">+ New template</button></div><div class="chips"><button class="chip ${filter==='All'?'active':''}" data-v95-library-filter="${kind}|All">All</button>${cats.map(c=>`<button class="chip ${filter===c?'active':''}" data-v95-library-filter="${kind}|${esc(c)}">${esc(c)}</button>`).join('')}</div><div class="v95-library-grid">${list.map(x=>v95LibraryCard(kind,x)).join('')||'<div class="card empty">No templates in this category.</div>'}</div>`}
function v95RenderCare(){document.getElementById('careScroll').innerHTML=`${v94PageHead('Daily Care','A seven-day care board above and a reusable Daily Care library below.',`${v95PrintIcon('data-v95-print-schedule="routine"','Print Daily Care plan')}<button class="primary" data-v94-new="routine">${svg('plus',14)} Add routine</button>`)}${v95WeekTools()}${v95WeekBoard('routine')}${v95LibrarySection('routine')}`;setTimeout(v94HydrateMedia,0)}
function v95RenderTherapy(){document.getElementById('therapyScroll').innerHTML=`${v94PageHead('Therapies & Cognitive Care','A seven-day therapy board above and a reusable library for every therapy category below.',`${v95PrintIcon('data-v95-print-schedule="therapy"','Print therapy plan')}<button class="primary" data-v94-new="therapy">${svg('plus',14)} Add activity</button>`)}${v95WeekTools()}${v95WeekBoard('therapy')}${v95LibrarySection('therapy')}`;setTimeout(v94HydrateMedia,0)}
function v95RenderMeals(){const dates=v94WeekDates();document.getElementById('mealsScroll').innerHTML=`${v94PageHead('Weekly Meal & Feeding Plan','A seven-day feeding board above and reusable meal library below.',`${v95PrintIcon('data-v95-print-schedule="meal"','Print meal plan')}<button class="secondary" data-v94-copy-meals>${svg('copy',14)} Copy day</button><button class="primary" data-v94-new="meal">${svg('plus',14)} Add meal</button>`)}${v95WeekTools()}<div class="v94-week-meals"><div class="v94-meal-grid">${dates.map(d=>{const list=state.mealAssignments.filter(m=>m.date===d).sort((a,b)=>a.time.localeCompare(b.time));return `<section class="v94-meal-day"><header class="v94-meal-head"><button data-v95-select-date="${d}" style="border:0;background:none;text-align:left"><strong>${v94FormatDate(d,{weekday:'short'})}</strong><span>${v94FormatDate(d,{day:'numeric',month:'short'})}</span></button><button class="v94-icon-btn" style="width:27px;height:27px" data-v94-new-meal-date="${d}">${svg('plus',12)}</button></header><div class="v94-meal-body">${list.map(v94MealCard).join('')||'<p style="font-size:8px;color:var(--muted);padding:6px">No meals scheduled.</p>'}<button class="v94-add-day" data-v94-new-meal-date="${d}">+ Add meal</button></div></section>`}).join('')}</div></div>${v94Section('Saved meal library','Reusable feeds, prepared meals and recipes.',`<button class="text-btn" data-v94-new="mealLibrary">+ Save meal</button>`)}<div class="v94-grid3">${state.mealLibrary.map(m=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:var(--amberp);color:var(--amber)">${svg('meal',18)}</span><div style="flex:1"><h4>${esc(m.name)}</h4><p>${esc(m.portion)} · ${esc(m.calories)} · ${esc(m.texture)}</p></div><button class="v94-icon-btn" data-v94-open="mealLibrary|${m.id}">${svg('edit',14)}</button></div><p>${esc(m.ingredients||'')}</p><div class="v94-module-foot"><span class="v94-pill">${esc(m.route)}</span><button class="small-btn fill" data-v94-assign-meal="${m.id}">Add to schedule</button></div></article>`).join('')}</div>`}
function v95RenderCalendar(){const cur=v94ParseDate(state.monthCursor||state.selectedDate),y=cur.getFullYear(),m=cur.getMonth(),first=new Date(y,m,1),start=new Date(y,m,1-first.getDay()),cells=Array.from({length:42},(_,i)=>{const d=new Date(start);d.setDate(start.getDate()+i);return d}),today=v94DateISO(new Date());document.getElementById('calendarScroll').innerHTML=`${v94PageHead('Unified Calendar','Daily Care, therapy, meals, routine medicines and appointments in one calendar.',`${v95PrintIcon('data-v95-print-calendar','Print calendar')}${v95DownloadIcon('data-v95-download-ics','Download .ics calendar')}`)}<div class="v95-ics-note"><strong>Calendar update logic:</strong> the download uses stable event UIDs and sequence numbers so edits can update matching events in compatible calendar apps. Manual re-import behaviour still varies; a subscribable calendar URL will be the reliable production sync method.</div><div class="v94-calendar-layout"><div class="v94-calendar-card card"><div class="v94-month-head"><button class="v94-icon-btn" data-v94-month="-1">${svg('back',15)}</button><h3>${cur.toLocaleDateString('en-MY',{month:'long',year:'numeric'})}</h3><button class="v94-icon-btn" data-v94-month="1">${svg('arrow',15)}</button></div><div class="v94-cal-grid">${V94_DAY_SHORT.map(x=>`<div class="v94-dow">${x}</div>`).join('')}${cells.map(d=>{const iso=v94DateISO(d),ev=v94EventsForDate(iso);return `<button class="v94-cal-day ${d.getMonth()!==m?'other':''} ${iso===state.selectedDate?'selected':''} ${iso===today?'today':''}" data-v94-cal-date="${iso}"><span class="v94-cal-num">${d.getDate()}</span><span class="v94-cal-dots">${ev.types.slice(0,5).map(t=>`<i class="v94-cal-dot ${t==='feed'?'meal':t}"></i>`).join('')}</span></button>`}).join('')}</div></div><div class="v94-calendar-card card">${v94Section(v94FormatDate(state.selectedDate,{weekday:'long',day:'numeric',month:'long'}),'Selected-date detail')}${v95Timeline(v94TodayItems(state.selectedDate),state.selectedDate)}</div></div>`;setTimeout(v94HydrateMedia,0)}
function v95RenderLogs(){const filter=state.logFilter||'all',list=[...state.logs].filter(l=>filter==='all'||l.type===filter).sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time));document.getElementById('logsScroll').innerHTML=`${v94PageHead('Structured Care Logs','The same structured fields are used for digital records and printable blank templates.',`${v95PrintIcon('data-v95-print-saved-logs','Print saved logs')}${v95PrintIcon('data-v95-empty-log','Print empty log template','gold')}<button class="primary" data-v94-log>${svg('plus',14)} Add log</button>`)}<div class="chips"><button class="chip ${filter==='all'?'active':''}" data-v94-log-filter="all">All</button>${V94_LOG_TYPES.map(t=>`<button class="chip ${filter===t?'active':''}" data-v94-log-filter="${t}">${t}</button>`).join('')}</div><div class="v94-grid2">${list.map(v94LogCard).join('')||'<div class="card empty">No logs match this filter.</div>'}</div>`;setTimeout(v94HydrateMedia,0)}
function v95MedicineCategory(m){return m.category||(m.rescue?'Emergency / rescue':m.prn?'PRN (as needed)':'Routine')}
function v95RenderMedicines(){const current=state.medications.filter(m=>m.status==='Current'),history=state.medications.filter(m=>m.status!=='Current');document.getElementById('medicinesScroll').innerHTML=`${v94PageHead('Medicines','Routine, PRN and rescue medicines share one source of truth with Today, SOS and the handover.',`<button class="primary" data-v94-new="medicine">${svg('plus',14)} Add medicine</button>`)}<div class="notice"><strong>Live handover synchronisation:</strong> every edit updates the current medicine summary and printed handover immediately. Today’s check button records a dated administration for routine medicines.</div>${V95_MED_CATEGORIES.map(cat=>{const list=current.filter(m=>v95MedicineCategory(m)===cat);return `${v94Section(cat,cat==='Routine'?'Scheduled medicines shown on Today.':cat==='PRN (as needed)'?'Given only when indicated and recorded separately.':'Emergency and rescue medicines shown prominently in SOS.')}<div class="v94-grid2">${list.map(m=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon" style="background:${cat==='Emergency / rescue'?'var(--redp)':'var(--bluep)'};color:${cat==='Emergency / rescue'?'var(--red)':'var(--blue)'}">${svg('med',18)}</span><div style="flex:1"><h4>${esc(m.name)}</h4><p>${esc(m.strength)} · ${esc(m.dose)} · ${esc(m.route)}</p></div><button class="v94-icon-btn" data-v94-open="medicine|${m.id}">${svg('edit',14)}</button></div><p>${esc(m.indication||m.instructions||'')}</p><div class="plan-meta"><span class="mini">${esc(v94MedSchedule(m))}</span><span class="mini">${esc(cat)}</span><span class="mini">Handover synced</span></div><div class="v94-module-foot"><span class="v94-pill ${cat==='Emergency / rescue'?'critical':''}">${esc(cat)}</span><button class="small-btn fill" data-v94-admin-med="${m.id}">Record administration</button></div></article>`).join('')||'<div class="card empty">No medicines in this category.</div>'}</div>`}).join('')}${history.length?`${v94Section('Medication history','Paused and discontinued medicines stay available but do not appear as current medicines in the handover.')}<div class="v94-grid2">${history.map(m=>`<article class="v94-module card"><div class="v94-module-head"><span class="v94-module-icon">${svg('med',18)}</span><div style="flex:1"><h4>${esc(m.name)}</h4><p>${esc(m.dose)} · ${esc(m.route)}</p></div><button class="v94-icon-btn" data-v94-open="medicine|${m.id}">${svg('edit',14)}</button></div><div class="v94-module-foot"><span class="v94-pill paused">${esc(m.status)}</span><span style="font-size:8px;color:var(--muted)">Not in current handover</span></div></article>`).join('')}</div>`:''}${v94Section('Administration history','Every dose is date-specific and separate from the medicine definition.')}<div class="plan-list">${[...state.administrations].sort((a,b)=>(b.date+b.actualTime).localeCompare(a.date+a.actualTime)).slice(0,30).map(a=>{const m=state.medications.find(x=>x.id===a.medId);return `<article class="grocery-card card"><span class="grocery-check" style="background:var(--greenp);color:var(--green);border:0">${svg('check',14)}</span><div><h4>${esc(m?.name||'Medicine')}</h4><p>${v94FormatDate(a.date,{day:'numeric',month:'short'})} · ${esc(a.actualTime||a.scheduledTime)} · ${esc(a.status)} · ${esc(a.dose||m?.dose||'')}</p></div><span class="price">${esc(a.caregiver||'')}</span></article>`}).join('')||'<div class="card empty">No administrations recorded.</div>'}</div>`}
function v95OnScreenMedicines(){const current=state.medications.filter(m=>m.status==='Current');return V95_MED_CATEGORIES.map(cat=>{const list=current.filter(m=>v95MedicineCategory(m)===cat);return `<div class="v95-med-group"><div class="v95-med-group-title">${esc(cat)}</div>${list.map(m=>`<div class="v95-med-row"><span class="grocery-check" style="background:${cat==='Emergency / rescue'?'var(--redp)':'var(--bluep)'};color:${cat==='Emergency / rescue'?'var(--red)':'var(--blue)'};border:0">${svg('med',13)}</span><div><h4>${esc(m.name)} · ${esc(m.dose)}</h4><p>${esc(m.route)} · ${esc(v94MedSchedule(m))}<br>${esc(m.indication||m.instructions||'')}</p></div></div>`).join('')||'<p style="font-size:8.5px;color:var(--muted)">None recorded.</p>'}</div>`}).join('')}
function v95RenderSOS(){const p=state.patient,contacts=v94EmergencyContacts(),activeR=state.routines.filter(r=>r.active),activeT=state.therapies.filter(t=>t.active),appts=state.appointments.filter(a=>a.status==='Scheduled').sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time)).slice(0,5);document.getElementById('sosScroll').innerHTML=`${v94PageHead('SOS & Complete Handover','A complete live handover view generated from the latest patient, caregiver, hospital, medicine and care records.',v95PrintIcon('data-v94-print-handover','Print complete handover','danger'))}<div class="detail-hero red"><div class="type">Emergency identity · ${esc(p.blood)} · Allergies: ${esc(p.allergies)}</div><h3>${esc(p.legalName)} <span style="font-size:.62em">(${esc(p.preferredName)})</span></h3><p>${esc(p.primaryDx)}<br>${esc(state.safetyAtGlance.critical)}</p><div class="detail-tags"><span>DOB ${esc(p.dob)} · ${esc(ageFromDob(p.dob))}</span><span>${esc(p.feeding)}</span><span>${state.hospitals.length} hospitals</span><span>${state.medications.filter(m=>m.status==='Current').length} current medicines</span><span>Updated ${esc(new Date(state.lastUpdated).toLocaleString('en-MY'))}</span></div></div><div class="v95-sos-grid"><section class="v94-module card v95-sos-section full"><div class="v95-safety-head"><div>${v94Section('Safety at a glance','Editable emergency principles used in this view and printout.')}</div><button class="v94-icon-btn" data-v95-edit-safety aria-label="Edit safety">${svg('edit',14)}</button></div><div class="v95-kv"><div class="full"><label>Critical notes</label><strong>${esc(state.safetyAtGlance.critical)}</strong></div><div><label>Immediate action</label><strong>${esc(state.safetyAtGlance.immediate)}</strong></div><div><label>Call criteria</label><strong>${esc(state.safetyAtGlance.callCriteria)}</strong></div><div class="full"><label>Rescue plan</label><strong>${esc(state.safetyAtGlance.rescue)}</strong></div></div></section><section class="v94-module card v95-sos-section full">${v94Section('Complete patient profile','Identity, diagnoses, allergies, feeding, communication and positioning.')}<div class="v95-kv"><div><label>Legal / preferred name</label><strong>${esc(p.legalName)}<br>${esc(p.preferredName)}</strong></div><div><label>DOB / age / sex / blood</label><strong>${esc(p.dob)} · ${esc(ageFromDob(p.dob))}<br>${esc(p.sex)} · ${esc(p.blood)}</strong></div><div><label>Primary diagnosis</label><strong>${esc(p.primaryDx)}</strong></div><div><label>Secondary diagnoses</label><strong>${esc(p.secondaryDx)}</strong></div><div><label>Allergies</label><strong>${esc(p.allergies)}</strong></div><div><label>Feeding</label><strong>${esc(p.feeding)}</strong></div><div><label>Communication</label><strong>${esc(p.communication)}</strong></div><div><label>Mobility / positioning</label><strong>${esc(p.mobility)}</strong></div><div class="full"><label>Home address</label><strong>${esc(p.address)}</strong></div></div></section><section class="v94-module card v95-sos-section">${v94Section('Caregivers','Complete profiles and authority.')}<div class="v95-kv">${state.caregivers.map(c=>`<div class="full"><label>${esc(c.type)} · ${esc(c.relationship)}</label><strong>${esc(c.fullName)} (${esc(c.displayName)})<br>${esc(c.phone)} · ${esc(c.email)}<br>${esc(c.occupation)} · ${esc(c.address)}<br>${c.decision?'Medical decision authority':''}${c.emergency?' · Emergency contact':''}</strong></div>`).join('')}</div></section><section class="v94-module card v95-sos-section">${v94Section('Hospitals & card details','Every linked centre, MRN, department and consultant.')}<div class="v95-kv">${state.hospitals.map(h=>`<div class="full"><label>${h.primary?'Primary hospital':'Linked centre'}</label><strong>${esc(h.name)} · ${esc(h.mrn)}<br>${esc(h.department)} · ${esc(h.consultant)}<br>${esc(h.phone)}${h.address?'<br>'+esc(h.address):''}${h.notes?'<br>'+esc(h.notes):''}</strong></div>`).join('')}</div></section><section class="v94-module card v95-sos-section">${v94Section('Emergency contacts','Derived from caregiver profiles.')} ${contacts.map(c=>`<div class="contact-row"><span class="contact-icon">${svg('phone',15)}</span><div><strong>${esc(c.name)}</strong><small>${esc(c.role)}</small></div><a href="tel:${esc(c.phone)}">${esc(c.phone)}</a></div>`).join('')}</section><section class="v94-module card v95-sos-section">${v94Section('Current medicines','Live single source from the Medicines module.')} ${v95OnScreenMedicines()}</section><section class="v94-module card v95-sos-section">${v94Section('Active Daily Care','Current support routines.')}<div class="v95-kv">${activeR.map(r=>`<div class="full"><label>${esc(r.time)} · ${esc(r.category)}</label><strong>${esc(r.title)}<br>${esc(r.instructions||'')}</strong></div>`).join('')}</div></section><section class="v94-module card v95-sos-section">${v94Section('Therapy & cognitive care','Active handling and stop criteria.')}<div class="v95-kv">${activeT.map(t=>`<div class="full"><label>${esc(t.time)} · ${esc(t.category)}</label><strong>${esc(t.title)} · ${t.duration} min<br>${esc(t.instructions||'')}</strong></div>`).join('')}</div></section><section class="v94-module card v95-sos-section full">${v94Section('Upcoming appointments','Hospital-linked appointments and preparation.')}<div class="v95-kv">${appts.map(a=>`<div><label>${esc(a.date)} · ${esc(a.time)}</label><strong>${esc(a.title)}<br>${esc(v94HospitalName(a.hospitalId))} · ${esc(a.department)}<br>${esc(a.prep||'')}</strong></div>`).join('')||'<div class="full"><strong>No scheduled appointments.</strong></div>'}</div></section></div>`}
function v95OpenSafetyEditor(){const s=state.safetyAtGlance;v94PrepareEditor('Edit Safety at a Glance',`<div class="notice warning"><strong>Emergency information:</strong> Keep this concise, current and aligned with the approved clinical plan.</div><div class="form-grid">${v94Text('Critical notes','v95SafetyCritical',s.critical)}${v94Text('Immediate action','v95SafetyImmediate',s.immediate)}${v94Text('When to call emergency services','v95SafetyCall',s.callCriteria)}${v94Text('Rescue plan','v95SafetyRescue',s.rescue)}</div><button class="primary wide" data-v95-save-safety>Save safety information</button>`)}
function v95SaveSafety(){state.safetyAtGlance={critical:document.getElementById('v95SafetyCritical').value.trim(),immediate:document.getElementById('v95SafetyImmediate').value.trim(),callCriteria:document.getElementById('v95SafetyCall').value.trim(),rescue:document.getElementById('v95SafetyRescue').value.trim()};state.patient.emergencyNotes=state.safetyAtGlance.critical;save();closeModal('editorModal');toast('Safety at a glance updated');v94Render()}
function v95OpenLibraryEditor(kind,item={}){const isCare=kind==='routine',cats=isCare?V95_CARE_CATEGORIES:V94_THERAPY_CATEGORIES;v94PendingMedia=[...(item.attachments||[])];v94PrepareEditor(item.id?'Edit reusable template':'New reusable template',`<div class="form-grid">${v94Field('Icon','v95LibIcon',item.icon|| (isCare?'🌿':'🧠'))}${v94Field('Template name','v95LibTitle',item.title||'')}<div class="field"><label>Category</label><select class="control" id="v95LibCategory">${cats.map(c=>`<option ${item.category===c?'selected':''}>${esc(c)}</option>`).join('')}</select></div>${v94Field('Default duration (minutes)','v95LibDuration',item.duration||15,'number')}${v94Text('Instructions / support / stop criteria','v95LibInstructions',item.instructions||'')}</div>${v94MediaField()}<div class="actions-row"><button class="primary" data-v95-save-library="${kind}|${item.id||''}">Save template</button>${item.id?`<button class="ghost" data-v95-delete-library="${kind}|${item.id}">Delete</button>`:''}</div>`)}
async function v95SaveLibrary(kind,id){const arr=kind==='routine'?state.routineLibrary:state.therapyLibrary,data={id:id||v94Uid(),icon:document.getElementById('v95LibIcon').value||'🌿',title:document.getElementById('v95LibTitle').value.trim()||'Reusable template',category:document.getElementById('v95LibCategory').value,duration:Number(document.getElementById('v95LibDuration').value)||15,instructions:document.getElementById('v95LibInstructions').value.trim(),attachments:await v94CommitMedia()};const i=arr.findIndex(x=>x.id===id);if(i>=0)arr[i]=data;else arr.push(data);save();closeModal('editorModal');toast('Reusable template saved');v94Render()}
function v95AssignLibrary(kind,id,date=state.selectedDate){const arr=kind==='routine'?state.routineLibrary:state.therapyLibrary,item=arr.find(x=>x.id===id);if(!item)return;const dow=v94ParseDate(date).getDay(),base={...item,id:'',days:[dow],time:kind==='routine'?'09:00':'10:00',active:true,attachments:[...(item.attachments||[])]};if(kind==='routine')v94OpenRoutineEditor(base);else v94OpenTherapyEditor(base)}
function v95DeleteLibrary(kind,id){if(!confirm('Delete this reusable template? Scheduled copies will remain.'))return;const key=kind==='routine'?'routineLibrary':'therapyLibrary';state[key]=state[key].filter(x=>x.id!==id);save();closeModal('editorModal');toast('Template deleted');v94Render()}
function v95OpenMedicineEditor(m={}){const category=v95MedicineCategory(m);v94PrepareEditor(m.id?'Edit medicine':'Add medicine',`<div class="form-grid">${v94Field('Medicine name','v94MdName',m.name||'')}${v94Field('Generic / brand','v94MdGeneric',m.generic||'')}${v94Field('Strength','v94MdStrength',m.strength||'')}${v94Field('Prescribed dose','v94MdDose',m.dose||'')}${v94Field('Route','v94MdRoute',m.route||'NG tube')}<div class="field"><label>Category</label><select class="control" id="v95MdCategory">${V95_MED_CATEGORIES.map(c=>`<option ${category===c?'selected':''}>${c}</option>`).join('')}</select></div>${v94Field('Frequency','v94MdFrequency',m.frequency||'')}${v94Field('Routine scheduled times (comma separated)','v94MdTimes',(m.times||[]).filter(x=>x!=='PRN').join(', '))}${v94Field('Indication','v94MdIndication',m.indication||'')}<div class="field"><label>Status</label><select class="control" id="v94MdStatus"><option ${m.status==='Current'?'selected':''}>Current</option><option ${m.status==='Paused'?'selected':''}>Paused</option><option ${m.status==='Discontinued'?'selected':''}>Discontinued</option></select></div>${v94Field('Prescriber','v94MdPrescriber',m.prescriber||'')}${v94Field('Start date','v94MdStart',m.startDate||'','date')}${v94Field('End date','v94MdEnd',m.endDate||'','date')}${v94Field('Last reviewed','v94MdReview',m.reviewDate||'','date')}${v94Field('Maximum PRN dose/frequency','v94MdMaxPrn',m.maxPrn||'')}${v94Text('Administration instructions','v94MdInstructions',m.instructions||m.notes||'')}${v94Text('Important warnings','v94MdWarnings',m.warnings||'')}${v94Field('Expiry date','v94MdExpiry',m.expiry||'','date')}</div><div class="notice"><strong>Handover sync:</strong> saving immediately updates Today, SOS and every printed handover according to category and status.</div><div class="actions-row"><button class="primary" data-v94-save-medicine="${m.id||''}">Save & sync medicine</button>${m.id?`<button class="ghost" data-v94-delete="medicine|${m.id}">Delete</button>`:''}</div>`)}
function v95SaveMedicine(mid){const category=document.getElementById('v95MdCategory').value,times=document.getElementById('v94MdTimes').value.split(',').map(x=>x.trim()).filter(Boolean),old=state.medications.find(x=>x.id===mid)||{};const data={...old,id:mid||v94Uid(),name:document.getElementById('v94MdName').value.trim()||'Medicine',generic:document.getElementById('v94MdGeneric').value.trim(),strength:document.getElementById('v94MdStrength').value.trim(),dose:document.getElementById('v94MdDose').value.trim(),route:document.getElementById('v94MdRoute').value.trim(),category,frequency:document.getElementById('v94MdFrequency').value.trim(),times:category==='Routine'?(times.length?times:['08:00']):['PRN'],indication:document.getElementById('v94MdIndication').value.trim(),status:document.getElementById('v94MdStatus').value,prescriber:document.getElementById('v94MdPrescriber').value.trim(),startDate:document.getElementById('v94MdStart').value,endDate:document.getElementById('v94MdEnd').value,reviewDate:document.getElementById('v94MdReview').value,prn:category!=='Routine',rescue:category==='Emergency / rescue',maxPrn:document.getElementById('v94MdMaxPrn').value.trim(),instructions:document.getElementById('v94MdInstructions').value.trim(),warnings:document.getElementById('v94MdWarnings').value.trim(),expiry:document.getElementById('v94MdExpiry').value,updatedAt:new Date().toISOString(),attachments:old.attachments||[]};const i=state.medications.findIndex(x=>x.id===mid);if(i>=0)state.medications[i]=data;else state.medications.push(data);save();closeModal('editorModal');toast('Medicine saved and handover synchronised');v94Render()}
function v95ToggleMedicineDone(id,date,time){const idx=state.administrations.findIndex(a=>a.medId===id&&a.date===date&&a.scheduledTime===time&&a.status==='Given');if(idx>=0){state.administrations.splice(idx,1);toast('Medicine returned to pending')}else{const m=state.medications.find(x=>x.id===id);if(!m)return;state.administrations.push({id:v94Uid(),medId:id,date,scheduledTime:time,actualTime:new Date().toTimeString().slice(0,5),status:'Given',dose:m.dose,caregiver:state.caregivers?.[0]?.displayName||'',note:'Marked done from Today'});toast('Medicine marked given')}save();v94Render()}
function v95PrintStyles(orientation='portrait'){return `<style>@page{size:A4 ${orientation};margin:10mm}*{box-sizing:border-box;-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}body{font-family:Arial,sans-serif;color:#2a1416;font-size:9pt;background:#fffdf9}h1{font-family:Georgia,serif;color:#fff;background:linear-gradient(135deg,#4d0e1d,#7b1c30);font-size:23pt;margin:0 0 3mm;padding:5mm 6mm;border-radius:5mm}h2{font-family:Georgia,serif;color:#7b1c30;font-size:13pt;margin:5mm 0 2mm;padding:2.2mm 3mm;background:#f3ead4;border-left:4px solid #c4963c;border-radius:0 3mm 3mm 0}h3{color:#4d0e1d;font-size:10pt;margin:3mm 0 1mm}p,li{line-height:1.45;margin:1mm 0}table{width:100%;border-collapse:separate;border-spacing:0;margin:2mm 0 4mm;border:1px solid #decfc2;border-radius:3mm;overflow:hidden}th,td{border-right:1px solid #e5d9ce;border-bottom:1px solid #e5d9ce;padding:2.2mm;text-align:left;vertical-align:top;line-height:1.4}tr:last-child td{border-bottom:0}th:last-child,td:last-child{border-right:0}th{background:#7b1c30;color:#fff;font-size:8pt}tr{break-inside:avoid}.identity{border:2px solid #7b1c30;padding:4mm;background:#fff8f2;border-radius:4mm}.critical{border-left:5px solid #b4232f;padding:3mm;background:#f8e7e8;border-radius:0 3mm 3mm 0}.goldbox{border:1px solid #dfc88f;background:#fff9ec;padding:3mm;border-radius:3mm}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:2.5mm}.box{padding:3mm;background:#faf6ef;border:1px solid #eadfd5;border-radius:3mm}.box strong{color:#7b1c30}.footer{margin-top:7mm;border-top:1px solid #cdbdaf;padding-top:2mm;display:flex;justify-content:space-between;font-size:7.5pt;color:#765d55}.page-break{break-before:page}.write-table td{height:23mm}.write-table .short td{height:13mm}.calendar-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:1.5mm}.calendar-cell{min-height:30mm;border:1px solid #e3d4c7;border-radius:2mm;padding:2mm;background:#fff}.calendar-cell.other{opacity:.42}.calendar-date{font-weight:700;color:#7b1c30;margin-bottom:1mm}.calendar-event{font-size:7pt;padding:1mm 1.5mm;margin:1mm 0;background:#f3ead4;border-radius:1.5mm;line-height:1.25}.schedule-day{break-inside:avoid;margin-bottom:3mm}.schedule-card{padding:2.2mm;margin:1.5mm 0;border-left:4px solid #7b1c30;background:#faf6ef;border-radius:0 2mm 2mm 0}.print-media-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:2mm;margin-top:2mm}.print-media-item{margin:0;break-inside:avoid;page-break-inside:avoid}.print-media-item img{display:block;width:100%;height:29mm;object-fit:cover;border:1px solid #decfc2;border-radius:2mm}.print-media-item figcaption{font-size:6.5pt;color:#765d55;margin-top:.8mm;line-height:1.2}.calendar-event .print-media-grid{grid-template-columns:repeat(2,minmax(0,1fr));gap:.7mm}.calendar-event .print-media-item img{height:13mm;border-radius:1mm}.calendar-event .print-media-item figcaption{display:none}</style>`}
function v95SetPrint(content,orientation='portrait'){document.getElementById('printSheet').innerHTML=`${v95PrintStyles(orientation)}${content}`;setTimeout(()=>window.print(),80)}
function v95PrintHandover(){const p=state.patient,current=state.medications.filter(m=>m.status==='Current'),contacts=v94EmergencyContacts(),routines=state.routines.filter(r=>r.active),therapies=state.therapies.filter(t=>t.active),appts=state.appointments.filter(a=>a.status==='Scheduled').sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time));const medRows=V95_MED_CATEGORIES.map(cat=>{const list=current.filter(m=>v95MedicineCategory(m)===cat);return `<h3>${esc(cat)}</h3><table><thead><tr><th>Medicine / indication</th><th>Strength / dose</th><th>Route / schedule</th><th>Instructions / warnings</th></tr></thead><tbody>${list.map(m=>`<tr><td><strong>${esc(m.name)}</strong>${m.generic?'<br>'+esc(m.generic):''}<br>${esc(m.indication||'')}</td><td>${esc(m.strength||'')}<br>${esc(m.dose)}</td><td>${esc(m.route)}<br>${esc(v94MedSchedule(m))}</td><td>${esc(m.instructions||'')}${m.warnings?'<br><strong>Warning:</strong> '+esc(m.warnings):''}${m.maxPrn?'<br><strong>Maximum PRN:</strong> '+esc(m.maxPrn):''}</td></tr>`).join('')||'<tr><td colspan="4">None recorded.</td></tr>'}</tbody></table>`}).join('');v95SetPrint(`<h1>CarePlan · Complete Emergency Handover</h1><p><strong>Generated:</strong> ${esc(new Date().toLocaleString('en-MY'))} · <strong>Last record update:</strong> ${esc(new Date(state.lastUpdated).toLocaleString('en-MY'))} · Confidential</p><section class="identity"><div class="grid"><div class="box"><strong>Patient</strong><br>${esc(p.legalName)}<br>Preferred: ${esc(p.preferredName)}</div><div class="box"><strong>DOB / age / sex / blood</strong><br>${esc(p.dob)} · ${esc(ageFromDob(p.dob))}<br>${esc(p.sex)} · ${esc(p.blood)}</div><div class="box"><strong>Primary diagnosis</strong><br>${esc(p.primaryDx)}</div><div class="box"><strong>Secondary diagnoses</strong><br>${esc(p.secondaryDx)}</div><div class="box"><strong>Allergies</strong><br>${esc(p.allergies)}</div><div class="box"><strong>Feeding</strong><br>${esc(p.feeding)}</div><div class="box"><strong>Communication</strong><br>${esc(p.communication)}</div><div class="box"><strong>Mobility / positioning</strong><br>${esc(p.mobility)}</div><div class="box" style="grid-column:1/-1"><strong>Home address</strong><br>${esc(p.address)}</div></div><div class="critical" style="margin-top:3mm"><strong>Critical emergency notes</strong><br>${esc(state.safetyAtGlance.critical)}</div></section><h2>Safety at a glance</h2><div class="grid"><div class="box"><strong>Immediate action</strong><br>${esc(state.safetyAtGlance.immediate)}</div><div class="box"><strong>Call emergency services</strong><br>${esc(state.safetyAtGlance.callCriteria)}</div><div class="box" style="grid-column:1/-1"><strong>Rescue plan</strong><br>${esc(state.safetyAtGlance.rescue)}</div></div><h2>Complete caregiver profiles</h2><table><thead><tr><th>Identity / relationship</th><th>Contact</th><th>Address / occupation</th><th>Authority</th></tr></thead><tbody>${state.caregivers.map(c=>`<tr><td><strong>${esc(c.fullName)}</strong><br>Preferred: ${esc(c.displayName)}<br>${esc(c.type)} · ${esc(c.relationship)}</td><td>${esc(c.phone)}<br>${esc(c.email)}</td><td>${esc(c.address)}<br>${esc(c.occupation)}</td><td>${c.decision?'Medical decision authority':''}${c.emergency?'<br>Emergency contact':''}</td></tr>`).join('')}</tbody></table><h2>Hospitals & card details</h2><table><thead><tr><th>Hospital / centre</th><th>Card / MRN</th><th>Department / consultant</th><th>Contact / notes</th></tr></thead><tbody>${state.hospitals.map(h=>`<tr><td><strong>${esc(h.name)}</strong>${h.primary?'<br>PRIMARY HOSPITAL':''}<br>${esc(h.address||'')}</td><td>${esc(h.mrn)}</td><td>${esc(h.department)}<br>${esc(h.consultant)}</td><td>${esc(h.phone)}<br>${esc(h.notes)}</td></tr>`).join('')}</tbody></table><h2>Emergency contacts</h2><table><thead><tr><th>Name</th><th>Role</th><th>Phone</th></tr></thead><tbody>${contacts.map(c=>`<tr><td>${esc(c.name)}</td><td>${esc(c.role)}</td><td>${esc(c.phone)}</td></tr>`).join('')}</tbody></table><div class="page-break"></div><h1>CarePlan · Medicines & Care Instructions</h1><h2>Current medicines — live from Medicines</h2><div class="goldbox"><strong>Single source of truth:</strong> Routine, PRN and rescue medicines below are generated directly from the current Medicines records. Paused and discontinued medicines are excluded.</div>${medRows}<h2>Active Daily Care</h2><table><thead><tr><th>Time / days</th><th>Routine</th><th>Category</th><th>Instructions</th></tr></thead><tbody>${routines.map(r=>`<tr><td>${esc(r.time)}<br>${r.days.map(d=>V94_DAY_SHORT[d]).join(', ')}</td><td>${esc(r.title)}</td><td>${esc(r.category)}</td><td>${esc(r.instructions||'')}</td></tr>`).join('')}</tbody></table><h2>Therapy & cognitive care</h2><table><thead><tr><th>Time / days</th><th>Activity</th><th>Category</th><th>Instructions / stop criteria</th></tr></thead><tbody>${therapies.map(t=>`<tr><td>${esc(t.time)}<br>${t.days.map(d=>V94_DAY_SHORT[d]).join(', ')}</td><td>${esc(t.title)}<br>${t.duration} min</td><td>${esc(t.category)}</td><td>${esc(t.instructions)}</td></tr>`).join('')}</tbody></table><h2>Upcoming appointments</h2><table><thead><tr><th>Date / time</th><th>Appointment</th><th>Hospital / department</th><th>Preparation</th></tr></thead><tbody>${appts.map(a=>`<tr><td>${esc(a.date)} ${esc(a.time)}</td><td>${esc(a.title)}<br>${esc(a.consultant||'')}</td><td>${esc(v94HospitalName(a.hospitalId))}<br>${esc(a.department)}</td><td>${esc(a.prep||'')}</td></tr>`).join('')||'<tr><td colspan="4">No scheduled appointments.</td></tr>'}</tbody></table><h2>Emergency action principles</h2><ol><li>${esc(state.safetyAtGlance.immediate)}</li><li>${esc(state.safetyAtGlance.callCriteria)}</li><li>${esc(state.safetyAtGlance.rescue)}</li><li>Bring this handover and all current medicines.</li></ol><div class="footer"><span>CarePlan · Complete Emergency Handover</span><span>${esc(p.legalName)} · CONFIDENTIAL</span></div>`,'portrait')}
function v95PrintSavedLogs(){const rows=[...state.logs].sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time)).map(l=>`<tr><td>${esc(l.date)} ${esc(l.time)}</td><td>${esc(l.type)}<br>${esc(l.severity)}</td><td><strong>${esc(l.title)}</strong><br>${esc(l.summary)}<br>${Object.entries(l.fields||{}).map(([k,v])=>`<strong>${esc(k)}:</strong> ${esc(v)}`).join('<br>')}</td><td>${esc(l.caregiver)}${l.attachments?.length?'<br>'+l.attachments.length+' media attachment(s)':''}</td></tr>`).join('');v95SetPrint(`<h1>CarePlan · Structured Care Logs</h1><p>Patient: ${esc(state.patient.legalName)} · Generated ${esc(new Date().toLocaleString('en-MY'))}</p><table><thead><tr><th>Date / time</th><th>Type / severity</th><th>Structured entry</th><th>Caregiver / media</th></tr></thead><tbody>${rows||'<tr><td colspan="4">No saved logs.</td></tr>'}</tbody></table><div class="footer"><span>CarePlan · Saved Logs</span><span>${esc(state.patient.legalName)}</span></div>`,'landscape')}
function v95OpenEmptyLogPrint(){v94PrepareEditor('Print empty log template',`<div class="notice"><strong>Horizontal writing template:</strong> fields match the digital app. Each writing row is tall enough for approximately two to three handwritten sentences.</div><div class="form-grid"><div class="field"><label>Template type</label><select class="control" id="v95EmptyLogType"><option value="All">All log types</option>${V94_LOG_TYPES.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class="field"><label>Copies per type</label><select class="control" id="v95EmptyLogCopies"><option value="1">1</option><option value="2">2</option><option value="3">3</option></select></div></div><div style="display:flex;justify-content:flex-end"><button class="v95-icon-only" data-v95-confirm-empty-log aria-label="Print empty log template" title="Print empty log template">${svg('print',16)}</button></div>`)}
function v95PrintEmptyLog(){const type=document.getElementById('v95EmptyLogType').value,copies=Number(document.getElementById('v95EmptyLogCopies').value)||1,types=type==='All'?V94_LOG_TYPES:[type],blocks=[];for(const t of types)for(let c=0;c<copies;c++){const fields=V94_LOG_FIELDS[t]||V94_LOG_FIELDS.General;blocks.push(`<section class="${blocks.length?'page-break':''}"><h1>CarePlan · ${esc(t)} Log</h1><p><strong>Patient:</strong> ${esc(state.patient.legalName)} &nbsp; <strong>DOB:</strong> ${esc(state.patient.dob)} &nbsp; <strong>Hospital/MRN:</strong> ${esc(state.hospitals[0]?.name||'')} · ${esc(state.hospitals[0]?.mrn||'')}</p><table class="write-table"><tbody><tr class="short"><th style="width:18%">Date</th><td></td><th style="width:18%">Time</th><td></td></tr><tr class="short"><th>Caregiver</th><td></td><th>Severity</th><td></td></tr><tr><th>Summary</th><td colspan="3"></td></tr>${fields.map(f=>`<tr><th>${esc(f)}</th><td colspan="3"></td></tr>`).join('')}<tr><th>Actions / follow-up</th><td colspan="3"></td></tr><tr><th>Clinician notes</th><td colspan="3"></td></tr></tbody></table><div class="footer"><span>CarePlan · Blank ${esc(t)} Template</span><span>Signature: ____________________</span></div></section>`)}closeModal('editorModal');v95SetPrint(blocks.join(''),'landscape')}
function v95PrintSchedule(kind){const dates=v94WeekDates(),title=kind==='routine'?'Daily Care Weekly Plan':kind==='therapy'?'Therapy & Cognitive Weekly Plan':'Meal & Feeding Weekly Plan';const days=dates.map(date=>{let items;if(kind==='meal')items=state.mealAssignments.filter(x=>x.date===date).sort((a,b)=>a.time.localeCompare(b.time)).map(x=>({time:x.time,title:x.name,sub:`${x.slot} · ${x.portion} · ${x.route}`,notes:x.notes}));else{const dow=v94ParseDate(date).getDay(),arr=kind==='routine'?state.routines:state.therapies;items=arr.filter(x=>x.active&&x.days.includes(dow)).sort((a,b)=>a.time.localeCompare(b.time)).map(x=>({time:x.time,title:x.title,sub:`${x.category} · ${x.duration||15} min`,notes:x.instructions}))}return `<div class="schedule-day"><h2>${v94FormatDate(date,{weekday:'long',day:'numeric',month:'long'})}</h2>${items.map(x=>`<div class="schedule-card"><strong>${esc(x.time)} · ${esc(x.title)}</strong><br>${esc(x.sub)}${x.notes?'<br>'+esc(x.notes):''}</div>`).join('')||'<p>No scheduled items.</p>'}</div>`}).join('');v95SetPrint(`<h1>CarePlan · ${title}</h1><p>${v94FormatDate(dates[0],{day:'numeric',month:'long',year:'numeric'})} – ${v94FormatDate(dates[6],{day:'numeric',month:'long',year:'numeric'})} · ${esc(state.patient.legalName)}</p>${days}<div class="footer"><span>CarePlan · ${title}</span><span>${esc(state.patient.preferredName)}</span></div>`,'portrait')}
function v95PrintCalendar(){const cur=v94ParseDate(state.monthCursor||state.selectedDate),y=cur.getFullYear(),m=cur.getMonth(),first=new Date(y,m,1),start=new Date(y,m,1-first.getDay()),cells=Array.from({length:42},(_,i)=>{const d=new Date(start);d.setDate(start.getDate()+i);return d});v95SetPrint(`<h1>CarePlan · ${cur.toLocaleDateString('en-MY',{month:'long',year:'numeric'})} Calendar</h1><p>${esc(state.patient.legalName)} · Daily Care, therapy, meals, routine medicines and appointments</p><div class="calendar-grid">${V94_DAY_SHORT.map(x=>`<div style="text-align:center;font-weight:700;color:#7b1c30">${x}</div>`).join('')}${cells.map(d=>{const iso=v94DateISO(d),items=v94TodayItems(iso);return `<div class="calendar-cell ${d.getMonth()!==m?'other':''}"><div class="calendar-date">${d.getDate()}</div>${items.slice(0,6).map(x=>`<div class="calendar-event">${esc(x.time)} · ${esc(x.title)}</div>`).join('')}${items.length>6?`<div class="calendar-event">+${items.length-6} more</div>`:''}</div>`}).join('')}</div><div class="footer"><span>CarePlan · Unified Calendar</span><span>${esc(state.patient.preferredName)}</span></div>`,'landscape')}
function v95IcsEscape(s){return String(s??'').replace(/\\/g,'\\\\').replace(/\n/g,'\\n').replace(/,/g,'\\,').replace(/;/g,'\\;')}
function v95IcsLocal(date,time='00:00'){return date.replace(/-/g,'')+'T'+String(time||'00:00').replace(':','')+'00'}
function v95IcsUtc(d=new Date()){return d.toISOString().replace(/[-:]/g,'').replace(/\.\d{3}/,'')}
function v95EndTime(date,time,duration=30){const d=v94ParseDate(date),[h,m]=String(time||'00:00').split(':').map(Number);d.setHours(h||0,m||0,0,0);d.setMinutes(d.getMinutes()+Number(duration||30));return {date:v94DateISO(d),time:d.toTimeString().slice(0,5)}}
function v95CalendarExportEvents(start,end){const events=[];for(let date=start;date<=end;date=v94AddDays(date,1)){const dow=v94ParseDate(date).getDay();state.routines.filter(r=>r.active&&r.days.includes(dow)).forEach(r=>events.push({uid:`routine-${r.id}-${date}@careplanpro.local`,date,time:r.time,duration:r.duration||15,title:`Daily Care: ${r.title}`,description:`${r.category}\n${r.instructions||''}`,category:'Daily Care'}));state.therapies.filter(t=>t.active&&t.days.includes(dow)).forEach(t=>events.push({uid:`therapy-${t.id}-${date}@careplanpro.local`,date,time:t.time,duration:t.duration||15,title:`${t.category}: ${t.title}`,description:t.instructions||'',category:'Therapy'}));state.mealAssignments.filter(x=>x.date===date).forEach(x=>events.push({uid:`meal-${x.id}@careplanpro.local`,date,time:x.time,duration:30,title:`Meal: ${x.name}`,description:`${x.slot} · ${x.portion} · ${x.route}\n${x.notes||''}`,category:'Meal'}));state.medications.filter(m=>m.status==='Current'&&v95MedicineCategory(m)==='Routine').forEach(m=>m.times.filter(x=>x!=='PRN').sort().forEach((time,idx)=>events.push({uid:`medicine-${m.id}-${date}-${idx}@careplanpro.local`,date,time,duration:10,title:`Medicine: ${m.name}`,description:`${m.dose} · ${m.route}\n${m.instructions||''}`,category:'Medicine'})));state.appointments.filter(a=>a.date===date&&a.status!=='Cancelled').forEach(a=>events.push({uid:`appointment-${a.id}@careplanpro.local`,date,time:a.time,duration:60,title:a.title,description:`${v94HospitalName(a.hospitalId)} · ${a.department}\n${a.prep||''}`,category:'Appointment'}))}return events}
function v95DownloadIcs(){const cur=v94ParseDate(state.monthCursor||state.selectedDate),start=v94DateISO(new Date(cur.getFullYear(),cur.getMonth(),1)),end=v94DateISO(new Date(cur.getFullYear(),cur.getMonth()+1,0)),now=v95IcsUtc(),seq=state.calendarRevision||1,lines=['BEGIN:VCALENDAR','VERSION:2.0','PRODID:-//CarePlan//PWA Care Calendar//EN','CALSCALE:GREGORIAN','METHOD:PUBLISH','X-WR-CALNAME:CarePlan · '+v95IcsEscape(state.patient.preferredName)];for(const e of v95CalendarExportEvents(start,end)){const finish=v95EndTime(e.date,e.time,e.duration);lines.push('BEGIN:VEVENT','UID:'+e.uid,'SEQUENCE:'+seq,'DTSTAMP:'+now,'LAST-MODIFIED:'+now,'DTSTART:'+v95IcsLocal(e.date,e.time),'DTEND:'+v95IcsLocal(finish.date,finish.time),'SUMMARY:'+v95IcsEscape(e.title),'DESCRIPTION:'+v95IcsEscape(e.description),'CATEGORIES:'+v95IcsEscape(e.category),'STATUS:CONFIRMED','X-CAREPLAN-SOURCE-UID:'+e.uid,'END:VEVENT')}lines.push('END:VCALENDAR');const blob=new Blob([lines.join('\r\n')],{type:'text/calendar;charset=utf-8'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`careplan-${start.slice(0,7)}.ics`;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);toast('Calendar .ics downloaded with stable event IDs')}
function v95AllMediaRefs(){const refs=[];['routines','therapies','logs','medications','routineLibrary','therapyLibrary'].forEach(k=>(state[k]||[]).forEach(x=>(x.attachments||[]).forEach(a=>refs.push(typeof a==='string'?{id:a}:{...a}))));return [...new Map(refs.map(x=>[x.id,x])).values()]}
function v95BlobDataUrl(blob){return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(r.result);r.onerror=rej;r.readAsDataURL(blob)})}
async function v95ExportBackup(){const media=[];for(const ref of v95AllMediaRefs()){const rec=await v94GetMedia(ref.id);if(rec?.blob)media.push({id:ref.id,name:rec.name||ref.name,type:rec.type||ref.type,kind:rec.kind||ref.kind,createdAt:rec.createdAt||'',data:await v95BlobDataUrl(rec.blob)})}const payload={format:'careplan-pro-complete-backup',version:'9.5-preview',exportedAt:new Date().toISOString(),state,media},blob=new Blob([JSON.stringify(payload)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`careplan-pro-complete-backup-${v94DateISO(new Date())}.json`;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);toast(`Complete backup downloaded · ${media.length} media file${media.length===1?'':'s'}`)}
async function v95ImportBackup(file){const r=new FileReader();r.onload=async()=>{try{const parsed=JSON.parse(r.result),payload=parsed.format==='careplan-pro-complete-backup'?parsed:{state:parsed,media:[]};await v94ClearMedia();state=merge(defaultState(),payload.state||{});v94Migrate();v95Migrate();for(const m of payload.media||[]){const blob=await (await fetch(m.data)).blob();await v94PutMedia({id:m.id,name:m.name,type:m.type,kind:m.kind,createdAt:m.createdAt||new Date().toISOString(),blob})}toast(`Backup restored · ${(payload.media||[]).length} media file${(payload.media||[]).length===1?'':'s'}`);v94Render()}catch(e){console.error(e);toast('That file is not a valid CarePlan backup')}};r.readAsText(file)}
const v95BaseRenderProfile=v94RenderProfile;
function v95RenderProfile(){v95BaseRenderProfile();if((state.profileTab||'patient')==='data'){const exp=document.querySelector('[data-v94-export]'),imp=document.querySelector('[data-v94-import]');if(exp)exp.innerHTML=`${svg('download',14)} Download complete backup`;if(imp)imp.innerHTML=`${svg('upload',14)} Upload backup`;const card=document.querySelector('#profileScroll .profile-card');if(card){const note=card.querySelector('.notice.warning');if(note)note.innerHTML='<strong>This preview saves locally.</strong> Clearing browser/site data, private browsing ending, uninstalling the PWA, resetting/replacing the device or browser storage failure may remove records. Download a complete backup regularly; the v9.5 backup includes records and attached media.'}}}
