/* Override current preview renderers and connected actions. */
v94Timeline=v95Timeline;v94RenderToday=v95RenderToday;v94RenderCare=v95RenderCare;v94RenderTherapy=v95RenderTherapy;v94RenderMeals=v95RenderMeals;v94RenderCalendar=v95RenderCalendar;v94RenderLogs=v95RenderLogs;v94RenderMedicines=v95RenderMedicines;v94RenderSOS=v95RenderSOS;v94OpenMedicineEditor=v95OpenMedicineEditor;v94SaveMedicine=v95SaveMedicine;v94PrintHandover=v95PrintHandover;v94PrintLogs=v95PrintSavedLogs;v94Export=v95ExportBackup;v94Import=v95ImportBackup;v94RenderProfile=v95RenderProfile;v94SavePatient=v95SavePatient;
document.addEventListener('click',async e=>{
 const med=e.target.closest('[data-v95-med-done]');if(med){const [id,date,time]=med.dataset.v95MedDone.split('|');return v95ToggleMedicineDone(id,date,time)}
 if(e.target.closest('[data-v95-edit-safety]'))return v95OpenSafetyEditor();if(e.target.closest('[data-v95-save-safety]'))return v95SaveSafety();
 const select=e.target.closest('[data-v95-select-date]');if(select){state.selectedDate=select.dataset.v95SelectDate;state.monthCursor=state.selectedDate;save();return v94Render()}
 const add=e.target.closest('[data-v95-schedule-new]');if(add){const [kind,date]=add.dataset.v95ScheduleNew.split('|');return v95OpenBlankOrEditor(kind,date)}
 const nlib=e.target.closest('[data-v95-new-library]');if(nlib)return v95OpenLibraryEditor(nlib.dataset.v95NewLibrary,{});
 const elib=e.target.closest('[data-v95-edit-library]');if(elib)return v95OpenLibraryFromData(elib.dataset.v95EditLibrary);
 const alib=e.target.closest('[data-v95-assign-library]');if(alib){const [kind,id]=alib.dataset.v95AssignLibrary.split('|');return v95AssignLibrary(kind,id)}
 const slib=e.target.closest('[data-v95-save-library]');if(slib){const [kind,id]=slib.dataset.v95SaveLibrary.split('|');return v95SaveLibrary(kind,id)}
 const dlib=e.target.closest('[data-v95-delete-library]');if(dlib){const [kind,id]=dlib.dataset.v95DeleteLibrary.split('|');return v95DeleteLibrary(kind,id)}
 const filt=e.target.closest('[data-v95-library-filter]');if(filt){const [kind,value]=filt.dataset.v95LibraryFilter.split('|');if(kind==='routine')state.careLibraryFilter=value;else state.therapyLibraryFilter=value;save();return v94Render()}
 const ps=e.target.closest('[data-v95-print-schedule]');if(ps)return v95PrintSchedule(ps.dataset.v95PrintSchedule);
 if(e.target.closest('[data-v95-print-calendar]'))return v95PrintCalendar();if(e.target.closest('[data-v95-download-ics]'))return v95DownloadIcs();
 if(e.target.closest('[data-v95-print-saved-logs]'))return v95PrintSavedLogs();if(e.target.closest('[data-v95-empty-log]'))return v95OpenEmptyLogPrint();if(e.target.closest('[data-v95-confirm-empty-log]'))return v95PrintEmptyLog();
},true);
