const V96_CARE_FILTERS=['All','Daily Care',...V94_THERAPY_CATEGORIES];
let v96CareAddContext={date:null,library:false};
function v96AddButton(attr,label){return `<button class="v96-add-button" ${attr} aria-label="${esc(label)}" title="${esc(label)}">${svg('plus',16)}</button>`}
function v96PageHead(title,desc,actions=''){return `<div class="v94-page-head"><div><div class="eyebrow">CarePlan · PWA Preview</div><h1>${title}</h1><p>${desc}</p></div><div class="v94-page-actions">${actions}</div></div>`}
function v96SafetyCard(){const s=state.safetyAtGlance;return `<div class="v94-safety card"><div class="v95-safety-head"><h3>Safety at a glance</h3><button class="v94-icon-btn" data-v95-edit-safety aria-label="Edit safety at a glance">${svg('edit',14)}</button></div><div class="v95-safety-list"><div class="v95-safety-row"><strong>Critical notes</strong><span>${esc(s.critical)}</span></div><div class="v95-safety-row"><strong>Immediate action</strong><span>${esc(s.immediate)}</span></div><div class="v95-safety-row"><strong>Call emergency services</strong><span>${esc(s.callCriteria)}</span></div><div class="v95-safety-row"><strong>Rescue plan</strong><span>${esc(s.rescue)}</span></div></div><div class="v94-safety-actions"><button class="secondary" data-v94-quick="seizure">Log seizure</button><button class="secondary" data-v94-quick="dystonia">Log dystonia</button><button class="secondary" data-v94-nav="medicines">Medicines</button></div></div>`}
function v96RenderToday(){
 const date=v94DateISO(new Date()),items=v94TodayItems(date),done=items.filter(x=>v94ItemDone(x,date)).length,pct=items.length?Math.round(done/items.length*100):0,currentMeds=state.medications.filter(m=>m.status==='Current').length;
 document.getElementById('todayScroll').innerHTML=`${v94PageHead(`Good ${new Date().getHours()<12?'morning':new Date().getHours()<18?'afternoon':'evening'}, ${esc(state.caregivers[0]?.displayName||'Caregiver')}.`,`A complete view of ${esc(state.patient.preferredName)}’s care for today.`,'')}<div class="v96-today-overview"><div class="v96-progress-summary"><div class="v96-progress-top"><div><strong>${done} of ${items.length} care items complete</strong><span>${esc(state.patient.primaryDx)} · ${esc(state.patient.feeding)}<br>${v94FormatDate(date,{weekday:'long',day:'numeric',month:'long',year:'numeric'})}</span></div><div class="v96-progress-value">${pct}%</div></div><div class="progress-line"><span style="width:${pct}%"></span></div></div>${v96SafetyCard()}</div><div class="v94-stats">${v94Stat('care',state.routines.filter(r=>r.active).length,'Daily Care routines','Personal, clinical and comfort care')}${v94Stat('therapy',state.therapies.filter(t=>t.active).length,'Therapy activities','Physio, OT, speech and cognitive')}${v94Stat('med',currentMeds,'Current medicines','Synced live to SOS handover')}${v94Stat('logs',state.logs.length,'Care logs','Structured records with media')}</div>${v94Section('Today’s complete timeline','Care, meals, routine medicines and appointments in time order.',`<button class="text-btn" data-v94-nav="calendar">Open calendar</button>`)}${v95Timeline(items,date)}<div class="notice" style="margin-top:14px"><strong>Media follows the task.</strong> Images and short videos attached to Care activities render here as thumbnails and never autoplay.</div>`;
 setTimeout(v94HydrateMedia,0)
}
function v96CareEntriesForDate(date){
 const dow=v94ParseDate(date).getDay(),filter=state.careUnifiedFilter||'All',items=[];
 if(filter==='All'||filter==='Daily Care')state.routines.filter(r=>r.active&&r.days.includes(dow)).forEach(r=>items.push({kind:'routine',record:r,category:'Daily Care',subCategory:r.category}));
 state.therapies.filter(t=>t.active&&t.days.includes(dow)&&(filter==='All'||t.category===filter)).forEach(t=>items.push({kind:'therapy',record:t,category:t.category,subCategory:''}));
 return items.sort((a,b)=>a.record.time.localeCompare(b.record.time));
}
function v96CareCard(entry,date){const r=entry.record,done=!!v94Completion(entry.kind,r.id,date,r.time);return `<article class="v95-plan-card ${done?'done':''}"><div class="v95-plan-top"><span class="v95-plan-icon">${esc(r.icon||'🌿')}</span><div><h4>${esc(r.title)}</h4><p>${esc(r.time)} · ${entry.kind==='routine'?`Daily Care · ${esc(r.category)}`:`${esc(r.category)}`} · ${r.duration||15} min</p><span class="v96-kind ${entry.kind==='therapy'?'therapy':''}">${entry.kind==='routine'?'Daily Care':esc(r.category)}</span></div></div>${r.instructions?`<p>${esc(r.instructions)}</p>`:''}${v94MediaStrip(r.attachments)}<div class="v95-plan-actions"><button class="v94-icon-btn" data-v94-open="${entry.kind}|${r.id}" aria-label="Edit">${svg('edit',13)}</button><button class="v94-icon-btn ${done?'done':''}" data-v94-complete="${entry.kind}|${r.id}|${date}|${r.time}" aria-label="${done?'Mark pending':'Mark done'}">${svg('check',13)}</button></div></article>`}
function v96CareWeekBoard(){const dates=v94WeekDates();return `<div class="v95-board-scroll v96-care-board"><div class="v95-board">${dates.map(date=>{const list=v96CareEntriesForDate(date);return `<section class="v95-day ${date===state.selectedDate?'selected':''}"><header class="v95-day-head"><button data-v95-select-date="${date}" style="border:0;background:none;text-align:left"><strong>${v94FormatDate(date,{weekday:'short'})}</strong><span>${v94FormatDate(date,{day:'numeric',month:'short'})}</span></button>${v96AddButton(`data-v96-new-care="${date}"`,'Add Care activity to this day')}</header><div class="v95-day-body">${list.map(x=>v96CareCard(x,date)).join('')||'<p style="font-size:8px;color:var(--muted);padding:6px">No scheduled Care items in this category.</p>'}<button class="v96-day-add" data-v96-new-care="${date}" aria-label="Add Care activity">${svg('plus',14)}</button></div></section>`}).join('')}</div></div>`}
function v96CombinedLibrary(){
 const filter=state.careUnifiedFilter||'All',items=[];
 if(filter==='All'||filter==='Daily Care')state.routineLibrary.forEach(x=>items.push({kind:'routine',record:x,category:'Daily Care',subCategory:x.category}));
 state.therapyLibrary.filter(x=>filter==='All'||x.category===filter).forEach(x=>items.push({kind:'therapy',record:x,category:x.category,subCategory:''}));
 return items;
}
function v96CareLibraryCard(entry){const x=entry.record;return `<article class="v94-module card v96-library-card"><div class="v94-module-head"><span class="v94-module-icon">${esc(x.icon||'🌿')}</span><div style="flex:1"><h4>${esc(x.title)}</h4><p>${entry.kind==='routine'?`Daily Care · ${esc(x.category)}`:esc(x.category)} · ${x.duration||15} min</p></div><button class="v94-icon-btn" data-v95-edit-library="${entry.kind}|${x.id}" aria-label="Edit template">${svg('edit',14)}</button></div><p>${esc(x.instructions||'')}</p>${v94MediaStrip(x.attachments)}<div class="v94-module-foot"><span class="v94-pill">Reusable template</span><button class="small-btn fill" data-v95-assign-library="${entry.kind}|${x.id}">Add to schedule</button></div></article>`}
function v96RenderCare(){
 const filter=state.careUnifiedFilter||'All',lib=v96CombinedLibrary();
 document.getElementById('careScroll').innerHTML=`${v94PageHead('Care','Daily Care, physiotherapy, occupational therapy, speech, cognitive and other support in one workspace.',`${v95PrintIcon('data-v96-print-care','Print Care plan')}${v96AddButton('data-v96-new-care=""','Add Care activity')}`)}${v95WeekTools()}<div class="chips v96-care-filter">${V96_CARE_FILTERS.map(c=>`<button class="chip ${filter===c?'active':''}" data-v96-care-filter="${esc(c)}">${esc(c)}</button>`).join('')}</div>${v96CareWeekBoard()}<div class="v96-library-heading"><div><h3>Care library</h3><p>Reusable Daily Care and therapy templates, organised by the same categories.</p></div>${v96AddButton('data-v96-new-care-library','Add reusable Care template')}</div><div class="v95-library-grid">${lib.map(v96CareLibraryCard).join('')||'<div class="card empty">No reusable templates in this category.</div>'}</div>`;
 setTimeout(v94HydrateMedia,0)
}
function v96OpenCareChooser(date=state.selectedDate,library=false){v96CareAddContext={date:date||state.selectedDate,library};const current=state.careUnifiedFilter&&state.careUnifiedFilter!=='All'?state.careUnifiedFilter:'Daily Care';v94PrepareEditor(library?'Add Care library template':'Add Care activity',`<div class="notice"><strong>One Care workspace:</strong> choose Daily Care or a therapy category. The correct editor and media fields will open next.</div><div class="field"><label>Care category</label><select class="control" id="v96CareCategory">${V96_CARE_FILTERS.filter(x=>x!=='All').map(c=>`<option ${c===current?'selected':''}>${esc(c)}</option>`).join('')}</select></div><button class="primary wide" data-v96-care-continue>Continue</button>`)}
function v96ContinueCareAdd(){const cat=document.getElementById('v96CareCategory')?.value||'Daily Care',date=v96CareAddContext.date||state.selectedDate,dow=v94ParseDate(date).getDay();if(v96CareAddContext.library){if(cat==='Daily Care')v95OpenLibraryEditor('routine',{});else v95OpenLibraryEditor('therapy',{category:cat});return}if(cat==='Daily Care')v94OpenRoutineEditor({days:[dow],time:'09:00',active:true,attachments:[]});else v94OpenTherapyEditor({category:cat,days:[dow],time:'10:00',active:true,attachments:[]})}
async function v96PrintCareSchedule(){
 const dates=v94WeekDates(),filter=state.careUnifiedFilter||'All',dayParts=[];
 for(const date of dates){const items=v96CareEntriesForDate(date),cards=[];for(const {kind,record:r,category} of items){cards.push(`<div class="schedule-card"><strong>${esc(r.time)} · ${esc(r.title)}</strong><br>${kind==='routine'?`Daily Care · ${esc(r.category)}`:esc(category)} · ${r.duration||15} min${r.instructions?'<br>'+esc(r.instructions):''}${await v98PrintMediaHtml(r.attachments||[])}</div>`)}dayParts.push(`<div class="schedule-day"><h2>${v94FormatDate(date,{weekday:'long',day:'numeric',month:'long'})}</h2>${cards.join('')||'<p>No scheduled Care items.</p>'}</div>`)}
 v95SetPrint(`<h1>Care Weekly Plan</h1><p>${esc(filter)} · ${v94FormatDate(dates[0],{day:'numeric',month:'long',year:'numeric'})} – ${v94FormatDate(dates[6],{day:'numeric',month:'long',year:'numeric'})} · ${esc(state.patient.legalName)}</p>${dayParts.join('')}<div class="footer"><span>CarePlan · Specialcare — Care Weekly Plan</span><span>${esc(state.patient.preferredName)}</span></div>`,'portrait')
}
function v96RenderNav(){
 const p=state.patient,patientHTML=`<span class="ava">${esc((p.preferredName||p.legalName).slice(0,1))}</span><div><strong>${esc(p.preferredName)}</strong><span>${esc(p.primaryDx)}</span></div>`;
 document.getElementById('v94Patient').innerHTML=patientHTML;const drawerPatient=document.getElementById('v94DrawerPatient');if(drawerPatient)drawerPatient.innerHTML=patientHTML;
 const care=[['today','Today'],['calendar','Calendar'],['care','Care'],['meals','Meals']],records=[['appointments','Appointments'],['medicines','Medicines'],['grocery','Grocery'],['logs','Logs']],safety=[['sos','SOS'],['profile','Profile']];
 const group=(title,arr)=>`<div class="v94-nav-sec">${title}</div>${arr.map(v94SideButton).join('')}`;const grouped=group('Care workspace',care)+group('Plans & records',records)+group('Safety & profile',safety);
 document.getElementById('v94SideNav').innerHTML=grouped;const secondaryActive=!['today','care','meals','calendar'].includes(state.screen);
 document.getElementById('bottomNav').innerHTML=[['today','Home'],['care','Care'],['meals','Meals'],['calendar','Calendar']].map(([k,l])=>`<button class="nav ${state.screen===k?'active':''}" data-v94-mobile="${k}">${svg(k,20)}<span>${l}</span></button>`).join('')+`<button class="nav nav-menu ${secondaryActive?'active':''}" data-v94-mobile="menu" aria-label="Open all CarePlan navigation" aria-controls="v94More" aria-expanded="false">${svg('more',22)}<span>Menu</span></button>`;
 document.getElementById('v94MoreGrid').innerHTML=grouped;document.querySelectorAll('[data-v94-close]').forEach(b=>b.innerHTML=svg('close',16));
}
function v96RecentLogs(){return [...state.logs].sort((a,b)=>(b.date+b.time).localeCompare(a.date+a.time)).slice(0,6)}
function v96UpcomingMeals(){const start=v94DateISO(new Date()),end=v94AddDays(start,6);return state.mealAssignments.filter(m=>m.date>=start&&m.date<=end).sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time)).slice(0,18)}
const v96BaseRenderSOS=v95RenderSOS;
function v96RenderSOS(){v96BaseRenderSOS();const hero=document.querySelector('#sosScroll .detail-hero.red');if(hero)hero.classList.add('v96-sos-hero');const grid=document.querySelector('#sosScroll .v95-sos-grid');if(!grid)return;const meals=v96UpcomingMeals(),logs=v96RecentLogs();grid.insertAdjacentHTML('beforeend',`<section class="v94-module card v95-sos-section full">${v94Section('Feeding & meal plan','Upcoming scheduled feeds and meal instructions.')}<div class="v95-kv">${meals.map(m=>`<div><label>${esc(m.date)} · ${esc(m.time)} · ${esc(m.slot)}</label><strong>${esc(m.name)} · ${esc(m.portion)} · ${esc(m.route)}<br>${esc(m.notes||'')}</strong></div>`).join('')||'<div class="full"><strong>No upcoming meals recorded.</strong></div>'}</div></section><section class="v94-module card v95-sos-section full">${v94Section('Recent clinically relevant logs','Latest structured observations available during handover.')}<div class="v95-kv">${logs.map(l=>`<div><label>${esc(l.date)} · ${esc(l.time)} · ${esc(l.type)}</label><strong>${esc(l.title)}<br>${esc(l.summary||'')}<br>${esc(l.caregiver||'')}</strong></div>`).join('')||'<div class="full"><strong>No recent logs recorded.</strong></div>'}</div></section><section class="v94-module card v95-sos-section full">${v94Section('Emergency action checklist','Use the clinician-approved plan and record exact times.')}<div class="v95-kv"><div><label>1 · Immediate action</label><strong>${esc(state.safetyAtGlance.immediate)}</strong></div><div><label>2 · Call criteria</label><strong>${esc(state.safetyAtGlance.callCriteria)}</strong></div><div class="full"><label>3 · Rescue plan</label><strong>${esc(state.safetyAtGlance.rescue)}</strong></div></div></section>`)}
function v96PrintHandover(){
 const p=state.patient,current=state.medications.filter(m=>m.status==='Current'),history=state.medications.filter(m=>m.status!=='Current'),contacts=v94EmergencyContacts(),routines=state.routines.filter(r=>r.active),therapies=state.therapies.filter(t=>t.active),appts=state.appointments.filter(a=>a.status==='Scheduled').sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time)),meals=v96UpcomingMeals(),logs=v96RecentLogs();
 const medTables=V95_MED_CATEGORIES.map(cat=>{const list=current.filter(m=>v95MedicineCategory(m)===cat);return `<h3>${esc(cat)}</h3><table><thead><tr><th>Medicine / indication</th><th>Strength / dose</th><th>Route / schedule</th><th>Instructions / warnings</th></tr></thead><tbody>${list.map(m=>`<tr><td><strong>${esc(m.name)}</strong>${m.generic?'<br>'+esc(m.generic):''}<br>${esc(m.indication||'')}</td><td>${esc(m.strength||'')}<br>${esc(m.dose)}</td><td>${esc(m.route)}<br>${esc(v94MedSchedule(m))}</td><td>${esc(m.instructions||'')}${m.warnings?'<br><strong>Warning:</strong> '+esc(m.warnings):''}${m.maxPrn?'<br><strong>Maximum PRN:</strong> '+esc(m.maxPrn):''}</td></tr>`).join('')||'<tr><td colspan="4">None recorded.</td></tr>'}</tbody></table>`}).join('');
 const generated=esc(new Date().toLocaleString('en-MY')),updated=esc(new Date(state.lastUpdated).toLocaleString('en-MY'));
 const page1=`<section class="v96-print-page"><h1>CarePlan · Complete Emergency Handover</h1><p><strong>Generated:</strong> ${generated} · <strong>Last updated:</strong> ${updated} · Confidential</p><section class="identity"><div class="grid"><div class="box"><strong>Patient</strong><br>${esc(p.legalName)}<br>Preferred: ${esc(p.preferredName)}</div><div class="box"><strong>DOB / age / sex / blood</strong><br>${esc(p.dob)} · ${esc(ageFromDob(p.dob))}<br>${esc(p.sex)} · ${esc(p.blood)}</div><div class="box"><strong>Primary diagnosis</strong><br>${esc(p.primaryDx)}</div><div class="box"><strong>Secondary diagnoses</strong><br>${esc(p.secondaryDx)}</div><div class="box"><strong>Allergies</strong><br>${esc(p.allergies)}</div><div class="box"><strong>Feeding</strong><br>${esc(p.feeding)}</div><div class="box"><strong>Communication</strong><br>${esc(p.communication)}</div><div class="box"><strong>Mobility / positioning</strong><br>${esc(p.mobility)}</div><div class="box" style="grid-column:1/-1"><strong>Home address</strong><br>${esc(p.address)}</div></div><div class="critical" style="margin-top:3mm"><strong>Critical emergency notes</strong><br>${esc(state.safetyAtGlance.critical)}</div></section><h2>Complete caregiver profiles</h2><table><thead><tr><th>Identity / relationship</th><th>Contact</th><th>Address / occupation</th><th>Authority</th></tr></thead><tbody>${state.caregivers.map(c=>`<tr><td><strong>${esc(c.fullName)}</strong><br>Preferred: ${esc(c.displayName)}<br>${esc(c.type)} · ${esc(c.relationship)}</td><td>${esc(c.phone)}<br>${esc(c.email)}</td><td>${esc(c.address)}<br>${esc(c.occupation)}</td><td>${c.decision?'Medical decision authority':''}${c.emergency?'<br>Emergency contact':''}</td></tr>`).join('')}</tbody></table><h2>Hospitals & card details</h2><table><thead><tr><th>Hospital / centre</th><th>Card / MRN</th><th>Department / consultant</th><th>Contact / notes</th></tr></thead><tbody>${state.hospitals.map(h=>`<tr><td><strong>${esc(h.name)}</strong>${h.primary?'<br>PRIMARY HOSPITAL':''}<br>${esc(h.address||'')}</td><td>${esc(h.mrn)}</td><td>${esc(h.department)}<br>${esc(h.consultant)}</td><td>${esc(h.phone)}<br>${esc(h.notes||'')}</td></tr>`).join('')}</tbody></table><h2>Emergency contacts</h2><table><thead><tr><th>Name</th><th>Role</th><th>Phone</th></tr></thead><tbody>${contacts.map(c=>`<tr><td>${esc(c.name)}</td><td>${esc(c.role)}</td><td>${esc(c.phone)}</td></tr>`).join('')}</tbody></table><div class="footer"><span>Page 1 · Identity, caregivers and hospitals</span><span>${esc(p.legalName)} · CONFIDENTIAL</span></div></section>`;
 const page2=`<section class="v96-print-page"><h1>Medicines, Safety & Daily Care</h1><div class="goldbox"><strong>Medicines are live from the Medicines module.</strong> Current Routine, PRN and emergency/rescue medicines are included. Paused and discontinued medicines are excluded from the current list.</div><h2>Safety at a glance</h2><div class="grid"><div class="box"><strong>Immediate action</strong><br>${esc(state.safetyAtGlance.immediate)}</div><div class="box"><strong>Call emergency services</strong><br>${esc(state.safetyAtGlance.callCriteria)}</div><div class="box" style="grid-column:1/-1"><strong>Rescue plan</strong><br>${esc(state.safetyAtGlance.rescue)}</div></div><h2>Current medicines</h2>${medTables}${history.length?`<h2>Paused / discontinued medicine history</h2><table><thead><tr><th>Medicine</th><th>Status</th><th>Dose / route</th><th>Notes</th></tr></thead><tbody>${history.map(m=>`<tr><td>${esc(m.name)}</td><td>${esc(m.status)}</td><td>${esc(m.dose)} · ${esc(m.route)}</td><td>${esc(m.instructions||m.notes||'')}</td></tr>`).join('')}</tbody></table>`:''}<h2>Active Daily Care</h2><table><thead><tr><th>Time / days</th><th>Routine</th><th>Category</th><th>Instructions</th></tr></thead><tbody>${routines.map(r=>`<tr><td>${esc(r.time)}<br>${r.days.map(d=>V94_DAY_SHORT[d]).join(', ')}</td><td>${esc(r.title)}</td><td>${esc(r.category)}</td><td>${esc(r.instructions||'')}</td></tr>`).join('')||'<tr><td colspan="4">No active Daily Care routines.</td></tr>'}</tbody></table><div class="footer"><span>Page 2 · Medicines, safety and Daily Care</span><span>${esc(p.legalName)} · CONFIDENTIAL</span></div></section>`;
 const page3=`<section class="v96-print-page"><h1>Therapy, Feeding & Follow-up</h1><h2>Therapy & cognitive care</h2><table><thead><tr><th>Time / days</th><th>Activity</th><th>Category</th><th>Instructions / stop criteria</th></tr></thead><tbody>${therapies.map(t=>`<tr><td>${esc(t.time)}<br>${t.days.map(d=>V94_DAY_SHORT[d]).join(', ')}</td><td>${esc(t.title)}<br>${t.duration} min</td><td>${esc(t.category)}</td><td>${esc(t.instructions||'')}</td></tr>`).join('')||'<tr><td colspan="4">No active therapy activities.</td></tr>'}</tbody></table><h2>Upcoming meal & feeding plan</h2><table><thead><tr><th>Date / time</th><th>Meal / feed</th><th>Portion / route</th><th>Instructions</th></tr></thead><tbody>${meals.map(m=>`<tr><td>${esc(m.date)} ${esc(m.time)}<br>${esc(m.slot)}</td><td>${esc(m.name)}</td><td>${esc(m.portion)}<br>${esc(m.route)}</td><td>${esc(m.notes||'')}</td></tr>`).join('')||'<tr><td colspan="4">No upcoming meals recorded.</td></tr>'}</tbody></table><h2>Upcoming appointments</h2><table><thead><tr><th>Date / time</th><th>Appointment</th><th>Hospital / department</th><th>Preparation</th></tr></thead><tbody>${appts.map(a=>`<tr><td>${esc(a.date)} ${esc(a.time)}</td><td>${esc(a.title)}<br>${esc(a.consultant||'')}</td><td>${esc(v94HospitalName(a.hospitalId))}<br>${esc(a.department)}</td><td>${esc(a.prep||'')}</td></tr>`).join('')||'<tr><td colspan="4">No scheduled appointments.</td></tr>'}</tbody></table><h2>Recent clinically relevant logs</h2><table><thead><tr><th>Date / time</th><th>Type / severity</th><th>Summary</th><th>Caregiver</th></tr></thead><tbody>${logs.map(l=>`<tr><td>${esc(l.date)} ${esc(l.time)}</td><td>${esc(l.type)}<br>${esc(l.severity)}</td><td><strong>${esc(l.title)}</strong><br>${esc(l.summary||'')}</td><td>${esc(l.caregiver||'')}</td></tr>`).join('')||'<tr><td colspan="4">No recent logs.</td></tr>'}</tbody></table><h2>Emergency action checklist</h2><ol><li>${esc(state.safetyAtGlance.immediate)}</li><li>${esc(state.safetyAtGlance.callCriteria)}</li><li>${esc(state.safetyAtGlance.rescue)}</li><li>Bring this handover and all current medicines.</li></ol><div class="goldbox"><strong>Receiving team notes</strong><br><br>________________________________________________________________________________<br><br>________________________________________________________________________________</div><div class="footer"><span>Page 3 · Therapy, feeding, appointments and logs</span><span>${esc(p.legalName)} · CONFIDENTIAL</span></div></section>`;
 const extra=`<style>@media print{#printSheet{padding:0!important}.v96-print-page{position:relative;min-height:276mm;padding:0 0 13mm;break-after:page;page-break-after:always}.v96-print-page:last-child{break-after:auto;page-break-after:auto}.v96-print-page>.footer{position:absolute;left:0;right:0;bottom:0}.v96-print-page table{break-inside:auto}.v96-print-page thead{display:table-header-group}.v96-print-page tr{break-inside:avoid;page-break-inside:avoid}}</style>`;
 document.getElementById('printSheet').innerHTML=`${v95PrintStyles('portrait')}${extra}${page1}${page2}${page3}`;setTimeout(()=>window.print(),100)
}
function v96NormalizeAddButtons(){document.querySelectorAll('button[data-v94-new],button[data-v94-log],button[data-v95-new-library]').forEach(b=>{if(b.classList.contains('v96-add-button'))return;const label=(b.getAttribute('aria-label')||b.textContent||'Add').trim();b.setAttribute('aria-label',label);b.setAttribute('title',label);b.classList.add('v96-normalized-add');b.innerHTML=svg('plus',16)})}
